-- Poems batch 382
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('19cc765f-e382-4778-a54e-646c8ae5604d','送范子儀将漕湖北五首  其一','呂本中','宋','宋诗','song-poetry','','[]','君行欲何之，乃在湖水北。',72,'全唐诗/poet.song.92000.json','["君行欲何之，乃在湖水北。", "湖水多近縣，使者易爲德。", "其民淳而古，其吏朴且直。", "官閑足賓客，歲稔少盜賊。", "得君清靜化，用教不以力。", "但自養根苖，勿苦厭蟊螣。"]'),
('b762f489-6ba9-4735-bfc3-65ab72348c3f','送范子儀将漕湖北五首  其二','呂本中','宋','宋诗','song-poetry','','[]','許昌無事時，地固多英豪。',72,'全唐诗/poet.song.92000.json','["許昌無事時，地固多英豪。", "况君忠宣子，譽望素已高。", "讀書不出户，俛首自作勞。", "脱身走江南，始爲時所褒。", "每念其先人，水靜絕波濤。", "時從文字嬉，餘事及風騷。"]'),
('596dbf3d-3200-4e3d-815a-8e4e8e152ba5','送范子儀将漕湖北五首  其三','呂本中','宋','宋诗','song-poetry','','[]','忠宣在朝廷，每欲消黨與。',72,'全唐诗/poet.song.92000.json','["忠宣在朝廷，每欲消黨與。", "以我廣大心，盡使變齊魯。", "同門有不察，平地鬬豺虎。", "君昔住許昌，閉口不復吐。", "靜思前人意，皆是神所許。", "自守泥塗間，肯復計齟齬。"]'),
('58aa9f90-0461-4711-bc7c-03626361a9f8','送范子儀将漕湖北五首  其四','呂本中','宋','宋诗','song-poetry','','[]','令兄守家學，曰自文正始。',72,'全唐诗/poet.song.92000.json','["令兄守家學，曰自文正始。", "惟不卑小官，至死而後已。", "其間有富貴，乃是偶然爾。", "人欲學古人，豈不識此理。", "奈何厭貧賤，乃不退就已。", "君今又蹈之，可爲吾黨喜。"]'),
('892eb3b2-a58f-4a6e-8b5d-9f19f7d61b6b','送范子儀将漕湖北五首  其五','呂本中','宋','宋诗','song-poetry','','[]','我懶百事廢，尚叨交舊知。',72,'全唐诗/poet.song.92000.json','["我懶百事廢，尚叨交舊知。", "時蒙寄書來，索我送行詩。", "我詩老益退，久爲人所嗤。", "君獨不見鄙，論相不舉肥。", "送君湖北去，無事隔山陂。", "時應有佳句，尚足慰相思。"]'),
('4e5646ca-edfb-4c83-9d6c-bdf4b8e03680','梅花二首  其一','呂本中','宋','宋诗','song-poetry','','[]','白玉花頭碧玉枝，水邊籬下雪晴時。',32,'全唐诗/poet.song.92000.json','["白玉花頭碧玉枝，水邊籬下雪晴時。", "暗香别有關情處，却是春風未得知。"]'),
('b19c1c91-d8b7-4bc8-ab69-b0836b0eee4f','梅花二首  其二','呂本中','宋','宋诗','song-poetry','','[]','占得先開不待春，風饕雪虐長精神。',32,'全唐诗/poet.song.92000.json','["占得先開不待春，風饕雪虐長精神。", "老人不是尋花看，要與尊罍洗世塵。"]'),
('e1d8b38f-9fa6-432c-a608-c0681de7299c','周承務郔求諸己齋','呂本中','宋','宋诗','song-poetry','','[]','爲腹不爲目，貴久不貴速。',72,'全唐诗/poet.song.92000.json','["爲腹不爲目，貴久不貴速。", "人皆求其餘，我獨心易足。", "人皆重外慕，我獨御其獨。", "閉門想顔子，黙坐相追逐。", "壽夭有定分，簞瓢乃其福。", "脩身雖多途，要在不遠復。"]'),
('14e7bf51-070d-49b9-aba1-d23ea6ab8706','送程伯禹歸浮梁  其一','呂本中','宋','宋诗','song-poetry','','[]','不見程公二十年，上饒相遇各華顛。',64,'全唐诗/poet.song.92000.json','["不見程公二十年，上饒相遇各華顛。", "平生氣節名先立，老去安閑我未然。", "即看歸來上廊廟，未容休歇住林泉。", "飽山閣上憑欄處，合得逍遥第一篇。"]'),
('5c607e24-dffb-4ded-9db2-7aaf901decc9','送程伯禹歸浮梁  其二','呂本中','宋','宋诗','song-poetry','','[]','疾病因循懶出門，茅簷終日坐昏昏。',64,'全唐诗/poet.song.92000.json','["疾病因循懶出門，茅簷終日坐昏昏。", "雨聲點滴松藏寺，人迹稀疏犬吠村。", "時得使君相勞苦，勝于書札問寒温。", "只應此去添憔悴，又欠先生酒一尊。"]'),
('6d2e1e76-9f06-45c3-8d0d-36ad2633b845','寄題王珉中玉通判夢山堂','呂本中','宋','宋诗','song-poetry','','[]','青山甚不遠，每因塵事疏。',204,'全唐诗/poet.song.92000.json','["青山甚不遠，每因塵事疏。", "百念攪胸次，豈知山有無。", "君無適俗韻，常似山中居。", "出處本無二，夢覺固不殊。", "不知此山堂，始性從何途。", "未嘗走道路，亦不用舟車。", "溪流與山色，相對若有餘。", "此地甚閑曠，如君心地初。", "行雲映遠樹，中有此田廬。", "如今遂安處，始驗實不虚。", "得非神所相，無乃道力扶。", "親朋在左右，不待折簡呼。", "往來一笑樂，勝有十輪朱。", "何須從范子，辛苦泛五湖。", "亦不學淚溺，遠去斯人徒。", "從容萬事表，在我不在渠。", "欣然理前夢，已勝在華胥。"]'),
('011aa28e-de8a-4cf7-9a87-2cf463f16023','去冬以紙衾遺劉彦冲劉有詩來謝以二絕句答之  其一','呂本中','宋','宋诗','song-poetry','','[]','初無一物獻高人，紙被封題意却真。',32,'全唐诗/poet.song.92000.json','["初無一物獻高人，紙被封題意却真。", "想得蒙頭忘百慮，滿山風雪自成春。"]'),
('fe95540d-0318-422e-8e2d-a205f4545cd5','去冬以紙衾遺劉彦冲劉有詩來謝以二絕句答之  其二','呂本中','宋','宋诗','song-poetry','','[]','錦繡堆床已不宜，芬芳淑郁又成痴。',32,'全唐诗/poet.song.92000.json','["錦繡堆床已不宜，芬芳淑郁又成痴。", "心知此被無他巧，能與山翁換好詩。"]'),
('5b2f4c30-def7-4b9f-b38e-a7dc650b80fa','送曾季直下第歸臨川  其一','呂本中','宋','宋诗','song-poetry','','[]','老病侵凌重别離，爾來瘦欲不勝衣。',32,'全唐诗/poet.song.92000.json','["老病侵凌重别離，爾來瘦欲不勝衣。", "信州城北荒山寺，兩送親知下第歸。"]'),
('fd9f0c2f-4fe9-4e55-9442-2c3775ab8de1','送曾季直下第歸臨川  其二','呂本中','宋','宋诗','song-poetry','','[]','曾子不愁歸路泥，臨行索我送行詩。',32,'全唐诗/poet.song.92000.json','["曾子不愁歸路泥，臨行索我送行詩。", "頭童齒豁衰頹甚，不似京城相别時。"]'),
('2fb9ca9f-ab9a-4df7-9bba-11058c0ddbf2','送趙十一弟之官南安','呂本中','宋','宋诗','song-poetry','','[]','君爲千里行，我有一尊酒。',144,'全唐诗/poet.song.92000.json','["君爲千里行，我有一尊酒。", "把酒持勸君，欲以爲君壽。", "南安傍庾嶺，瘴癘亦時有。", "德人固天相，和氣生戶牖。", "斯民得安樂，如我屈伸肘。", "居然變遠俗，共感賢太守。", "我病居上饒，忽忽歲月久。", "杜門百事廢，亦復厭奔走。", "得君暫相從，感嘆成皓首。", "頗念河朔時，相從誦詩否。", "人生只此是，不必更抖擻。", "有便即寄書，頻來問衰朽。"]'),
('59561199-e87f-4d2e-a73a-b8c777f5bde4','寄劉彦冲兼寄胡原仲劉致中','呂本中','宋','宋诗','song-poetry','','[]','故人别去兩經冬，今歲書來第幾封。',64,'全唐诗/poet.song.92000.json','["故人别去兩經冬，今歲書來第幾封。", "正以空疏少製作，不因窮約廢過從。", "養生漫說終難效，學道無心亦未逢。", "若問真歸是何處，五更常聽寺樓鐘。"]'),
('b2fbab51-2eba-467a-b39e-8c35f3564306','去歲嘗以紙被竹簡遺劉致中後爲大水所漂致中有詩以二絕句答之  其一','呂本中','宋','宋诗','song-poetry','','[]','念君無愛亦無求，一室翛然冷欲秋。',32,'全唐诗/poet.song.92000.json','["念君無愛亦無求，一室翛然冷欲秋。", "尚恐深居有餘念，更將衾簡委洪流。"]'),
('a7edf3a9-1d54-438a-8631-0df76e8997d8','去歲嘗以紙被竹簡遺劉致中後爲大水所漂致中有詩以二絕句答之  其二','呂本中','宋','宋诗','song-poetry','','[]','紙被公無笑不才，兩公相繼有詩來。',32,'全唐诗/poet.song.92000.json','["紙被公無笑不才，兩公相繼有詩來。", "五更睡足天昏黒，也似他人錦繡堆。"]'),
('5caec185-f348-4b2d-aa54-87caa9872dc3','吳傅朋游絲書','呂本中','宋','宋诗','song-poetry','','[]','君不見往時文學顧八分，中郎之後典型存。',246,'全唐诗/poet.song.92000.json','["君不見往時文學顧八分，中郎之後典型存。", "又不見先朝文惠書堆墨，大榜濃雲照南北。", "未似只今上饒守，靜寫游絲不停手。", "非烟非雲斷復續，緩步徐行不拘束。", "斷崖一落千丈滑，遠望筆行如一髮。", "鬼神竭力覷不見，鐵礦消亡網作線。", "線舞飛揚不自由，縱横自在勝銀鈎。", "知君此意非安排，妙處不從筆下來。", "心疑形釋萬事去，信手却立無纖埃。", "滿堂回頭莫見猜，我自悟此忘胸懷。", "操舟相馬在事外，顔氏識此由心齋。", "如君下筆少有意，錦繡寧不悞剪裁。", "君惟無心故若此，秋毫自可纒風雷。", "鍾王歛手謝不敏，長史懷素慙衰頹。", "病夫覩此心目開，向來窮愁安在哉。"]'),
('50fbb0e0-d4e5-4f9e-8a33-31940c19758e','桂陽鹿頭山寺次壁間韻','呂本中','宋','宋诗','song-poetry','','[]','霜風過雨不勝寒，木落重重見遠山。',64,'全唐诗/poet.song.92000.json','["霜風過雨不勝寒，木落重重見遠山。", "風捲沈浮横浦外，鳥飛明滅夕陽間。", "頳肩道永方南去，趼足何時得北還。", "杖屨登臨共回首，自憐五澤入荒蠻。"]'),
('e67de54d-c076-4d0c-8c74-326a7d5870fa','同諸人再登鹿頭山再次前韻','呂本中','宋','宋诗','song-poetry','','[]','梅梢風動勒花寒，淡淡煙横天際山。',64,'全唐诗/poet.song.92000.json','["梅梢風動勒花寒，淡淡煙横天際山。", "顧我未能超物外，因君聊爾出雲間。", "水聲不逐鐘聲歇，林影常隨塔影還。", "異日同歸嵩少路，即將詩卷話南蠻。"]'),
('f164f88d-62ec-44bc-b731-1004d4c2f975','聞岳侯破賀州賊次韓端卿韻','呂本中','宋','宋诗','song-poetry','','[]','旌旗摩日甲生光，俘馘黄巾第幾方。',64,'全唐诗/poet.song.92000.json','["旌旗摩日甲生光，俘馘黄巾第幾方。", "滅賊未須占鬬蟻，破胡行且見神狼。", "燕然刻石功昭漢，太華題詩事後唐。", "從此兒童傳姓氏，風流何止繼韓康。"]'),
('66c452ae-ff9d-4dea-8211-a1c67d6f1373','永州法華寺西亭','呂本中','宋','宋诗','song-poetry','','[]','西亭清浄冠南州，蠟屐聊爲半日留。',64,'全唐诗/poet.song.92000.json','["西亭清浄冠南州，蠟屐聊爲半日留。", "蒼莽輕煙漲山麓，連卷雌霓落城頭。", "禽聲高下雲間木，帆影参差天際舟。", "欲去凭欄一回首，晚風吹角不勝愁。"]'),
('c7f3e968-8d8c-478e-9b0f-d153b6cd7f1e','廬陵舟行','呂本中','宋','宋诗','song-poetry','','[]','雨過歸雲山更昏，時聞鷄犬閙江村。',64,'全唐诗/poet.song.92000.json','["雨過歸雲山更昏，時聞鷄犬閙江村。", "風欹船側收帆幅，浪拍堤平沒石痕。", "憂患積年身益勌，功名他日志空存。", "又看秋色飛紅葉，故國歸期未可論。"]'),
('b8178ce5-f865-4712-9146-46d55954f161','春晚','呂本中','宋','宋诗','song-poetry','','[]','柳暗鶯啼春正妍，斷塍分水灌平田。',64,'全唐诗/poet.song.92000.json','["柳暗鶯啼春正妍，斷塍分水灌平田。", "花開花落幾番雨，山淡山明一抹烟。", "突兀初晴雲外寺，横斜欲晚渡頭船。", "天涯因惬滄洲興，何用區區苦自憐。"]'),
('815a9ede-4df9-4d20-b0dc-032984ded3c7','宜章元日','呂本中','宋','宋诗','song-poetry','','[]','東風初解凍，桃李已經春。',48,'全唐诗/poet.song.92000.json','["東風初解凍，桃李已經春。", "避地逢鷄日，傷時感雁臣。", "湖南馳賊騎，江外踐胡塵。", "憔悴成無用，虚煩泪濕巾。"]'),
('b6233540-d1de-436f-8c2a-f79b77276730','久雨','呂本中','宋','宋诗','song-poetry','','[]','宿雨何曾歇，濃雲未放晴。',48,'全唐诗/poet.song.92000.json','["宿雨何曾歇，濃雲未放晴。", "莓苔侵户長，蛙蚓入窗行。", "鐘送遠山響，燈挑殘夜明。", "芭蕉添客恨，只伴□簷聲。"]'),
('bc7bf18e-03e9-4aef-b977-881acbb8e08f','界步河亭','呂本中','宋','宋诗','song-poetry','','[]','窮山擁翠染人愁，亭下寒溪東北流。',32,'全唐诗/poet.song.93000.json','["窮山擁翠染人愁，亭下寒溪東北流。", "寄語扁舟舟上客，爲傳消息到筠州。"]'),
('95bdf25f-cf4a-49e2-93df-8238cf30c483','塗中久雨乍晴','呂本中','宋','宋诗','song-poetry','','[]','匝地濃雲散曉風，輕霜挟冷下長空。',32,'全唐诗/poet.song.93000.json','["匝地濃雲散曉風，輕霜挟冷下長空。", "攅峰疊嶂来無盡，疑是舟行圖畫中。"]'),
('e6cc5607-e8bf-42b1-9fe8-4fd1a705c17e','連州','呂本中','宋','宋诗','song-poetry','','[]','再到連州却是家，逢人不復嘆生涯。',32,'全唐诗/poet.song.93000.json','["再到連州却是家，逢人不復嘆生涯。", "尊前欲洒思鄉泪，羞見枝頭含笑花。"]'),
('8a292db5-4791-4be1-b2e1-78df11bcc1ee','寧遠道中','呂本中','宋','宋诗','song-poetry','','[]','路轉寒松日欲斜，野梅初吐兩三花。',32,'全唐诗/poet.song.93000.json','["路轉寒松日欲斜，野梅初吐兩三花。", "溪流映石風吹碧，時有粼粼雨後砂。"]'),
('f3b993bd-db8a-4071-8cfb-d28a8601776e','春晚','呂本中','宋','宋诗','song-poetry','','[]','宴坐翛然萬慮忘，從他風雨送春忙。',32,'全唐诗/poet.song.93000.json','["宴坐翛然萬慮忘，從他風雨送春忙。", "佛燈初上黄昏後，時炷郴州石乳香。"]'),
('283d5bc4-9495-4143-b19b-c2ae81412ed6','湘江斑竹','呂本中','宋','宋诗','song-poetry','','[]','湘江江上數重山，山遠雲深縹緲間。',32,'全唐诗/poet.song.93000.json','["湘江江上數重山，山遠雲深縹緲間。", "帝子不歸腸欲斷，竹梢空染淚痕斑。"]'),
('0488bc88-17ed-46a9-8268-540e8e224a42','興安靈渠','呂本中','宋','宋诗','song-poetry','','[]','淡日輕風細雨餘，陰陰溪柳映溪蒲。',32,'全唐诗/poet.song.93000.json','["淡日輕風細雨餘，陰陰溪柳映溪蒲。", "清流平岸舟行疾，野鳥時聞聲自呼。"]'),
('5e24a969-f3a1-4f96-9908-0d23832236eb','野岸','呂本中','宋','宋诗','song-poetry','','[]','淡日輕烟村徑斜，長風卷浪欲浮花。',32,'全唐诗/poet.song.93000.json','["淡日輕烟村徑斜，長風卷浪欲浮花。", "夜深隔岸漁舟過，螢火驚飛亂點沙。"]'),
('7150efcc-4451-4dd5-bbb0-cd88be027940','春晚即事','呂本中','宋','宋诗','song-poetry','','[]','淡淡陰雲晝掩門，隔溪楊柳暗江村。',32,'全唐诗/poet.song.93000.json','["淡淡陰雲晝掩門，隔溪楊柳暗江村。", "落花狼藉飛紅雨，又是潺湲過一春。"]'),
('8d5a6f70-1090-46d5-a89b-d12ae7b77e1c','香山觀壁間詩因次其韻','呂本中','宋','宋诗','song-poetry','','[]','抗志欲學仙，自恨無仙骨。',48,'全唐诗/poet.song.93000.json','["抗志欲學仙，自恨無仙骨。", "去國將六年，避地欠三窟。", "禪房翳翠陰，竹本可製笏。", "誰持大君前，指顧收回鶻。"]'),
('891c0c0d-a9cd-4e9c-9bbe-c4e8e241ed4b','懷古','呂本中','宋','宋诗','song-poetry','','[]','買臣負薪行且歌，其妻羞縮悲蹉跎。',128,'全唐诗/poet.song.93000.json','["買臣負薪行且歌，其妻羞縮悲蹉跎。", "季子歸佩六相印，骨肉歆羡緣金多。", "人生窮達等幻滅，貧賤何憂貴何悦。", "爭如饑采首陽薇，不慕臯夔希稷契。", "貪功徇名世莫嗤，拖金曳紫同兒嬉。", "一朝禍至幾發冢，却思衣布丹徒時。", "丹徒風月依然好，爾自升沈委荒草。", "草長木拱荒烟寒，此恨年年向誰道。"]'),
('992194e2-4748-47b8-91c5-dcfb633f94c8','近體詩二十韻寄秉之','呂本中','宋','宋诗','song-poetry','','[]','憶昔春將暮，分攜桂嶺邊。',240,'全唐诗/poet.song.93000.json','["憶昔春將暮，分攜桂嶺邊。", "落花依斷隴，飛絮滿長川。", "風急吹殘雨，雲開放曉天。", "山光如欲動，草木不勝妍。", "沽酒□村市，停驂近郭田。", "臨行思款曲，已别更流連。", "治邑煩游刃，編氓荷息肩。", "高牙久藏巧，篤行衆推賢。", "屢辱銀鈎貺，頻更玉律遷。", "故鄉迷藪澤，回夢渺雲烟。", "漂泊遥相望，窮愁秪自憐。", "愛閑身益嬾，多病氣仍孱。", "故國因人問，新年底事傳。", "政應升斗戀，聊結簿書緣。", "諸老方推轂，乘時好著鞭。", "提撕起憔悴，騰踏動蜿蜒。", "袖有平戎策，囊無封禪篇。", "功名期萬里，富貴屬丁年。", "范蠡中興越，田單卒破燕。", "異時歸捆載，乞我買隣錢。"]'),
('938114be-0727-4232-97db-1da22289dd02','離行在即事三首  其一','呂本中','宋','宋诗','song-poetry','','[]','昏旦黄□裏，經營謝獨清。',48,'全唐诗/poet.song.93000.json','["昏旦黄□裏，經營謝獨清。", "看人長麈尾，懷我短燈檠。", "舊友分窮達，斯文鼎重輕。", "邊聲授明主，禮樂謝諸生。"]'),
('6f5a0ca1-cb70-4eb3-aae9-eabdcc4adb6a','離行在即事三首  其二','呂本中','宋','宋诗','song-poetry','','[]','漂泊留旁郡，煩人久厚顔。',48,'全唐诗/poet.song.93000.json','["漂泊留旁郡，煩人久厚顔。", "强求微祿去，未得故鄉還。", "驛騎隨朝發，舟師語夜闌。", "到家傳吉夢，歸使下燕山。"]'),
('f1513660-6468-4493-a8a6-a3021d3c9df2','離行在即事三首  其三','呂本中','宋','宋诗','song-poetry','','[]','客况多堪笑，歸舟静擁衾。',48,'全唐诗/poet.song.93000.json','["客况多堪笑，歸舟静擁衾。", "轉喉常觸諱，對面卻論心。", "外物家無有，園居念本深。", "妻孥安短褐，終不羨多金。"]'),
('9d5ee737-1425-4026-9c9d-8f906a5ee020','廬陵相遇同煉金液贈師厚直閣','呂本中','宋','宋诗','song-poetry','','[]','掃地樗樹陰，扇火煉金液。',96,'全唐诗/poet.song.93000.json','["掃地樗樹陰，扇火煉金液。", "饑烏下朝陽，啄枝墜紅實。", "禿翁未着巾，僂背散破綌。", "提鈐顧四海，老手閑可惜。", "相勉各衰年，省事慎藥石。", "急當固根本，廼可傳損益。", "元氣日憊虧，藥邪資資賊。", "誰解醫乾坤，相視淚橫臆。"]'),
('3ea1b176-942a-467d-bb6c-22a11bf6d507','次韻景實椰子詩','呂本中','宋','宋诗','song-poetry','','[]','舊傳椰實來瓊州，珍如楚萍出中流。',128,'全唐诗/poet.song.93000.json','["舊傳椰實來瓊州，珍如楚萍出中流。", "雙帆入槳嚴護送，海若亦恐貽神羞。", "當時荔子寵妃子，一日紅塵歸帝里。", "棄捐碩果□不食，正音鏗鏘不入耳。", "勿嗤磈礧老瓠壺，中含瓊漿碧琳腴。", "聖門貌取失子羽，底事端可銘璠璵。", "新詩應欲泄感意，更復誇談作真賜。", "閲人如此慎勿欺，我□與君諳世事。"]'),
('71f7f54f-1d52-45a6-b871-5e4e5636c887','閑居','呂本中','宋','宋诗','song-poetry','','[]','風土傜人住，依棲縣令尊。',48,'全唐诗/poet.song.93000.json','["風土傜人住，依棲縣令尊。", "摘山春晚苦，汲澗雨餘渾。", "白日供高枕，生涯付小園。", "時来攜白鏟，種藥兩三根。"]'),
('3c3372e4-c729-49e5-9496-10dc887ca64a','冬日雜詩  其一','呂本中','宋','宋诗','song-poetry','','[]','白日供多病，青山且舊居。',48,'全唐诗/poet.song.93000.json','["白日供多病，青山且舊居。", "柴門臨水静，風葉舞霜餘。", "老練時情熟，貧□家計疏。", "牆東端可望，炙背飽翻書。"]'),
('c782aea1-07af-4b8d-bd65-cf405b68bcce','冬日雜詩  其二','呂本中','宋','宋诗','song-poetry','','[]','春景晴乃映，寒江曉不波。',48,'全唐诗/poet.song.93000.json','["春景晴乃映，寒江曉不波。", "雲山明客眼，風露净林柯。", "紫塞傳烽急，黄池带劍多。", "蒼生好蘇息，天意定如何。"]'),
('6f4a27f7-9bd6-4b3f-adeb-92ee5045638d','苦雨','呂本中','宋','宋诗','song-poetry','','[]','雨添東澗連西澗，雲斷前山起後山。',64,'全唐诗/poet.song.93000.json','["雨添東澗連西澗，雲斷前山起後山。", "野水到門人去盡，昏煙迷樹鳥飛還。", "江天日月渾無色，客路風埃只强顔。", "舞石至今隨燕乳，裁詩不復哭龍慳。"]'),
('5d06b2b2-da5a-4a9c-a046-a7b51e646fc2','題官使趙樞密獨往亭','呂本中','宋','宋诗','song-poetry','','[]','謝公爲時出，四海正仰渠。',144,'全唐诗/poet.song.93000.json','["謝公爲時出，四海正仰渠。", "雅志在東山，本末固不渝。", "苻堅百萬師，一掃談笑餘。", "今公抱長策，豈止安石徒。", "平生獨往願，結亭山一隅。", "躋扳上修竹，已自勝巾車。", "舉手謝世人，不與汝同途。", "出佐明天子，意欲無強胡。", "行當復中原，即日還舊都。", "豈容思昔隱，更作深山居。", "小人病無能，悮入承明廬。", "朝夕投劾歸，爲公先掃除。"]'),
('2c012a4a-46bb-4940-8119-2b55807eaf97','申瑞應詩','呂本中','宋','宋诗','song-poetry','','[]','避亂久去國，遠游將抱孫。',48,'全唐诗/poet.song.93000.json','["避亂久去國，遠游將抱孫。", "氛埃到湖嶠，愁嘆滿乾坤。", "氣力吾先老，風流子獨存。", "相逢能少駐，重爲倒餘尊。"]'),
('d81bcf52-2cdf-4681-9168-9d03270c1417','丁酉冬江上驚報','呂本中','宋','宋诗','song-poetry','','[]','京路蕭條信不通，胡塵尚欲競南風。',64,'全唐诗/poet.song.93000.json','["京路蕭條信不通，胡塵尚欲競南風。", "三年避地身多病，萬里攜孥囊屢空。", "天際每垂憂國淚，日邊誰了濟時功。", "宣王自是中興主，會見鑾輿返故宫。"]'),
('ca01d227-e94d-4073-9aef-da9967e57b7b','高安道中有懷故人李彤','呂本中','宋','宋诗','song-poetry','','[]','寒起溪邊蘆荻風，霜林病葉未全紅。',64,'全唐诗/poet.song.93000.json','["寒起溪邊蘆荻風，霜林病葉未全紅。", "雁隨雲落斜陽外，舟傍山行晚照中。", "極目閑愁愁欲絕，滿川離恨恨無窮。", "天涯更送親朋去，尊酒何時再得同。"]'),
('c2368091-a98a-417d-a726-41120de9141c','游陽山廣慶寺','呂本中','宋','宋诗','song-poetry','','[]','泝流蕩漿到陽山，寺在雲山縹緲間。',64,'全唐诗/poet.song.93000.json','["泝流蕩漿到陽山，寺在雲山縹緲間。", "雨洗竹萌穿野岸，風吹榕葉落荒灣。", "僧眠白日鐘聲静，花送青春鳥語閑。", "留醉嶺南無所恨，不妨蠟屐恣躋攀。"]'),
('c9292feb-fd88-4861-a36b-add945bbcdd6','自陽山還連州','呂本中','宋','宋诗','song-poetry','','[]','雨後輕裘寒尚侵，杖藜終日共登臨。',64,'全唐诗/poet.song.93000.json','["雨後輕裘寒尚侵，杖藜終日共登臨。", "水聲不似風聲急，山色何如草色深。", "萬疊殘雲渡晚照，千章古木發新陰。", "飄零未忍疏杯酌，欲醉翻嫌酒滿斟。"]'),
('6dd2616c-94fc-4918-bd48-645d14c6c0ba','柳州開元寺夏雨','呂本中','宋','宋诗','song-poetry','','[]','風雨翛翛似晚秋，鴉歸門掩伴僧幽。',64,'全唐诗/poet.song.93000.json','["風雨翛翛似晚秋，鴉歸門掩伴僧幽。", "雲深不見千巖秀，水漲初開萬壑留。", "鐘喚夢回空悵望，人傳書到竟沈浮。", "面如田字非吾相，莫羡班超封列侯。"]'),
('9a87912d-0b86-4095-957d-a828b1a49298','寄雲門山僧宗杲','呂本中','宋','宋诗','song-poetry','','[]','隋堤河畔别支公，目斷霜天數去鴻。',64,'全唐诗/poet.song.93000.json','["隋堤河畔别支公，目斷霜天數去鴻。", "歲月峥嶸如許久，江湖漂泊略相同。", "無窮煙草夕陽外，不盡雲山秋色中。", "寄語只今能見憶，書来莫遣太匆匆。"]'),
('ca7ee41d-ecec-4b3f-9e7e-df43424f6792','懷從弟','呂本中','宋','宋诗','song-poetry','','[]','折柳長亭今幾年，一行作吏楚江邊。',64,'全唐诗/poet.song.93000.json','["折柳長亭今幾年，一行作吏楚江邊。", "音書頓逐歸鴻斷，消息時因過客傳。", "五嶺風温吹瘴雨，九疑雲濕卷愁烟。", "每吟春草池塘句，尚想詩成夢惠連。"]'),
('9e3db853-6984-4df5-b279-a70c73c7cc14','郴州謁義帝陵廟','呂本中','宋','宋诗','song-poetry','','[]','淅淅寒聲未落霜，滿庭殘葉不勝黄。',64,'全唐诗/poet.song.93000.json','["淅淅寒聲未落霜，滿庭殘葉不勝黄。", "牆頭雨带煙悲冢，爐冷風飄塵带香。", "修墓尚應懷楚德，入關猶想快秦王。", "追思往事空垂淚，無限傷心對夕陽。"]'),
('2457680f-8b09-45d2-93a3-5e2f9a0d7926','絕句  其一','呂本中','宋','宋诗','song-poetry','','[]','雲海冥冥日向西，春風着意力猶微。',32,'全唐诗/poet.song.93000.json','["雲海冥冥日向西，春風着意力猶微。", "無端一棹歸舟疾，驚起鴛鴦相背飛。"]'),
('fb45c79d-fabc-47d6-952b-7e64b423cb27','絕句  其二','呂本中','宋','宋诗','song-poetry','','[]','過盡層城渡石梁，亂山千疊轉羊腸。',32,'全唐诗/poet.song.93000.json','["過盡層城渡石梁，亂山千疊轉羊腸。", "草堂居士風流在，與種寒香滿古堂。"]'),
('6c9de5ee-cf37-45a3-a433-cc5be5b646fa','絕句  其三','呂本中','宋','宋诗','song-poetry','','[]','江城春色漲晴空，櫻杏漫山潑眼紅。',32,'全唐诗/poet.song.93000.json','["江城春色漲晴空，櫻杏漫山潑眼紅。", "溪轉路迴人不見，籃輿十里度松風。"]'),
('e2e6ee0e-dc73-4479-bd0e-24a74de0e945','送韓存中侍郎赴光州二首  其一','呂本中','宋','宋诗','song-poetry','','[]','公今處群士，培塿望嵩高。',48,'全唐诗/poet.song.93000.json','["公今處群士，培塿望嵩高。", "不有千鈞重，虛蒙一字褒。", "荒山伏虎兕，小徑狎狸猱。", "默坐吾已得，往尋渠自勞。"]'),
('2b52d038-8251-4817-9ad4-217357f2bc35','送韓存中侍郎赴光州二首  其二','呂本中','宋','宋诗','song-poetry','','[]','令弟今先達，諸郎復可人。',48,'全唐诗/poet.song.93000.json','["令弟今先達，諸郎復可人。", "一麾公出守，三徑我知津。", "香火它年社，山河後夜春。", "會須從几杖，不必畫麒麟。"]'),
('0b4ec9ce-9f1b-467f-9019-0010522b6e11','試院中呈諸同官','呂本中','宋','宋诗','song-poetry','','[]','老眼文書便一窗，短檠風味竹方床。',64,'全唐诗/poet.song.93000.json','["老眼文書便一窗，短檠風味竹方床。", "洛陽甲子清明近，海內交游道里長。", "漸欲着身舡尾上，不能尋汝馬蹄旁。", "慢紅夭綠無多事，紫蝶黄蜂各自忙。"]'),
('bfc6625f-3664-4f9d-9e28-efee2870f51f','試院鎖宿數日未出','呂本中','宋','宋诗','song-poetry','','[]','一閉幾十日，春風能幾時。',48,'全唐诗/poet.song.93000.json','["一閉幾十日，春風能幾時。", "悮尋高士傳，虛負老人期。", "酒或知愁處，人應笑我癡。", "衰顔已無緒，仍對折殘枝。"]'),
('3c9395c8-5fb8-4d11-bd6b-d38e63112d4a','堤上','呂本中','宋','宋诗','song-poetry','','[]','水上人家各繫船，畫旗何處插鞦韆。',64,'全唐诗/poet.song.93000.json','["水上人家各繫船，畫旗何處插鞦韆。", "長堤繚繞人行外，古木槎牙鳥宿邊。", "敢爲簿書嫌蹭蹬，卻因升斗致留連。", "何時更鼓江南棹，一住越中三十年。"]'),
('a97c4a7a-7d73-4413-ba56-8c127c76c0d3','阻雨不出','呂本中','宋','宋诗','song-poetry','','[]','年來塵土住都城，尚見東行半月程。',32,'全唐诗/poet.song.93000.json','["年來塵土住都城，尚見東行半月程。", "一夜北風三尺雨，臥聞車馬濺泥聲。"]'),
('7080b86f-8dd4-442e-9d8d-936ba6e8e143','次潘節夫韻','呂本中','宋','宋诗','song-poetry','','[]','昔年繞舍培楸梧，霜風初勁葉未枯。',144,'全唐诗/poet.song.93000.json','["昔年繞舍培楸梧，霜風初勁葉未枯。", "雞肥兔賤年穀熟，草服黄冠真野夫。", "時時步屧遇鄰叟，共醉不復煩追呼。", "杯中滿汎注白玉，林邊阿堵無青鳬。", "擊壤歌缶有餘樂，豈羨騏驥馳大衢。", "眼眵看朱或成碧，心懵讀馬還作烏。", "富如安昌徒自苦，上賈必欲求膏腴。", "聲名向晚更寂寞，何似楊雄宅一區。", "美官好爵乃上苴，人生要在修廉隅。"]'),
('6762aaef-99d3-4cec-8ccb-96c059bd89c8','再用前韻寄璧公','呂本中','宋','宋诗','song-poetry','','[]','直言曾許老盲聾，文物當年掃地空。',64,'全唐诗/poet.song.93000.json','["直言曾許老盲聾，文物當年掃地空。", "縱病且懷脩月手，更窮不顧拍張公。", "長年眼作胡僧碧，舊賞花今何處紅。", "知有百年餘習在，略煩佳句愈頭風。"]'),
('10a74e38-5de1-40e9-b0cc-4ea0bb175691','郴州牛脾山謁景星觀下有白鹿洞乃蘇耽飛昇之地','呂本中','宋','宋诗','song-poetry','','[]','清霜散曉陰，輕風吹宿霧。',120,'全唐诗/poet.song.93000.json','["清霜散曉陰，輕風吹宿霧。", "橋傾絕人行，漁間借舟渡。", "初驚烏背轉，漸入牛脾路。", "長林連雲壑，細草縈石戶。", "洞深鎖靈蹤，鹿去驂仙馭。", "殿高鄰天冠，廊回寬地屨。", "驟響水湍流，飄香花似雨。", "崎嶇到山椒，靜曠奪塵慮。", "四顧但蒼莽，俯窺若軒翥。", "竚立鶴不歸，寒生日云莫。"]'),
('606a3324-8e06-4a7a-9941-1a310122cd75','春日十二韻','呂本中','宋','宋诗','song-poetry','','[]','看花不忍摘，憶在歷陽時。',120,'全唐诗/poet.song.93000.json','["看花不忍摘，憶在歷陽時。", "夢挾春風走，生嫌莫景移。", "老人扶杖隱，諸少倚歌遲。", "懶拙今誰問，漂流只自知。", "久無紅頰映，但有白須隨。", "一世半疾病，百年常別離。", "謾成歸隱夢，頻有送行詩。", "痛飲心猶在，高吟病不宜。", "未應譏偪仄，或恐勝肥癡。", "何日江南去，秋帆滿意吹。"]'),
('2a54b9d6-5d4a-46f2-86b5-11e0734ad952','京師雨春','呂本中','宋','宋诗','song-poetry','','[]','驟雨翻簷急，殘花落案頻。',48,'全唐诗/poet.song.93000.json','["驟雨翻簷急，殘花落案頻。", "春光一夢過，物態逐時新。", "舊識嵇康懶，兼隨原憲貧。", "南鄰鼓喚客，知是可憐人。"]'),
('e979d016-f448-468e-9fa0-64bccb00c756','府學治事奉懷張彥實兼寄惠子澤范信中向君受','呂本中','宋','宋诗','song-poetry','','[]','疾病衝忙百不宜，只今筋力已全衰。',64,'全唐诗/poet.song.93000.json','["疾病衝忙百不宜，只今筋力已全衰。", "長廊廣殿風來遠，古柳高槐日上遲。", "彭澤老人新斷酒，輞川居士舊能詩。", "已憐匹馬西歸後，更憶扁舟南渡時。"]'),
('d053361e-b529-4087-bdfc-1183ea30120d','寄家叔虛己','呂本中','宋','宋诗','song-poetry','','[]','莫言離別廢周旋，萬里星河共此天。',64,'全唐诗/poet.song.93000.json','["莫言離別廢周旋，萬里星河共此天。", "山色自然無罣礙，月明何處不團圓。", "寒雲渺莽初飛雁，野樹蕭條咽斷蟬。", "問舍求田經有願，曉帆春渚望回舡。"]'),
('2d365dcc-fded-4f2e-bf28-050924413f97','北齊','呂本中','宋','宋诗','song-poetry','','[]','陳郎苑裏朝朝樹，齊主宮中步步蓮。',32,'全唐诗/poet.song.93000.json','["陳郎苑裏朝朝樹，齊主宮中步步蓮。", "莫言河朔便粗魯，便有琵琶膝上弦。"]'),
('52d79740-d89d-419d-882b-90c8041b3461','信安生日','呂本中','宋','宋诗','song-poetry','','[]','和風藹藹動祥煙，此日祥鸞下九天。',64,'全唐诗/poet.song.93000.json','["和風藹藹動祥煙，此日祥鸞下九天。", "已共清秋卻殘暑，更同蒼柏享長年。", "瓊枝自出塵囂外，寶月常臨雨露前。", "□問當筵何所頌，人間今日地行仙。"]'),
('e3c48409-80cb-45f9-a9d3-19f6a9ff15c8','晉大寧四年王敦自武昌下屯于湖明年六月敦將舉兵內向明帝微行至于湖陰察其營壘而去唐溫庭筠作湖陰曲蓋爲此也後漢王霸之孫改封蕪湖吳時此地稱于湖或稱蕪湖察其營壘則姑熟之西初無湖陰又且于湖乃蕪湖也張文潛有于湖曲廣其意追和焉','呂本中','宋','宋诗','song-poetry','','[]','瑯琊初渡秦淮水，外旋轉姦雄抗胡壘。',193,'全唐诗/poet.song.93000.json','["瑯琊初渡秦淮水，外旋轉姦雄抗胡壘。", "白頭欻發問鼎新，十萬銳師同日起。", "旌旗蔽江銜舳艫，缷帆鈎壍屯于湖。", "雲昏霧慘恣誅殺，電激風奔傳指呼。", "謀狂慮逆天奪魄，晝夢環營日五色。", "巴滇駿馬去如飛，始遣輕兵索行客。", "黄須英特神所憐，舍旁老嫗留寶鞭。", "寶鞭玩賊佇俄頃，野陌塵斷生青煙。", "石城戰士爭憤泣，君王試敵曾深入。", "纍纍金印取封侯，忍瞰上流借餘力。", "際山暴骨真可哀，向來勝負安在哉。", "至今秋晚漁樵地，雨洗漬血空蒼苔。"]'),
('a42ced77-2130-4db6-87e6-65515210856e','題九江王插劍泉','呂本中','宋','宋诗','song-poetry','','[]','嬴氏方失鹿，群豪競奔馳。',168,'全唐诗/poet.song.93000.json','["嬴氏方失鹿，群豪競奔馳。", "較力爭勝負，未辨雄與雌。", "項羽奮其中，氣壓諸侯師。", "破關與救趙，九江實先之。", "指揮半率土，自謂可立治。", "孰知大蛇斷，天命潛已移。", "隋何說淮南，禍福非面欺。", "間行共歸漢，遂合垓下圍。", "海岳既在主，智勇安所施。", "不自晦圭角，寧能免嫌疑。", "殺身膏草莽，爲復歸怨誰。", "插劍郴岸口，泉溢何神奇。", "載籍加隱括，曷嘗親到斯。", "惜哉功名悮，徒令後世嗤。"]'),
('3ea36acb-7b65-4b6c-a372-e871e17e11f3','陽山大雹','呂本中','宋','宋诗','song-poetry','','[]','建炎庚戌正月尾，陽山雨雹大如李。',160,'全唐诗/poet.song.93000.json','["建炎庚戌正月尾，陽山雨雹大如李。", "疾雷先驅風御隨，頃刻雲屯遍千里。", "初疑地軸開九淵，固陰驚蟄神龍起。", "又恐帝出發震怒，下掃炎荒除癘鬼。", "破窗穿牖□□橫，觸石摧林勢難比。", "疑是曉色方窺簷，慘澹復黑迷巾履。", "披衣欲興還就枕，渹磕崩騰喧兩耳。", "吾君聖德過成康，胡虜憑陵殊未已。", "中原郡邑半丘墟，鐵騎猶思犯南鄙。", "安得天威假廟謨，恢復兩河端可竢。"]'),
('0fb34c7b-1d54-4130-af0e-52d82d9fff82','謁韓文公廟陽山','呂本中','宋','宋诗','song-poetry','','[]','雄文峙華嵩，高詞燦星斗。',144,'全唐诗/poet.song.93000.json','["雄文峙華嵩，高詞燦星斗。", "孝思古人齊，名出當時右。", "少小懷經綸，志氣頗自負。", "束带入柏臺，極力排姦醜。", "讒言如青蠅，正立無所苟。", "貶官宰陽山，萬里困奔走。", "松竹羅縣齋，黄卷不離手。", "地偏難蠻風，吏民歸化誘。", "至今數百年，流俗獨淳厚。", "山川發清奇，與公俱不朽。", "我來拜遺像，肴蔬薦芳酒。", "指石哦公詩，一洗胸中垢。"]'),
('961f4965-d5f7-4ad9-8aef-a78184183a44','游會勝寺蒙泉','呂本中','宋','宋诗','song-poetry','','[]','去郡十五里，滿山蔽青松。',144,'全唐诗/poet.song.93000.json','["去郡十五里，滿山蔽青松。", "朝來雨初過，蕭瑟鳴悲風。", "踏泥轉溪曲，路盡山無窮。", "層崖築欄閣，宛在雲煙中。", "引水遶砌下，濆石常飛濛。", "尋幽到寺背，蒼碧摩高空。", "古甃冽寒泉，淺沙影重重。", "伏流尚數步，暗與溪相通。", "潺湲去何之，可折從此東。", "會有到海期，豈計朝莫功。", "我行因避賊，眺覽聊從容。", "徘徊未忍去，僧飯催撞鍾。"]'),
('b8e51d53-e111-4bb7-a240-960319059e65','連州游隅湖亭','呂本中','宋','宋诗','song-poetry','','[]','附溪翳嘉木，瀕溪引清流。',120,'全唐诗/poet.song.93000.json','["附溪翳嘉木，瀕溪引清流。", "如何幾畝田，委曲林泉幽。", "亂石際高下，森列如戈矛。", "青色染黛淺，映水疑欲浮。", "危亭跨絕壁，廣榭排荒丘。", "我來雨初過，遠山雲半收。", "百花開已盡，桑柘鳴晴鳩。", "不知汝潁間，還有此景不。", "躊躇思痛飲，沃洗胸中愁。", "明朝儻未去，提壺再來游。"]'),
('2ef77aca-d7e9-45d0-9232-8f3ea40e9e7c','奉觀超然居士面面亭唱和新句輒成近體詩上呈','呂本中','宋','宋诗','song-poetry','','[]','我老日已懶，君閑寧廢詩。',48,'全唐诗/poet.song.93000.json','["我老日已懶，君閑寧廢詩。", "塵埃久無夢，苔竹舊相知。", "早晚春猶在，追隨病不宜。", "因觀七字句，尚足樂晨饑。"]'),
('e93b355d-4139-4055-85e3-cd69ab7fa6bc','送李惇秀才','呂本中','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','有口莫飲朝市水，有腳莫踏紅塵地。',128,'全唐诗/poet.song.93000.json','["有口莫飲朝市水，有腳莫踏紅塵地。", "市朝之水不可飲，塵埃一涴無由洗。", "十年閱世真夢寐，一日逢君得歡喜。", "自嫌急雨倒晴雷，且願濁河露清泚。", "君行此去道廬山，爲我作詩山兩間。", "寒泉夜聽鳴玦環，剗茅後池種白蓮。", "更約洪謝林汪潘，徐李欲去不作難。", "倚松聞之亦解顔，我且往矣君先還。"]'),
('763ea6dd-40e5-4583-9208-cd648535e60a','元日雪中作','呂本中','宋','宋诗','song-poetry','','[]','老病昏昏閑不出，山後山前雪三日。',64,'全唐诗/poet.song.93000.json','["老病昏昏閑不出，山後山前雪三日。", "人家閉戶作新年，一飽經營苦無術。", "朝地附火讀陽秋，箋注紛羅添一憂。", "未減少年窮事業，青燈分坐寫蠅頭。"]'),
('e074160e-6c11-4782-88ce-afb25d323d6c','送王周士','呂本中','宋','宋诗','song-poetry','','["\u8861\u5c71"]','病欲馳驅轉不宜，只今筋力十分衰。',64,'全唐诗/poet.song.93000.json','["病欲馳驅轉不宜，只今筋力十分衰。", "平生轗軻老更甚，此去艱難心自知。", "苛癢未除妨攝念，交遊雖近廢論詩。", "明年更欲尋公去，同上衡山過九疑。"]'),
('02f8eb11-142b-48a4-b387-43b7dba8f02d','寄小范','呂本中','宋','宋诗','song-poetry','','[]','高臥終無策，繙書謾作緣。',48,'全唐诗/poet.song.93000.json','["高臥終無策，繙書謾作緣。", "相望如一日，不見已三年。", "事少知心遠，居門覺地偏。", "明年得安靜，爲子下臨川。"]'),
('4a27c024-2afd-4c0b-99d2-cbc537756306','奉贈伯世仲志二弟  其一','呂本中','宋','宋诗','song-poetry','','[]','我已蹉跎不及閑，百年遺範子猶存。',32,'全唐诗/poet.song.93000.json','["我已蹉跎不及閑，百年遺範子猶存。", "故知前輩風流遠，世世傳家有外孫。"]'),
('d326cf8b-7141-4837-af9f-4eebbb7e5db9','奉贈伯世仲志二弟  其二','呂本中','宋','宋诗','song-poetry','','[]','往時天未喪斯文，吾祖聲名更絕群。',31,'全唐诗/poet.song.93000.json','["往時天未喪斯文，吾祖聲名更絕群。", "內外諸孫人在，不應如我便無聞。"]'),
('fcfc0198-86d2-4218-a262-dcc8d8be9e89','送張子直西歸  其一','呂本中','宋','宋诗','song-poetry','','[]','年來衰病只深藏，轉覺閑居氣味長。',32,'全唐诗/poet.song.93000.json','["年來衰病只深藏，轉覺閑居氣味長。", "所恨浮生有拘絆，不能相逐上瞿塘。"]'),
('201c4eb5-90ab-47d6-9d35-52684b933eaf','送張子直西歸  其二','呂本中','宋','宋诗','song-poetry','','[]','君家兄弟各能文，季也風流又絕群。',32,'全唐诗/poet.song.93000.json','["君家兄弟各能文，季也風流又絕群。", "萬里相逢又相別，落花時節卻思君。"]'),
('baf743dd-eacf-4aab-9bd9-53325bb5abe5','送張子直西歸  其三','呂本中','宋','宋诗','song-poetry','','[]','朋從索寞厭分離，老去心情祇自知。',32,'全唐诗/poet.song.93000.json','["朋從索寞厭分離，老去心情祇自知。", "記取上饒相望處，小橋南路往來時。"]'),
('e971b5f0-9eb8-45d5-8a17-871108c3c4d1','送張子直西歸  其四','呂本中','宋','宋诗','song-poetry','','[]','親舊留連莫厭頻，幷江花絮已殘春。',32,'全唐诗/poet.song.93000.json','["親舊留連莫厭頻，幷江花絮已殘春。", "定知數到嘗新酒，未有工夫憶故人。"]'),
('c9c0ae29-8568-4aec-80c4-009c77481575','謝趙士原送酒  其一','呂本中','宋','宋诗','song-poetry','','[]','小雨生涼挽未回，只愁殘暑悶風雷。',32,'全唐诗/poet.song.93000.json','["小雨生涼挽未回，只愁殘暑悶風雷。", "老人端坐氣如縷，更進先生雨一盃。"]'),
('ff7302b3-e011-4bb2-83c9-8cfadb2cac91','謝趙士原送酒  其二','呂本中','宋','宋诗','song-poetry','','[]','早來取酒瓶已空，對琖不復能從容。',32,'全唐诗/poet.song.93000.json','["早來取酒瓶已空，對琖不復能從容。", "出門更值督郵苦，住鬲猶憎琥珀濃。"]'),
('41f7429a-9f11-41b0-8509-2dd6a05505e9','謝趙士原送酒  其三','呂本中','宋','宋诗','song-poetry','','[]','老來疾病與時添，苦怕香醪如蜜甜。',32,'全唐诗/poet.song.93000.json','["老來疾病與時添，苦怕香醪如蜜甜。", "安得瀉缾清似水，主人應未笑無厭。"]'),
('3177feb3-8765-418d-8487-d035b1c8b43b','謝趙士原送酒  其四','呂本中','宋','宋诗','song-poetry','','[]','愛君好句能勝酒，顧我無心久似灰。',32,'全唐诗/poet.song.93000.json','["愛君好句能勝酒，顧我無心久似灰。", "老病深藏如怯暑，未妨初伏送詩來。"]'),
('5e493988-f088-465b-acd5-0aa32092a3e5','邦傑惠硯紙墨三物謹成古體詩一首上謝','呂本中','宋','宋诗','song-poetry','','[]','歙溪孕石成縠紋，歙山松煤煙入雲。',64,'全唐诗/poet.song.93000.json','["歙溪孕石成縠紋，歙山松煤煙入雲。", "敲冰落手卷盈軸，頓使几案生清芬。", "魏侯哦詩日更好，靜到溪山未枯槁。", "肯分三物到幽人，不留自起太玄草。"]'),
('44646963-b974-4698-be5e-7230e29b4ef9','燕龍圖畫山水歌','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','燕公畫山水，名在能品中。',175,'全唐诗/poet.song.93000.json','["燕公畫山水，名在能品中。", "至今筆墨欲飛動，妙處不與丹青同。", "巴陵六月風暴起，咫尺長江欲千里。", "魚龍變怪鮫鱷怒，細草長林恣鞭箠。", "斷雲卻掛懸石上，急雨正墮荒崖裏。", "想見行人弝檐時，亦有野店臨沙觜。", "漁子回頭嘆失色，霜女無言欣一洗。", "問公何處得此妙，長劍出匣須天倚。", "公不見簿書叢中塵埃多，歸思頗遭貧病魔。", "念今新涼江始波，如此萬水千山何。", "爲公試作吳興歌，更覓神仙張志和。"]'),
('367a1748-596a-4ba2-b0a2-cc813e80c026','初夏即事','呂本中','宋','宋诗','song-poetry','','[]','但見溪山如畫裏，不知風景是它鄉。',64,'全唐诗/poet.song.93000.json','["但見溪山如畫裏，不知風景是它鄉。", "苦遭毒暑三年旱，預喜西風一榻涼。", "俗事不須頻到口，舊書何苦要撐腸。", "雨聲只在芭蕉上，正與愁人作夜長。"]'),
('437eb34a-b4e3-4923-9718-5e269cf145d0','晚出','呂本中','宋','宋诗','song-poetry','','[]','小雨收殘暑，低雲隱莫雷。',48,'全唐诗/poet.song.93000.json','["小雨收殘暑，低雲隱莫雷。", "聊乘野興出，復爲故人回。", "旱日晚難好，秋花愁正開。", "論詩已奇事，猶恨不勝杯。"]'),
('cc0bc059-b84a-4202-b866-32c79e3eed5e','贈趙九弟','呂本中','宋','宋诗','song-poetry','','[]','獨居少還往，況此陰雨天。',96,'全唐诗/poet.song.93000.json','["獨居少還往，況此陰雨天。", "疏籬閉岑寂，晝永不得眠。", "芳菲隨手盡，樂事缺周旋。", "趙郎遠過我，千里一蓬舡。", "溫姿破殘夢，妙語爭春妍。", "喜逢骨肉親，懶初新少年。", "平生金石交，惟爾未改前。", "君看嵇與阮，感概後代傳。"]'),
('0194f45b-98db-408c-948e-ffb7137a6d03','寄李商老','呂本中','宋','宋诗','song-poetry','','[]','淥漲西河可縱篙，春光無信費詩招。',64,'全唐诗/poet.song.93000.json','["淥漲西河可縱篙，春光無信費詩招。", "香煙繚繞重城靜，月影欹斜半夜潮。", "好鳥似聞昆弟語，垂楊初放女兒腰。", "無人與語當時事，興盡江南大小喬。"]'),
('eb4de562-ab91-4753-a72e-836ad1852113','喜宗師諸公數見過分韻得席字','呂本中','宋','宋诗','song-poetry','','[]','野水春未生，積雪晴已滴。',120,'全唐诗/poet.song.93000.json','["野水春未生，積雪晴已滴。", "翛然六尺床，正可容一席。", "諸公數往還，未厭詩酒溺。", "短檠有新功，妙語乃破的。", "鱠槃約纖紅，茗碗亂晴碧。", "雖無費百金，亦有飲一石。", "尚念山堂老，病鳥藏羽翼。", "生平餘習在，種種見排斥。", "荒城滿泥潦，亦可試幽屐。", "明當袖詩往，先盡一醉力。"]'),
('7502e930-4e51-4ff1-9e79-30f881adc9dd','巫山圖歌','呂本中','宋','宋诗','song-poetry','','[]','君不見我家壁上六幅圖，淡墨寒煙半江水。',179,'全唐诗/poet.song.93000.json','["君不見我家壁上六幅圖，淡墨寒煙半江水。", "上有巉然十二峰，乃似突兀當空起。", "幽花嫵媚閉泥土，亂石崢嶸入荆杞。", "巫山縣下水到天，神女廟前江接連。", "溪流去與飛瀑亂，屋角卻對寒崖懸。", "陽臺昨夢不知處，只今饑鴉迎客舡。", "饑鳥受食不肯去，舟子欣然得神護。", "曉鏡新粧斂舊屏，亦有餘紅點荒樹。", "病夫坐穩便幽禪，每見此畫心茫然。", "文章事業已罷倦，少日氣味無寅緣。", "楚王不作宋玉死，莫雨朝雲千萬年。"]'),
('19dd4858-1325-4e8f-b49b-143e9e421639','將去濟陰寄泗上寧陵','呂本中','宋','宋诗','song-poetry','','[]','淮海三年別，家山十日程。',48,'全唐诗/poet.song.93000.json','["淮海三年別，家山十日程。", "時思一笑樂，轉覺異鄉情。", "叔父勤相喚，諸郎許見迎。", "濁醪行處有，所恨不同傾。"]'),
('0536c625-788f-4741-876c-9191e743f8be','宿石頭多寶寺','呂本中','宋','宋诗','song-poetry','','[]','四山環其外，一峰屹當中。',96,'全唐诗/poet.song.93000.json','["四山環其外，一峰屹當中。", "支徑轉屈曲，雲峰踏飛鴻。", "僧居架蒼崖，高下潛相通。", "昏鐘罷香火，餘音裊寒空。", "梅開何處花，吹香到簾櫳。", "回望雲山城，木杪殘陽紅。", "愁心易生感，滿耳唯松風。", "對酒成浩歌，漂零見涂窮。"]'),
('f5ee7225-04a9-4ae3-a2fe-bfa03d60b638','兵亂後自嬄雜詩  其一','呂本中','宋','宋诗','song-poetry','','[]','晚逢戎馬際，處處聚兵時。',48,'全唐诗/poet.song.93000.json','["晚逢戎馬際，處處聚兵時。", "後死翻爲累，偷生未有期。", "積憂全少睡，經劫抱長饑。", "欲逐范仔輩，同盟起義師。"]'),
('393dc7d3-9d44-41f5-81e8-22e56fa316f7','兵亂後自嬄雜詩  其二','呂本中','宋','宋诗','song-poetry','','[]','羽檄連朝莫，戎旃匝邇遐。',48,'全唐诗/poet.song.93000.json','["羽檄連朝莫，戎旃匝邇遐。", "未教知死所，詎所作生涯。", "東郭同逃戶，西郊類破家。", "萍蓬無定跡，屢欲過三巴。"]'),
('f806b03e-18b9-4463-a574-2ca756a0038c','兵亂後自嬄雜詩  其三','呂本中','宋','宋诗','song-poetry','','[]','胡騎猖狂甚，連年窺西京。',48,'全唐诗/poet.song.93000.json','["胡騎猖狂甚，連年窺西京。", "貪饕期竭澤，剪戮遂盈城。", "國論多遺策，人情罷請纓。", "有誰似南八，血指衆心驚。"]'),
('0af95887-f997-45c3-9ed5-c5429ca755f5','兵亂後自嬄雜詩  其四','呂本中','宋','宋诗','song-poetry','','[]','廬舍經兵火，頭顱尚在門。',48,'全唐诗/poet.song.93000.json','["廬舍經兵火，頭顱尚在門。", "風掀灰𡏖跡，月澀劍鋩魂。", "鼠穴頻遭斷，燕巢猶半存。", "看花淚盈眼，寧忍復開尊。"]'),
('f14fd6f9-d937-451c-8b3d-e5308622a104','兵亂後自嬄雜詩  其五','呂本中','宋','宋诗','song-poetry','','[]','碣石豺狼種，長驅出不虞。',48,'全唐诗/poet.song.93000.json','["碣石豺狼種，長驅出不虞。", "是誰遺此賊，故使亂中都。", "官府室如磬，人家錐也無。", "有司少恩惠，何忍復追呼。"]'),
('5d7f0729-1eb2-42e3-a6d9-27187ef3576c','兵亂後自嬄雜詩  其六','呂本中','宋','宋诗','song-poetry','','[]','叛將斬關入，通衢列衆兵。',48,'全唐诗/poet.song.93000.json','["叛將斬關入，通衢列衆兵。", "軍聲逐飛瓦，殺氣暗前旌。", "事定愁方劇，身危夢尚驚。", "乾坤空納納，何處寄餘生。"]'),
('4d599371-32f4-44a5-aafd-6ba6172a0b6c','兵亂後自嬄雜詩  其七','呂本中','宋','宋诗','song-poetry','','[]','將士承恩澤，臨危勿擇安。',48,'全唐诗/poet.song.93000.json','["將士承恩澤，臨危勿擇安。", "牛衣寒臥易，馬革裹尸難。", "破虜陳奇計，策勛超達官。", "兜鍪未可忽，從古出貂冠。"]'),
('4c1e5b59-de2c-47f2-b4f9-38fd66022f2e','兵亂後自嬄雜詩  其八','呂本中','宋','宋诗','song-poetry','','[]','夷甫終隳晉，群胡迫帝居。',48,'全唐诗/poet.song.93000.json','["夷甫終隳晉，群胡迫帝居。", "王綱板蕩後，國勢土崩初。", "戈戟連梁苑，頭顱塞浚渠。", "天心應助順，側聽十行書。"]'),
('0defc564-53ef-415a-97ca-817a14f7ba92','兵亂後自嬄雜詩  其九','呂本中','宋','宋诗','song-poetry','','[]','黄事多反覆，蕭蘭不辨真。',48,'全唐诗/poet.song.93000.json','["黄事多反覆，蕭蘭不辨真。", "汝爲誤國賊，我作破家人。", "求飽羹無糝，澆愁爵有塵。", "往來梁上燕，相顧卻情親。"]'),
('88dd77b9-4cb5-45b4-81d2-6fbf64d954cb','兵亂後自嬄雜詩  其一○','呂本中','宋','宋诗','song-poetry','','[]','兵餘門巷靜，親故白頭新。',48,'全唐诗/poet.song.93000.json','["兵餘門巷靜，親故白頭新。", "常與貧爲侶，祇將愁送春。", "焚車絕此事，推宅望何人。", "便得長安信，相看眉一伸。"]'),
('11ec2df0-d8ff-4d8e-adf7-b00e9490591d','兵亂後自嬄雜詩  其一一','呂本中','宋','宋诗','song-poetry','','[]','國命方屯厄，吾曹何所依。',48,'全唐诗/poet.song.93000.json','["國命方屯厄，吾曹何所依。", "白駒將老至，黄鳥恨春歸。", "柳巷清陰合，花蹊紅蕊稀。", "主憂聞未解，涕泗望天畿。"]'),
('4a33d5b2-f203-41d1-a0b9-ee20a2e9b75b','兵亂後自嬄雜詩  其一二','呂本中','宋','宋诗','song-poetry','','[]','江城朝夕閉，里巷絕人行。',48,'全唐诗/poet.song.93000.json','["江城朝夕閉，里巷絕人行。", "驕虜未歸塞，凶渠猶弄兵。", "正須烽火息，早罷陣雲橫。", "胡孽將銷藴，吾君幸聖明。"]'),
('dbad3524-cbed-48dd-8d24-2536bfc7424f','兵亂後自嬄雜詩  其一三','呂本中','宋','宋诗','song-poetry','','[]','四郊多屬壘，何地可逃生。',48,'全唐诗/poet.song.93000.json','["四郊多屬壘，何地可逃生。", "水水但爭渡，城城各點兵。", "牛亡罷春種，馬奪盡徒行。", "囊櫜經鈔掠，寇來渾不驚。"]'),
('e041d755-befb-4507-838a-86992ce4ed76','兵亂後自嬄雜詩  其一四','呂本中','宋','宋诗','song-poetry','','[]','蝸舍嗟蕪沒，孤城亂定初。',48,'全唐诗/poet.song.93000.json','["蝸舍嗟蕪沒，孤城亂定初。", "籬根留敝屨，屋角得殘書。", "雲路慚高鳥，淵潛羨巨魚。", "客來闕佳致，親爲摘山蔬。"]'),
('115624b3-8661-469d-909e-d7676d1cfcad','兵亂後自嬄雜詩  其一五','呂本中','宋','宋诗','song-poetry','','[]','一紀幽棲地，宛然高樹林。',48,'全唐诗/poet.song.93000.json','["一紀幽棲地，宛然高樹林。", "比鄰風雨散，垣屋草萊深。", "池面華光歇，井床苔色侵。", "衰年筋力弱，閣道罷登臨。"]'),
('2db80b1b-47d5-4a82-a1a6-bf345542dd01','兵亂後自嬄雜詩  其一六','呂本中','宋','宋诗','song-poetry','','[]','一廛江上宅，毀撤自群凶。',48,'全唐诗/poet.song.93000.json','["一廛江上宅，毀撤自群凶。", "卜築勞心計，攜鉏失指蹤。", "鳩啼□□景，花斂带愁容。", "何日休兵革，重來依老農。"]'),
('d59275ad-4c39-4f9a-b554-9daeff52c5b8','兵亂後自嬄雜詩  其一七','呂本中','宋','宋诗','song-poetry','','[]','遭亂心紆鬰，那堪茅舍空。',48,'全唐诗/poet.song.93000.json','["遭亂心紆鬰，那堪茅舍空。", "百年窘食事，一旦墮兵戎。", "授簡慙詞客，據鞍成老翁。", "欲逃無所適，朝夕泣涂窮。"]'),
('de97610b-4dcb-4813-8033-934195d88acb','兵亂後自嬄雜詩  其一八','呂本中','宋','宋诗','song-poetry','','[]','汾陽六甲士，率衆出中都。',48,'全唐诗/poet.song.93000.json','["汾陽六甲士，率衆出中都。", "欲使親平虜，翻成遠避胡。", "操戈取金幣，奪馬載妻孥。", "汝自違天意，何緣保汝軀。"]'),
('18158c15-af42-4dc4-bcd4-02cca512ecbb','兵亂後自嬄雜詩  其一九','呂本中','宋','宋诗','song-poetry','','[]','春宅屯兵後，荒墟非故居。',48,'全唐诗/poet.song.93000.json','["春宅屯兵後，荒墟非故居。", "陶門柳徑短，阮舍竹陰疏。", "風雨無由障，牛羊自入廬。", "朝廷安反側，何日降恩書。"]'),
('9fa2c681-ece2-4f70-b660-263c7e025520','兵亂後自嬄雜詩  其二○','呂本中','宋','宋诗','song-poetry','','[]','平世多忘戰，今真得陣梁。',48,'全唐诗/poet.song.93000.json','["平世多忘戰，今真得陣梁。", "燕雲擁豺虎，陸晉失金湯。", "漢將爭奔北，胡兵尚崛強。", "何當合餘燼，戮力共勤王。"]'),
('49833874-60bd-4c77-bd73-19ef4473a376','兵亂後自嬄雜詩  其二一','呂本中','宋','宋诗','song-poetry','','[]','閭巷經鏖戰，空餘池上亭。',48,'全唐诗/poet.song.93000.json','["閭巷經鏖戰，空餘池上亭。", "簷楹鏃可拾，草木血猶腥。", "雲漢悲鴻雁，郊原媿鶺鴒。", "白頭兩兄弟，各未保殘齡。"]'),
('d6885b0e-2e63-4709-8595-d7b03ef5ee0c','兵亂後自嬄雜詩  其二二','呂本中','宋','宋诗','song-poetry','','[]','嬖孽開邊隙，羌胡恃釁端。',48,'全唐诗/poet.song.93000.json','["嬖孽開邊隙，羌胡恃釁端。", "天戈增照耀，國步向平安。", "騎吹春容遠，孤烽戰氣殘。", "妖星稍退舍，便覽老懷寬。"]'),
('2b515268-eba7-419e-a024-e36c9be905c4','兵亂後自嬄雜詩  其二三','呂本中','宋','宋诗','song-poetry','','[]','亂後驚身在，端如犬喪家。',48,'全唐诗/poet.song.93000.json','["亂後驚身在，端如犬喪家。", "沈吟悲世故，寂默對春華。", "堤外鴉藏柳，欄中蜂動花。", "今宵眠未愁，餘寇尚紛拏。"]'),
('1a765e2a-b7d5-4e30-80de-55d6331b94f5','兵亂後自嬄雜詩  其二四','呂本中','宋','宋诗','song-poetry','','[]','君父圍城內，忽逾三月期。',48,'全唐诗/poet.song.93000.json','["君父圍城內，忽逾三月期。", "六龍時𡰈卼，百雉日孤危。", "報國寧無策，全軀各有詞。", "旄頭漸低小，早晚定班師。"]'),
('95ac3ec3-0655-40b1-bf3c-bb774b497105','兵亂後自嬄雜詩  其二五','呂本中','宋','宋诗','song-poetry','','[]','亂離仍再歲，未敢有吾廬。',48,'全唐诗/poet.song.93000.json','["亂離仍再歲，未敢有吾廬。", "林下休官久，草間求活初。", "跡雖寄戎旅，心已混樵漁。", "吉語來何晚，將軍□素書。"]'),
('872fc0f2-6fd9-4efc-97ca-88fa61207766','兵亂後自嬄雜詩  其二六','呂本中','宋','宋诗','song-poetry','','[]','重到江頭宅，荒殘足嘆嗟。',48,'全唐诗/poet.song.93000.json','["重到江頭宅，荒殘足嘆嗟。", "新烏忽栖樹，舊犬已辭家。", "月淡初回夢，風輕不落花。", "相親爲部曲，弓劍作生涯。"]'),
('aa06cf89-c534-4292-906b-ab0fbaa3b907','兵亂後自嬄雜詩  其二七','呂本中','宋','宋诗','song-poetry','','[]','偷生戎馬內，室宇半摧殘。',48,'全唐诗/poet.song.93000.json','["偷生戎馬內，室宇半摧殘。", "假寐何曾着，驚魂尚未安。", "風前花自妥，雨後食猶寒。", "望斷京華信，終宵淚不干。"]'),
('22f038c2-528a-444c-a523-a7cbe243c9c2','兵亂後自嬄雜詩  其二八','呂本中','宋','宋诗','song-poetry','','[]','忽復清明過，林園綠陰稠。',48,'全唐诗/poet.song.93000.json','["忽復清明過，林園綠陰稠。", "光陰同轂轉，身世着舟浮。", "舊識梁間燕，全生水上鷗。", "幸聞諸將輩，稍稍近前旒。"]'),
('fc0efecd-5ea0-4672-9de7-b1c3ea67df14','兵亂後自嬄雜詩  其二九','呂本中','宋','宋诗','song-poetry','','[]','歲間值狂寇，曾此駐戈鋋。',48,'全唐诗/poet.song.93000.json','["歲間值狂寇，曾此駐戈鋋。", "臺沼餘春草，圖書散野煙。", "懶尋愛酒伴，愁起落花邊。", "不忍登江閣，心隨北斗懸。"]'),
('4528d685-d263-44f8-861f-8bd9aa4ed2ba','賀州周秀才','呂本中','宋','宋诗','song-poetry','','[]','青松着城市，不辭塵土侵。',145,'全唐诗/poet.song.93000.json','["青松着城市，不辭塵土侵。", "忍恥伴桃李，肯言歸故林。", "交游在貧賤，始見平生心。", "周侯客異縣，屢蒙金玉音。", "殷勤不我厭，自昔以至今。", "使其小富貴，未必能相尋。", "豈謂子誠然，此風風今則深。", "子行轉嶺海，歲莫足愁陰。", "路多資賊窘，往往未能擒。", "加鞭策駑馬，欲往無滯淫。", "故人散天涯，所到足崎崟。", "相逢儻見及，道我病難侵。"]'),
('d240a24b-41e5-49ca-a88d-e3de630727e1','寄題莊季裕靜軒','呂本中','宋','宋诗','song-poetry','','[]','雲靜天如水，風停海不波。',24,'全唐诗/poet.song.93000.json','["雲靜天如水，風停海不波。", "請觀如是相，夫子意如何。"]'),
('1d2f9a09-bed7-4a5a-8f1c-1a0a3ae54c27','雪中奉簡張子直','呂本中','宋','宋诗','song-poetry','','[]','深居畏雪謾添衣，過了梅花病不知。',32,'全唐诗/poet.song.93000.json','["深居畏雪謾添衣，過了梅花病不知。", "同住荒越懶還往，一年天氣最寒時。"]'),
('080dff82-d636-4a61-a09d-41e8888758bb','夜同李十步月至崔成美家','呂本中','宋','宋诗','song-poetry','','[]','伏暑不可去，客帆秋未回。',48,'全唐诗/poet.song.93000.json','["伏暑不可去，客帆秋未回。", "偶攜南縣李，來訪北橋崔。", "藤枕風前簟，瓜盤月下杯。", "十年老懷抱，姑爲故人開。"]'),
('0a2c888d-286c-428c-9944-54c6be14dee9','讀東坡詩','呂本中','宋','宋诗','song-poetry','','[]','命代風騷第一功，斯文到底爲誰雄。',64,'全唐诗/poet.song.93000.json','["命代風騷第一功，斯文到底爲誰雄。", "太山北斗攀韓愈，琨玉秋霜敵孔融。", "不見陸機歸洛下，只聞張翰過江東。", "廣陵雅操無人繼，六十餘年一夢中。"]'),
('6df221b9-2708-4a62-98b3-ca951f4a1b10','讀亡弟由義舊詩有感','呂本中','宋','宋诗','song-poetry','','[]','平昔烏衣游，盛事寄青史。',132,'全唐诗/poet.song.93000.json','["平昔烏衣游，盛事寄青史。", "後生見頭角，唯子與夫子。", "奈何阻中涂，去我適蒿里。", "三年莫春日，西郊漫桃李。", "才難聖所嘆，反是俗眼瞇。", "坐看玉壺冰，終污青蠅矢。", "銜憤已成疾，傷讒空忍死。", "雪涕別時言，歷歷猶在耳。", "嗚呼骨肉親，遺恨有如此。", "吾生復亡聊，念爾中夜起。", "讀君離別篇，沈吟淚如水。"]'),
('c22d67b8-6d90-41c2-abdf-728a159ca595','與范益謙飲有懷才仲','呂本中','宋','宋诗','song-poetry','','[]','范郎醉倒西風前，夜思趙子起不眠。',96,'全唐诗/poet.song.93000.json','["范郎醉倒西風前，夜思趙子起不眠。", "與渠別來今幾年，細數往事如雷顛。", "塵埃刺促今尚賢，問我北行詩幾篇。", "殘篇斷簡棄不編，鶴鳴九皋鳶唳天。", "燕雀欲上無寅緣，江湖舊游性所便。", "我先往矣君加鞭，更呼趙子來同船。"]'),
('975563a4-c144-4c76-8bb8-f2d47c3a6cbf','感懷','呂本中','宋','宋诗','song-poetry','','[]','十年南北長爲客，萬里江山半是鄉。',64,'全唐诗/poet.song.93000.json','["十年南北長爲客，萬里江山半是鄉。", "夢裏題詩隨意了，醉中書字不成行。", "燕思公子歸來早，草憶王孫恨更長。", "枕上不知多少事，覺來依舊熟黄粱。"]'),
('e6f374c3-908a-445e-b17c-ff943fa56fb5','贈唐虎','呂本中','宋','宋诗','song-poetry','','[]','白酒因循久絕傾，小詩聊復贈君行。',32,'全唐诗/poet.song.93000.json','["白酒因循久絕傾，小詩聊復贈君行。", "故人若問庵中事，但道春來太瘦生。"]'),
('a5c55ee0-8507-4d26-9f2f-6b709f66798f','寄酒與陽翟諸弟','呂本中','宋','宋诗','song-poetry','','[]','奔走黄塵小說歸，諸郎堅坐各能詩。',64,'全唐诗/poet.song.93000.json','["奔走黄塵小說歸，諸郎堅坐各能詩。", "略無夢去尋消息，謾有書來道別離。", "但得阮公連月醉，不嫌王湛半生癡。", "遙知共飲北窗下，自勝烏衣全盛時。"]'),
('04c31fa3-2e65-4d4f-b8ca-10faa384d136','晉康逢師厚','呂本中','宋','宋诗','song-poetry','','[]','藤江合賀江，浮蕩蒼梧雲。',252,'全唐诗/poet.song.93000.json','["藤江合賀江，浮蕩蒼梧雲。", "我如老餓鶴，忍饑啄蠻塵。", "二更客入戶，月黑雨翻盆。", "坐久始驚省，兩翁非昔人。", "一別二十年，家國忍復論。", "豈知半暗眼，再見忠宣孫。", "君負濟世美，實識治亂根。", "寧同二三子，但粥父祖名。", "心豈燕丘壑，屢召終逡巡。", "新年憤忠極，決意去脩門。", "龍鬼亦妬賢，翻舟使回奔。", "嗚呼天下事，敢笑不敢言。", "師尹實令弟，高義橫乾坤。", "政坐才卓犖，亦使身奇屯。", "人說龔州居，勝事專江村。", "未赴結社約，長耿懷友心。", "君歸兄弟語，況我應殷勤。", "二子豈隱者，中興要甫申。", "勉哉赤松子，善事黄中君。", "我欲北渡嶺，江西老耕耘。", "子房但強飯，勿道綺與園。"]'),
('462f03e9-3617-43a5-9c12-5a8964b711d2','初十日王震秀才家探梅','呂本中','宋','宋诗','song-poetry','','[]','不問主人聊一來，水亭風榭小徘徊。',32,'全唐诗/poet.song.93000.json','["不問主人聊一來，水亭風榭小徘徊。", "春風大似私南土，未臘江梅半欲開。"]'),
('248d7b32-8ee8-4c31-b389-0b47bf41a9d3','王園觀梅主人置酒莫歸  其一','呂本中','宋','宋诗','song-poetry','','[]','臨溪照影若自愛，犯雪看花寧怕寒。',32,'全唐诗/poet.song.93000.json','["臨溪照影若自愛，犯雪看花寧怕寒。", "百繞蜂兒緣底事，癡心猶作蜜房看。"]'),
('88ec40b3-c74c-4b0e-8055-df667784f04a','王園觀梅主人置酒莫歸  其二','呂本中','宋','宋诗','song-poetry','','[]','日沒未沒霧索山，古寺松門欲上關。',32,'全唐诗/poet.song.93000.json','["日沒未沒霧索山，古寺松門欲上關。", "尚有香風泛衣袖，兒童知我探春還。"]'),
('686af65a-63d2-45eb-8081-326a8b4260d9','飯花光店是日立春','呂本中','宋','宋诗','song-poetry','','[]','採勝繒幡安在哉，客行巾帽只風埃。',64,'全唐诗/poet.song.93000.json','["採勝繒幡安在哉，客行巾帽只風埃。", "東西水畔凍全坼，南北枝頭春已回。", "故國音書黄耳斷，餘生光景白駒催。", "山村誰道全荒陋，也有畦蔬入饌來。"]'),
('dbb0796f-3c98-43e2-a017-80fc8fc0823e','清隱及歐園賞梅  其一','呂本中','宋','宋诗','song-poetry','','[]','亭邊竹外影疏疏，惱客清香半有無。',32,'全唐诗/poet.song.93000.json','["亭邊竹外影疏疏，惱客清香半有無。", "不共東君苦交涉，只緣冰雪作肌膚。"]'),
('cc6fe32b-bc2b-48a6-b38d-f71439ae4d34','清隱及歐園賞梅  其二','呂本中','宋','宋诗','song-poetry','','[]','枮叢凍枿兩交加，中有仙人萼綠華。',32,'全唐诗/poet.song.93000.json','["枮叢凍枿兩交加，中有仙人萼綠華。", "會挽一枝供越使，莫令三弄發胡笳。"]'),
('bcd29c67-e895-408c-9445-ae37cb869b15','清隱及歐園賞梅  其三','呂本中','宋','宋诗','song-poetry','','[]','向人一笑真粲者，出屋數枝殊瘦生。',32,'全唐诗/poet.song.93000.json','["向人一笑真粲者，出屋數枝殊瘦生。", "剛腸妙句兩無語，始覺諸孫愧廣平。"]'),
('c4c74b4f-9863-4592-9faa-86d5953dbd85','次韻酴醿  其一','呂本中','宋','宋诗','song-poetry','','[]','絕去人間淺俗香，染成天上羽衣黄。',32,'全唐诗/poet.song.93000.json','["絕去人間淺俗香，染成天上羽衣黄。", "綠窗擬倩纖纖手，收拾春風入枕囊。"]'),
('abbe1b80-e6d2-48d5-b19e-5c793689dd93','次韻酴醿  其二','呂本中','宋','宋诗','song-poetry','','[]','掩冉欹垂千萬條，始知天女是青腰。',32,'全唐诗/poet.song.93000.json','["掩冉欹垂千萬條，始知天女是青腰。", "輕衫曾立花陰下，三日餘香尚不銷。"]'),
('99bfa9f9-2a36-4d93-9084-9e7807ea123c','寒食  其一','呂本中','宋','宋诗','song-poetry','','[]','三年羈旅逢寒食，萬里江山隔故園。',32,'全唐诗/poet.song.93000.json','["三年羈旅逢寒食，萬里江山隔故園。", "墳墓荒涼誰拜掃，東風吹淚濕黄昏。"]'),
('d9be2be4-e8b4-41ea-b7d0-19f08227335b','寒食  其二','呂本中','宋','宋诗','song-poetry','','[]','淮南江北半胡兵，想見春風戰血腥。',32,'全唐诗/poet.song.93000.json','["淮南江北半胡兵，想見春風戰血腥。", "無復良辰修祓禊，空將新火發兜零。"]'),
('c3cf007a-39f4-443c-9d90-50b9a39be0c2','寒食  其三','呂本中','宋','宋诗','song-poetry','','[]','野哭行歌滿道邊，紙灰飛處落烏鳶。',32,'全唐诗/poet.song.93000.json','["野哭行歌滿道邊，紙灰飛處落烏鳶。", "墦間祭肉能多少，只恐齊人意缺然。"]'),
('cb78df77-d1f3-492c-9b04-255c36daaaaa','寒食  其四','呂本中','宋','宋诗','song-poetry','','[]','病夫只欲閉柴荆，客至從嗔不出迎。',32,'全唐诗/poet.song.93000.json','["病夫只欲閉柴荆，客至從嗔不出迎。", "未恨家貧無曆日，紫桐花發即清明。"]'),
('237ba935-d701-4dd2-bb82-a925745cb64b','寒食  其五','呂本中','宋','宋诗','song-poetry','','[]','松塢雲窗睡足時，溪藤閑展試毛錐。',32,'全唐诗/poet.song.93000.json','["松塢雲窗睡足時，溪藤閑展試毛錐。", "薄才豈敢追能事，寒食江村合有詩。"]'),
('f77f0856-62ff-4328-ab7e-52af3f9b1aea','宿嵩前','呂本中','宋','宋诗','song-poetry','','[]','火雲如鵬騫，簸翮赴山谷。',84,'全唐诗/poet.song.93000.json','["火雲如鵬騫，簸翮赴山谷。", "獨含片雨歸，故故喧澗竹。", "野亭桂空起，入夜鳥爭宿。", "我行亦已殆，況此弛擔僕。", "倒床不復呼，爛熳聽自足。", "人生浪游世，世網未易觸。", "好學還山雲，終焉宿幽獨。"]'),
('790db939-7a31-48a4-b80e-44ea2fefa4d7','客說嵩頂松實甚佳','呂本中','宋','宋诗','song-poetry','','[]','飄颻山中女，綠毛以爲衣。',108,'全唐诗/poet.song.93000.json','["飄颻山中女，綠毛以爲衣。", "但食青松子，不死亦不饑。", "晝想此仙人，夜或夢見之。", "客云嵩高頂，長松亂紛披。", "拔地起霜幹，盤空缺虬枝。", "惜無長臂人，挽此鬚與鬐。", "但聞雲間子，時被天風吹。", "愧我一食身，何由揖仙姿。", "欲學餐松法，人間了無師。"]'),
('ca9ddda4-b206-47be-958b-769cd620b95f','送蘇龍圖知明州  其一','呂本中','宋','宋诗','song-poetry','','[]','知君鄉味憶吳餕，便逐輕鷗下急湍。',32,'全唐诗/poet.song.93000.json','["知君鄉味憶吳餕，便逐輕鷗下急湍。", "更使煙雲有佳思，莫驅鼓吹傍湖山。"]'),
('152c313e-d0d0-4733-be6f-db54298f6a13','送蘇龍圖知明州  其二','呂本中','宋','宋诗','song-poetry','','[]','宇宙之間得幾人，平生季子最相親。',32,'全唐诗/poet.song.93000.json','["宇宙之間得幾人，平生季子最相親。", "一麾出守三千里，去覓風流賀季真。"]'),
('f949df7a-f42f-49b0-8af2-64d9914d32cc','塵外亭','呂本中','宋','宋诗','song-poetry','','[]','寧飲山中泉，勿食城中米。',108,'全唐诗/poet.song.93000.json','["寧飲山中泉，勿食城中米。", "塵埃苦着人，何翅虱與蟻。", "爬搔十指禿，敗褐未易洗。", "緬懷佳公子，珠璧不受浼。", "藏身着幽處，闔戶謝紈綺。", "君看羅曲旃，何似容燕几。", "不辜文字眼，未負鍾鼎耳。", "長安游俠窟，未晚看參觜。", "紛紛萬馬蹄，門外自千里。"]'),
('ac26318b-56cc-4255-b53b-4a4c1e6abf9b','題晁以道新居','呂本中','宋','宋诗','song-poetry','','[]','小阮東來語太誇，爲傳新構甲千家。',64,'全唐诗/poet.song.93000.json','["小阮東來語太誇，爲傳新構甲千家。", "氣衝雪野群山過，光轉雲空一水斜。", "聞道洗心求凈觀，不妨合掌讀楞枷。", "箇中富貴還君子，莫愛群奴日兩衙。"]'),
('deb9d1e8-09da-4819-ba2c-20963870732c','星月枕屏歌','呂本中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雪涵疏星月既望，老檜長松倚千丈。',96,'全唐诗/poet.song.93000.json','["雪涵疏星月既望，老檜長松倚千丈。", "田夫漁父不愛惜，落向公家枕屏上。", "枕屏映研連春冰，主人中夜卷寒藤。", "詩成不寫坐嘆息，長松老檜無顔色。", "海陵掾曹來作歌，卻憶洞庭秋水多。", "洞庭水多秋亦晚，如此枕屏星月何。"]'),
('e24fbc2e-e9e2-4399-9d98-a2755bb22c56','即事','呂本中','宋','宋诗','song-poetry','','[]','夭夭桃李花，春到已成蹊。',72,'全唐诗/poet.song.93000.json','["夭夭桃李花，春到已成蹊。", "主人不好事，居然作藩籬。", "容華坐消歇，芳心端爲誰。", "風雨日衰謝，覆水難再期。", "物有幸不幸，難用一理推。", "不見浣溪女，嫁與隴頭兒。"]'),
('ca1c641a-d644-4b34-b585-4066ca577b4a','次韻堯明如皋道中五首  其一','呂本中','宋','宋诗','song-poetry','','[]','萬頃曾經一葦航，舊纓如可濯滄浪。',32,'全唐诗/poet.song.93000.json','["萬頃曾經一葦航，舊纓如可濯滄浪。", "簿書窘束塵埃裏，猶見當時玉樹郎。"]'),
('57a01597-7182-498f-85f2-423682578251','次韻堯明如皋道中五首  其二','呂本中','宋','宋诗','song-poetry','','[]','王李風華舊得名，頗容偏左去求盟。',32,'全唐诗/poet.song.93000.json','["王李風華舊得名，頗容偏左去求盟。", "從來量比江河大，不取人間盆盎清。"]'),
('35d6e879-2fa2-4b8a-8205-66db43c9bf48','次韻堯明如皋道中五首  其三','呂本中','宋','宋诗','song-poetry','','[]','不嫌衆裏衣冠古，自覺人前禮法疏。',32,'全唐诗/poet.song.93000.json','["不嫌衆裏衣冠古，自覺人前禮法疏。", "已似羲之棄官後，近逢安石赴京初。"]'),
('38fe3b8b-6427-4a69-a512-d91488c10269','次韻堯明如皋道中五首  其四','呂本中','宋','宋诗','song-poetry','','[]','醉別江南久未還，至今猶夢雨餘山。',32,'全唐诗/poet.song.93000.json','["醉別江南久未還，至今猶夢雨餘山。", "少留白髪三千丈，勝取黄金十二鐶。"]'),
('16e336f9-e951-4b38-87f9-bd69d86bf17e','次韻堯明如皋道中五首  其五','呂本中','宋','宋诗','song-poetry','','[]','侯喜學詩新有聲，坐中忽遇老彌明。',32,'全唐诗/poet.song.93000.json','["侯喜學詩新有聲，坐中忽遇老彌明。", "故知麥飯與藜藿，不識虞卿醒酒鯖。"]'),
('ef7d4285-3844-4b01-828c-268fc46f6c06','別才仲','呂本中','宋','宋诗','song-poetry','','[]','憶子丱角時，單衣小襦褂。',144,'全唐诗/poet.song.93000.json','["憶子丱角時，單衣小襦褂。", "見我不能拜，笑語多自誤。", "初看讀孝經，旋即絕文字。", "先姑謂我言，爾曹頗相似。", "悠悠二十年，歷歷眼中事。", "江河坐乖隔，清□謾佳句。", "堂堂曾定州，許爾天下士。", "自爾憂患多，頗復慰漂寓。", "故人薄□腸，子猶披情素。", "胸次磈礧盡，皆是濟世具。", "從來人中英，俗子眼中刺。", "子行多邅迴，無與此曹遇。"]'),
('55d84946-bc00-45ef-baf5-4e9c1e20e34d','臞庵','呂本中','宋','宋诗','song-poetry','','[]','伊洛富山水，家有五畝園。',156,'全唐诗/poet.song.93000.json','["伊洛富山水，家有五畝園。", "花竹遶瀍澗，不讓桃花源。", "清時足真賞，戶門開層軒。", "一朝胡塵暗，故家希復存。", "莽蒼走萬里，始及吳市門。", "庵廬據形勝，冰壺貯乾坤。", "亭榭着仍穩，不見斧鑿痕。", "主人更超邁，雲夢八九吞。", "植杖邀我坐，笑語清而溫。", "坐令車馬客，稍識山林尊。", "十年老朝市，漸見兩目昏。", "求田與問舍，姑置不復論。", "但願從我公，不使世諦諢。"]'),
('9551e059-9762-4dc3-84cb-75c0a8fc89cf','夜雨','呂本中','宋','宋诗','song-poetry','','[]','吟魂不飲覺惺惺，那更宵眠得雨晴。',64,'全唐诗/poet.song.93000.json','["吟魂不飲覺惺惺，那更宵眠得雨晴。", "遍地亂沾霜葉碎，隨風斜上紙窗明。", "暗欣石罅添泉脈，幾回簷牙認雪聲。", "明日梅邊曾有約，西郊泥濘未堪行。"]'),
('8e676226-1361-4c9d-b0bd-aadf42af6020','暮雨','呂本中','宋','宋诗','song-poetry','','[]','暮燕翻雷天作雲，一聲歸鳥萬村昏。',32,'全唐诗/poet.song.93000.json','["暮燕翻雷天作雲，一聲歸鳥萬村昏。", "荒城寂寞無堪宿，月下搘頤雨打門。"]'),
('1c9cba7a-cf36-4b1c-8d88-3f5645d9079e','寄傲軒','呂本中','宋','宋诗','song-poetry','','[]','自嗟踽踽復涼涼，餬口安能抑四方。',64,'全唐诗/poet.song.93000.json','["自嗟踽踽復涼涼，餬口安能抑四方。", "目送歸鴻心自遠，門堪羅雀日偏長。", "家徒四壁樽仍綠，侯戶千頭橘又黄。", "我醉欲眠君且去，肯陪俗客話羲皇。"]'),
('0b28d371-cbb3-4a75-845d-a523a4934e41','谷隱堂','呂本中','宋','宋诗','song-poetry','','[]','汝州城南二十里，栖畝山前足山水。',208,'全唐诗/poet.song.93000.json','["汝州城南二十里，栖畝山前足山水。", "老人中開谷隱堂，草屋疏簷對山起。", "南橫秀嶺石官道，想像此堂容此老。", "堂前茂林浮春煙，堂後池溏多白蓮。", "前池紅蓮開更早，正與茂林相對好。", "開軒看蓮看不足，遠望少室如碧玉。", "碧玉如屏掩此堂，老人與世已相忘。", "胡馬揚塵不容駐，萬里奔波失歸路。", "客舟不顧生事窘，所至有堂名谷隱。", "大榜灰飛小榜存，至今長在對衡門。", "澗上丈人肯已冷，中原舊事空銷魂。", "老人本是山中客，四海爲家無住宅。", "家人清坐已忘貧，何曾更問堂寬窄。"]'),
('c7db240b-9a81-481a-8598-e55cfdc55c02','丹桂軒','呂本中','宋','宋诗','song-poetry','','[]','丹枝近歲出深宮，合向嚴辰伴晚楓。',32,'全唐诗/poet.song.93000.json','["丹枝近歲出深宮，合向嚴辰伴晚楓。", "珍重幽軒無俗物，月中根墢日邊紅。"]'),
('a6411c04-75b0-4429-9dcf-3ba70ce64af6','松','呂本中','宋','宋诗','song-poetry','','[]','一依風霜萬木枯，歲寒惟見老松孤。',32,'全唐诗/poet.song.93000.json','["一依風霜萬木枯，歲寒惟見老松孤。", "秦皇不識清高操，強欲煩君作大夫。"]'),
('8121d752-9426-4fbe-8659-4fa08309de6f','秋窗遣興  其一','呂本中','宋','宋诗','song-poetry','','[]','造物何繁敷，雜然呈萬變。',60,'全唐诗/poet.song.93000.json','["造物何繁敷，雜然呈萬變。", "潛飛愜會心，顯藏亦遞見。", "人生事機巧，雕鑿失性善。", "碌碌塵寰事，輪環走精電。", "蕭散眄庭柯，商意集微霰。"]'),
('40b5633d-fd52-418e-bc40-5a5776ad9bf9','秋窗遣興  其二','呂本中','宋','宋诗','song-poetry','','[]','晴枝颭小鳥，啁啾振毛羽。',60,'全唐诗/poet.song.93000.json','["晴枝颭小鳥，啁啾振毛羽。", "涼飈墮寒花，靜中有真趣。", "倚檻看浮雲，隨時成散聚。", "世變無常境，心定自安遇。", "棐几雜圖書，幽事能畢具。"]'),
('d95eddad-6a02-44a8-aabe-d74fab202135','秋窗遣興  其三','呂本中','宋','宋诗','song-poetry','','[]','朝擁群書坐，所樂常自足。',60,'全唐诗/poet.song.93000.json','["朝擁群書坐，所樂常自足。", "聖賢重出處，理本無偏曲。", "志行道合尊，安貧未爲辱。", "壓架富卷帙，縱情無蹐跼。", "窮達各有時，此意當勉勗。"]'),
('34b16fa7-6011-4556-a954-d25022fd1235','秋窗遣興  其四','呂本中','宋','宋诗','song-poetry','','[]','東園有喬木，翳翳凌霄漢。',60,'全唐诗/poet.song.93000.json','["東園有喬木，翳翳凌霄漢。", "歲月變虬枝，雨露潫霜幹。", "濃陰書屋□，伴我同昏旦。", "根株視百草，秋風已萎爛。", "良材際時用，未忍付樵爨。"]'),
('64b98664-a56f-4b14-b96f-30b7caa4e11d','秋窗遣興  其五','呂本中','宋','宋诗','song-poetry','','[]','抱璞淪巖阿，失懷亦自寶。',60,'全唐诗/poet.song.93000.json','["抱璞淪巖阿，失懷亦自寶。", "豈無用世心，遇合貴得道。", "連城重白珩，聲價先傾倒。", "瑕瑜混沙礫，莫訝荆山老。", "會當游勳華，元圭贊熙皡。"]'),
('4daeceda-bcac-412b-ac75-5b75862c0962','秋窗遣興  其六','呂本中','宋','宋诗','song-poetry','','[]','日奭久不作，依然三代民。',60,'全唐诗/poet.song.93000.json','["日奭久不作，依然三代民。", "一善孚萬端，不難風俗淳。", "上士貴抱負，修己在立身。", "進退各有據，宇宙任屈伸。", "願言勵厥修，學以答君親。"]'),
('18113d38-09a7-4657-bc17-b34e7e2358bd','秋窗遣興  其七','呂本中','宋','宋诗','song-poetry','','[]','門外一渠水，清光自泠泠。',60,'全唐诗/poet.song.93000.json','["門外一渠水，清光自泠泠。", "濯纓偕素侶，鬚髪無遯形。", "春風起層波，鵾化失南溟。", "縠紋亂星斗，泥沙混窅冥。", "澄清當有志，天地還虛靈。"]'),
('a3fb710b-8ce7-4d57-a18b-7c71315646f6','秋窗遣興  其八','呂本中','宋','宋诗','song-poetry','','[]','智者尚明察，不爲物理宥。',60,'全唐诗/poet.song.93000.json','["智者尚明察，不爲物理宥。", "吾儒任學術，精力事研究。", "至人邈難繼，得亦瞠乎後。", "庸盲終溟漠，全天亦自厚。", "大化無殊途，何事樸與秀。"]'),
('6ce10c09-bf59-4b55-9b5a-1be704ad76f4','秋窗遣興  其九','呂本中','宋','宋诗','song-poetry','','[]','寒氣生戶牖，草木變輕黄。',60,'全唐诗/poet.song.93000.json','["寒氣生戶牖，草木變輕黄。", "南郊詢秋畦，豐稔薦滌場。", "八口娛妻孥，溫飽樂歲康。", "簞瓢亦自得，憂樂各兩忘。", "所以常忻忻，安問無儲糧。"]'),
('a4da427d-ccc6-43da-9161-129ea5a2887e','秋窗遣興  其一○','呂本中','宋','宋诗','song-poetry','','[]','我生事柔翰，中懷異好尚。',60,'全唐诗/poet.song.93000.json','["我生事柔翰，中懷異好尚。", "瀟灑逼嵇阮，功成薄瑜亮。", "白衣本山人，置身豈疏放。", "途逢醉尉呵，未且對侯相。", "亭亭千仞松，當破萬里浪。"]'),
('eb0b4cf8-b93f-4303-8506-83d121e0d5c3','次韻錢遜叔泛舟虹橋','呂本中','宋','宋诗','song-poetry','','[]','半篙春漲綠平溪，二月江城草色齊。',64,'全唐诗/poet.song.93000.json','["半篙春漲綠平溪，二月江城草色齊。", "舟比蜉蝣千頃外，□同斥鷃一枝栖。", "野橋柳線斜風軟，曲檻花光夕照低。", "卻訝探驪人不至，清樽畫航倩分題。"]'),
('4b23744e-c5c5-4c10-8e58-8d59529c7e72','春暮渡江  其一','呂本中','宋','宋诗','song-poetry','','[]','霽色春江上，滄茫一棹通。',48,'全唐诗/poet.song.93000.json','["霽色春江上，滄茫一棹通。", "水隨天地闊，山入畫圖工。", "薄靄凝新碧，輕風隨亂紅。", "片帆迎返照，疊嶂路疑窮。"]'),
('713af0e6-34a2-49e2-9df8-0e2dc1f80701','春暮渡江  其二','呂本中','宋','宋诗','song-poetry','','[]','間移書畫舫，一葉足浮家。',48,'全唐诗/poet.song.93000.json','["間移書畫舫，一葉足浮家。", "潮漲添春雨，山明放野花。", "遶煙依樹斷，飛鳥受風斜。", "翻訝江潭客，塵容改歲華。"]'),
('7b9c8a82-4381-4937-b31f-f7ffad6bd2b3','荷珠','呂本中','宋','宋诗','song-poetry','','[]','誰倩亭亭着意擎，風中零亂月中明。',64,'全唐诗/poet.song.93000.json','["誰倩亭亭着意擎，風中零亂月中明。", "渾無定處光偏潤，正值圓時影最清。", "曲檻落江欹一串，橫塘點碧夢三更。", "絕憐蕩漾波心裏，添得連宵細雨聲。"]'),
('5e2bab1d-6fe5-44c8-bc52-bf5efe411c21','偶題','呂本中','宋','宋诗','song-poetry','','[]','槿籬臨古澗，蒼然來書幄。',72,'全唐诗/poet.song.93000.json','["槿籬臨古澗，蒼然來書幄。", "垂釣澗魚清，銜盃山醪濁。", "三逕草既深，一庭鳥剝啄。", "繩牀竹翠陰，石几苔蘚駁。", "遊方莊老書，抱琴陶家樂。", "山水洗塵囂，百年好一覺。"]'),
('cffda9ab-b184-4bd5-93ef-770130c0a00c','田家漫興  其一','呂本中','宋','宋诗','song-poetry','','[]','巷陌交道近，茅簷接復疏。',60,'全唐诗/poet.song.93000.json','["巷陌交道近，茅簷接復疏。", "岸榆容繫艇，籬竹許封蔬。", "地僻常遠市，簷卑牧雞豕。", "遶村楊柳花，沿溪蘆荻水。", "野老隨分過，商榷桑與梓。"]'),
('ddacd06e-ccad-4866-8f82-333fef2cce32','田家漫興  其二','呂本中','宋','宋诗','song-poetry','','[]','參星瞻穀日，水影量元夕。',60,'全唐诗/poet.song.93000.json','["參星瞻穀日，水影量元夕。", "旱潦種早晚，老農從定策。", "催耕鳴鳩起，護竿烏鵲去。", "秋成不饜懷，暑雨不告勞。", "歲時社酒會，扶醉有年高。"]'),
('4781c90e-1931-4191-a4e6-724848aab8cc','游白省寺看畫壁','呂本中','宋','宋诗','song-poetry','','[]','古徑接長松，曠觀碧殿逢。',48,'全唐诗/poet.song.93000.json','["古徑接長松，曠觀碧殿逢。", "巉巖山巘立，浩渺海濤衝。", "盡啗寰中勝，尤瞻天外峰。", "世塵何日埽，五嶽遍扶笻。"]'),
('9c0ef9ff-43c4-4098-8217-2c44add57b2c','秋游埭山游新庵中路卻過頭陀雪野','呂本中','宋','宋诗','song-poetry','','[]','秋雲歷亂日光微，山色蕭疏木葉飛。',64,'全唐诗/poet.song.93000.json','["秋雲歷亂日光微，山色蕭疏木葉飛。", "旅夢空遺鶴唳恨，羈情思聽牧吟歸。", "荒涼舊院深溪遠，解后江湖逸士稀。", "卻作頭陀談越事，不堪楚客淚沾衣。"]'),
('8c1fc854-ee41-4b9a-a38e-6565b8985ab1','紀棲賢山讀書','呂本中','宋','宋诗','song-poetry','','[]','遲日欣欣山景妍，攜琴吟咏翠微前。',64,'全唐诗/poet.song.93000.json','["遲日欣欣山景妍，攜琴吟咏翠微前。", "行廚燒筍粉鋪色，高閣看梅雪白天。", "午罷拋書曳短杖，雨來擁卷聽幽泉。", "一春灑落韶光足，他日芳懷得復然。"]'),
('bfe6574a-9bb9-46cb-8031-6b0451c4b43b','秋興  其一','呂本中','宋','宋诗','song-poetry','','[]','平疇一望黍禾稀，遠樹峰巒天外微。',64,'全唐诗/poet.song.93000.json','["平疇一望黍禾稀，遠樹峰巒天外微。", "水國蝦留當鱠鮓，鄉園桑盡典秋衣。", "連翩羽檄荒林下，繹絡徵書塞上飛。", "可是三分纔溢額，那知鴻雁野號歸。"]'),
('e16c9419-e772-4b60-98ea-45a9cf4361ec','秋興  其二','呂本中','宋','宋诗','song-poetry','','[]','西郊一夕葉初稀，原野荒涼草具腓。',64,'全唐诗/poet.song.93000.json','["西郊一夕葉初稀，原野荒涼草具腓。", "荷鍤耕夫閑箬笠，從戎火伴急軍機。", "閨中淚雨征衫剪，塞外驚風夜柝依。", "莫是羽毛零落盡，不堪燕燕頡頏飛。"]'),
('cf53e60f-a321-4428-b872-968dfc4c77ce','秋興  其三','呂本中','宋','宋诗','song-poetry','','[]','浸滿溪煙楓葉紛，嶔崎蒼弁入青雲。',64,'全唐诗/poet.song.93000.json','["浸滿溪煙楓葉紛，嶔崎蒼弁入青雲。", "捲堂宋室由來事，逐客秦都曾有文。", "兔苑圃田間可耨，豹林筆研笑須焚。", "莫嘲寂寞秋風士，于越當年君子軍。"]'),
('8caaeeac-d7f2-4d0b-b369-bf110592d050','秋興  其四','呂本中','宋','宋诗','song-poetry','','[]','清秋風景晝平分，江外波濤驚夕曛。',64,'全唐诗/poet.song.93000.json','["清秋風景晝平分，江外波濤驚夕曛。", "誰誤唐家門架史，卻來蓬戶市租文。", "樹禽惋惜一枝借，野兔何心三窟聞。", "只恐東南馬力盡，祇應契伴駐寒雲。"]'),
('121e31e2-0267-4e22-a3aa-c534a48e9f95','秋日康山東歸','呂本中','宋','宋诗','song-poetry','','[]','整檝凌晨問所之，鄉園迢遞水東遲。',64,'全唐诗/poet.song.93000.json','["整檝凌晨問所之，鄉園迢遞水東遲。", "歸舟但信溪紅蓼，別夢還牽山翠眉。", "安穩秋風三徑竹，躊躇行李一囊詩。", "解維猶有留題處，瓜葛縈懷不自持。"]'),
('47ae5932-74d6-41c2-9c1b-f915060d0436','中秋  其一','呂本中','宋','宋诗','song-poetry','','[]','雨雲初霽放晴空，乍捲珠簾望月宮。',32,'全唐诗/poet.song.93000.json','["雨雲初霽放晴空，乍捲珠簾望月宮。", "夜靜□篁何處發，玉樓猶記月明中。"]'),
('530e54c8-2f57-4cb2-b93f-8dc156ea0d38','中秋  其二','呂本中','宋','宋诗','song-poetry','','[]','泱泱秋水荻蘆輕，徙倚樓頭待月明。',32,'全唐诗/poet.song.93000.json','["泱泱秋水荻蘆輕，徙倚樓頭待月明。", "紅燭燒殘白墮醒，秋風颯颯獨關情。"]'),
('12313cd5-af8c-4704-a336-6c386764c3df','海上篇','呂本中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天風萬里起，海水高十尋。',156,'全唐诗/poet.song.93000.json','["天風萬里起，海水高十尋。", "中有都人士，拔劍拯陸沉。", "素甲三十里，朱縢萬千壘。", "誓身殉家國，援抱常切齒。", "東連海上兵，天挺三世英。", "艨艟山岳高，軍儲滄海傾。", "縱橫長江動，軍威千里空。", "拊手功可立，名姝何足惜。", "痛飲佇黄龍，酣醉實狼籍。", "一朝肘腋變，驚雷還自敵。", "鳥獸散何爲，島上復賣國。", "嘆息復嘆息，燕市文山即。", "海外多君子，至今長恨水。"]'),
('428ba952-2122-4f24-9b98-56cb717bed1e','閑居  其一','呂本中','宋','宋诗','song-poetry','','[]','濕雲一片傍門垂，秋草盈庭綠未辭。',32,'全唐诗/poet.song.93000.json','["濕雲一片傍門垂，秋草盈庭綠未辭。", "剝啄無聲詩思懶，竹牀方枕夢回遲。"]'),
('d405aaac-3e7b-4d6e-a01b-54a6e51fabe0','閑居  其二','呂本中','宋','宋诗','song-poetry','','[]','綿綿風雨雨鳩催，衰柳朦朧玉作堆。',32,'全唐诗/poet.song.93000.json','["綿綿風雨雨鳩催，衰柳朦朧玉作堆。", "不道陶公秫未熟，煙波一片欲飛來。"]'),
('4b8212fe-624d-400e-bed7-e33cfcade0c2','閑居  其三','呂本中','宋','宋诗','song-poetry','','[]','新添漲非碧天空，拄杖斜衣紅蓼中。',32,'全唐诗/poet.song.93000.json','["新添漲非碧天空，拄杖斜衣紅蓼中。", "角甕何須猶倔強，桔槹南陌正秋風。"]'),
('9328e295-da9b-4993-99f4-7f40407ff2eb','閑居  其四','呂本中','宋','宋诗','song-poetry','','[]','荆扉寂寞鎖花枝，欹枕閑追方外知。',32,'全唐诗/poet.song.93000.json','["荆扉寂寞鎖花枝，欹枕閑追方外知。", "一縷茶煙新水足，半簾宿雨燕飛遲。"]'),
('9f5d8921-585e-48a4-892c-9f53803fe3d5','閑居  其五','呂本中','宋','宋诗','song-poetry','','[]','陰晴未定兩相催，夜半蛩聲送晚雷。',32,'全唐诗/poet.song.93000.json','["陰晴未定兩相催，夜半蛩聲送晚雷。", "可憐野人無底事，階前新看繡莓苔。"]'),
('fcc305a8-ed1d-4fed-ae86-29c691d9f0bf','閑居  其六','呂本中','宋','宋诗','song-poetry','','[]','秋原儘好放遊笻，何事山齋任懶慵。',32,'全唐诗/poet.song.93000.json','["秋原儘好放遊笻，何事山齋任懶慵。", "屋漏有痕留作字，梧桐带雨聽笙鏞。"]'),
('d258d908-37c9-412a-b90b-1a926d40394f','閑居  其七','呂本中','宋','宋诗','song-poetry','','[]','西風岑寂子雲居，未放秋陽曬腹書。',32,'全唐诗/poet.song.93000.json','["西風岑寂子雲居，未放秋陽曬腹書。", "卻笑問字誰載酒，雨煙仍是老樵漁。"]'),
('7de3c895-b997-4166-82b1-e3719d30b768','喜晴','呂本中','宋','宋诗','song-poetry','','[]','經旬陰雨水滄浪，煙鎖巖扉遊騎荒。',64,'全唐诗/poet.song.93000.json','["經旬陰雨水滄浪，煙鎖巖扉遊騎荒。", "赤日纔來異宿昔，青山看去倍尋常。", "秋林腰斧歌共醉，春市擔魚粟滿囊。", "野老新新興未艾，風雲役使不勝狂。"]'),
('c3a9fc3f-6146-4198-93e9-54fff39ebcc1','咏郭西魚池','呂本中','宋','宋诗','song-poetry','','[]','煙艇江湖網罟疏，石磯風雨釣綸虛。',64,'全唐诗/poet.song.93000.json','["煙艇江湖網罟疏，石磯風雨釣綸虛。", "碧池漫鑿方通徑，鱗沼聊巡供別儲。", "詩客興來堪佐酒，野人夢去卻多魚。", "鴟夷聞道曾興越，經濟還餘千倍漁。"]'),
('65f45d85-b856-4e79-85e8-36f1f281171d','採菱詞','呂本中','宋','宋诗','song-poetry','','[]','浩瀚湖光淹北皋，柳彎翠滿敢辭勞。',65,'全唐诗/poet.song.93000.json','["浩瀚湖光淹北皋，柳彎翠滿敢辭勞。", "青菰出水猶佳蔌，上級芰循溪作沚毛。", "楚水嗜奇聞辨論，輞川燈火正風騷。", "何當採掇秋光裏，遊嬉吳姬蕩小舠。"]'),
('76cf5b7b-6434-4180-aaa8-162366107357','古意','呂本中','宋','宋诗','song-poetry','','[]','茂陵消渴遠山眉，那得閑情到綠絲。',32,'全唐诗/poet.song.93000.json','["茂陵消渴遠山眉，那得閑情到綠絲。", "一曲白頭吟未了，迴文字字起新詩。"]'),
('819cc33d-034a-4b01-bc83-92d90f8dc8bc','寒梅','呂本中','宋','宋诗','song-poetry','','[]','一樹寒梅曲檻東，含葩未吐蕊頭紅。',32,'全唐诗/poet.song.93000.json','["一樹寒梅曲檻東，含葩未吐蕊頭紅。", "霜枝不許遊人看，驀地吹來栗烈風。"]'),
('2ae6b401-280e-46fa-af84-25fd18bcc652','渡鶯湖至溪上即事  其一','呂本中','宋','宋诗','song-poetry','','[]','宿霧重陰傍晚桴，日斜風定渡鶯湖。',64,'全唐诗/poet.song.93000.json','["宿霧重陰傍晚桴，日斜風定渡鶯湖。", "陂塘浩淼水光闊，煙寺中流島嶼孤。", "滿眼波濤迷客泛，一行雁影带雲徂。", "到來荒舍未岑寂，寒樹依依鬧晚烏。"]'),
('442f4d91-b26d-42bd-9761-d82cfd4fadbf','渡鶯湖至溪上即事  其二','呂本中','宋','宋诗','song-poetry','','[]','絡繹蕭蕭遍里門，支機嘉事自天孫。',64,'全唐诗/poet.song.93000.json','["絡繹蕭蕭遍里門，支機嘉事自天孫。", "七襄曉織憐花譜，百室春梭饜夕餐。", "誰檢吳綾儉歲月，猶飛楚縠照軍屯。", "摻摻女手還持作，佳麗江南第一論。"]'),
('d12f9ca2-702b-4113-8952-cf9e4a47f123','渡鶯湖至溪上即事  其三','呂本中','宋','宋诗','song-poetry','','[]','湖水安瀾似鏡明，昔年曾向鏡中行。',64,'全唐诗/poet.song.93000.json','["湖水安瀾似鏡明，昔年曾向鏡中行。", "侵晨浥露來花市，落日流風倚醉楹。", "俯仰繁華餘暮色，蕭條高寄但秋聲。", "應知節序猶遷轉，撫劍如何教未平。"]'),
('fb54cca2-70a1-42b4-8800-661896d4bfbd','寄遠曲','呂本中','宋','宋诗','song-poetry','','[]','相送江邊遠客船，孤帆一道寸心懸。',32,'全唐诗/poet.song.93000.json','["相送江邊遠客船，孤帆一道寸心懸。", "日南珠價知多少，不及閨中珠淚圓。"]'),
('eb560709-8afd-4f12-95b8-ccb850cd6e29','覲竺閨女','呂本中','宋','宋诗','song-poetry','','[]','澹妝素抹舊羅衣，雅致天姿覲竺歸。',32,'全唐诗/poet.song.93000.json','["澹妝素抹舊羅衣，雅致天姿覲竺歸。", "始信若耶溪畔女，何須珠翠館娃妃。"]'),
('659ff8fa-b345-45d3-9163-bcdfe579ea2b','夏夜宿乳竇峰','呂本中','宋','宋诗','song-poetry','','[]','峭壁凌空靄氣浮，山泉滴茗暗香流。',32,'全唐诗/poet.song.93000.json','["峭壁凌空靄氣浮，山泉滴茗暗香流。", "炎雲不到冰心靜，好向峰前一簟秋。"]'),
('9e56d4aa-a49e-4901-88a8-0b8a82dcbd54','游石筍庵','呂本中','宋','宋诗','song-poetry','','[]','石筍殊峰精舍幽，瘦笻踏向碧雲游。',32,'全唐诗/poet.song.93000.json','["石筍殊峰精舍幽，瘦笻踏向碧雲游。", "天然青茁層崖裏，玉版參來點石頭。"]'),
('fccd1c4f-c0e8-4854-9421-e24a163417d1','望遠','呂本中','宋','宋诗','song-poetry','','[]','上林燕不飛，朔雲無消息。',60,'全唐诗/poet.song.93000.json','["上林燕不飛，朔雲無消息。", "天山應雲霏，吳苑草碧色。", "斷腸人不知，耿耿多思憶。", "當年惜繁華，綠琴悔不理。", "於今霜露歸，徘徊明月裏。"]'),
('fe5aa7a1-e246-495b-9493-52d046645a2d','月夜閑步聞笛','呂本中','宋','宋诗','song-poetry','','[]','挑燈讀易後，乘月到溪前。',48,'全唐诗/poet.song.93000.json','["挑燈讀易後，乘月到溪前。", "野犬聲如豹，秋蟲吟似禪。", "光寒人意靜，影澹物情妍。", "更聞村笛遠，幽意曲中傳。"]'),
('745425f9-c452-4d14-80b3-6de8cca48e94','長嘯夜泊','呂本中','宋','宋诗','song-poetry','','[]','春煙失晚樹，柔櫓翠峰湄。',48,'全唐诗/poet.song.93000.json','["春煙失晚樹，柔櫓翠峰湄。", "野徑尋山暗，艤舟問路岐。", "敲詩吟人甕，點字墨池前。", "把酒懷前哲，蕭條一夕思。"]'),
('aac89999-32f8-4a5a-a2d5-0f1fa14f92c7','金絲桃','呂本中','宋','宋诗','song-poetry','','[]','菲菲紅紫送春去，獨自黄葩夏日閑。',32,'全唐诗/poet.song.93000.json','["菲菲紅紫送春去，獨自黄葩夏日閑。", "那得文仙歸故園，黄冠相向到邱山。"]'),
('691d8821-1161-42d2-92e5-36cc7f9c7be4','昭君怨','呂本中','宋','宋诗','song-poetry','','[]','延壽無金翠鈿銷，銅丸擿鼓晚來朝。',32,'全唐诗/poet.song.93000.json','["延壽無金翠鈿銷，銅丸擿鼓晚來朝。", "寧爲龍塞青青草，不作昭陽細細腰。"]'),
('82cb61a9-48ed-4a39-b77f-576cb2099e40','采蓮曲','呂本中','宋','宋诗','song-poetry','','[]','芳時並採曾蓮舟，一段相思水緩流。',32,'全唐诗/poet.song.93000.json','["芳時並採曾蓮舟，一段相思水緩流。", "憎殺回風無意緒，解儂錦纜轉船頭。"]'),
('8d925f1b-3806-46a4-8d82-5dd286896f79','山園即事','呂本中','宋','宋诗','song-poetry','','[]','翠峰窩裏掛青黄，水市逡巡到野航。',64,'全唐诗/poet.song.93000.json','["翠峰窩裏掛青黄，水市逡巡到野航。", "带雨鋤耘碧萼淺，臨風採摘綠枝長。", "分甘送客憐秋實，辟穀仙家嗜果香。", "聞道龍陽千匹絹，何如山圃四時芳。"]'),
('e36e56e8-21d7-4242-b39f-7fadd1dd5d09','秋夜雨分中韻','呂本中','宋','宋诗','song-poetry','','[]','風凄漏永暗銀河，滴響空階碎玉壺。',64,'全唐诗/poet.song.93000.json','["風凄漏永暗銀河，滴響空階碎玉壺。", "無那騷心思紛墜，且教高咏和寒梧。", "閑心欲寄雲中鶴，逸興旋懷江上鱸。", "莫使扶搖不可即，他年惆悵舊時粗。"]'),
('2ca71a98-0f6c-415e-bd89-4c129c7ea4dd','華林書堂漫興','呂本中','宋','宋诗','song-poetry','','[]','兩樹疏梅草閣前，一池晴日畫橋穿。',64,'全唐诗/poet.song.93000.json','["兩樹疏梅草閣前，一池晴日畫橋穿。", "論文欲飲先民筆，讀史常期循吏賢。", "攜酒閑望野陌間，吟柳外來采桑篇。", "應憐百里平蕪寂，漫使寒山片石傳。"]'),
('44654ec3-850c-44b3-9759-7b36c03f0edc','晨興','呂本中','宋','宋诗','song-poetry','','[]','書闈靜若隱，鐘到攬衣遲。',48,'全唐诗/poet.song.93000.json','["書闈靜若隱，鐘到攬衣遲。", "花睡猶含露，鶯歌方踏枝。", "耘苔開曲徑，考古韻新詩。", "誰識晨興意，西山爽氣時。"]'),
('955687f3-74f8-4b59-83f9-bbd65683709e','戲咏庭前萱草','呂本中','宋','宋诗','song-poetry','','[]','傳說亡憂樹後屏，誰教卻種在前亭。',64,'全唐诗/poet.song.93000.json','["傳說亡憂樹後屏，誰教卻種在前亭。", "想因白髪愁千斛，故遣芳階綠一庭。", "青柎幾時將碧草，丹心有日恐飄萍。", "更憐共道慈親號，遶砌還須雨露榮。"]'),
('be6eb124-c306-453e-bbe2-f1526018934d','立冬日贈張直夫','呂本中','宋','宋诗','song-poetry','','[]','參差寒葉樹，林鳥獨依棲。',48,'全唐诗/poet.song.93000.json','["參差寒葉樹，林鳥獨依棲。", "髪變心同素，年遲日向西。", "一水通晨夕，三山隔海溪。", "尚憶魯儒席，南樓攜手齊。"]'),
('b125b94a-0dc5-4c78-8090-12a92bbf58f9','清明游震澤即事','呂本中','宋','宋诗','song-poetry','','[]','挈伴提壺桃柳芳，東風暫醉少年場。',64,'全唐诗/poet.song.93000.json','["挈伴提壺桃柳芳，東風暫醉少年場。", "波浮十里飛舸疾，衣影千重夾道光。", "使氣可如燕趙士，輕兵原是楚吳卿。", "應知萬事同棋局，鼓角春江一日狂。"]'),
('e5a71e2e-f726-43e5-a119-e59d49f85081','句  其一','呂本中','宋','宋诗','song-poetry','','[]','昔者同升夫子堂，如今俱是鬢蒼浪。',16,'全唐诗/poet.song.93000.json','["昔者同升夫子堂，如今俱是鬢蒼浪。"]'),
('176f04e7-9db0-4248-abc3-3f8e2686e844','句  其二','呂本中','宋','宋诗','song-poetry','','[]','莫言衲子籃無底，盛得山南骨董歸。',16,'全唐诗/poet.song.93000.json','["莫言衲子籃無底，盛得山南骨董歸。"]'),
('4271947b-65f0-4bca-86da-5f78c562d1e9','句  其三','呂本中','宋','宋诗','song-poetry','','[]','山中露冷草木瘦，江上月寒蒲柳秋。',16,'全唐诗/poet.song.93000.json','["山中露冷草木瘦，江上月寒蒲柳秋。"]'),
('7544301a-aac0-4e62-849f-55475a7fcb67','句  其四','呂本中','宋','宋诗','song-poetry','','[]','十二峰前且繫船。',8,'全唐诗/poet.song.93000.json','["十二峰前且繫船。"]'),
('c9e93f1e-564a-41d7-ae6d-8aa8dd6cdbda','句  其五','呂本中','宋','宋诗','song-poetry','','[]','不用君王羯鼓敲。',8,'全唐诗/poet.song.93000.json','["不用君王羯鼓敲。"]'),
('fc059941-26a1-4431-adb9-ba057f5c49b2','句  其六','呂本中','宋','宋诗','song-poetry','','[]','老大多材，十年堅坐。',10,'全唐诗/poet.song.93000.json','["老大多材，十年堅坐。"]'),
('5e5d684c-13f8-4a4d-8075-aa0ca1de75c2','存目','呂本中','宋','宋诗','song-poetry','','[]','詩題：白公守蘇時劉夢得守杭（和）有歲暮贈劉詩三首因效其體寄齊州無咎二歌首句：過去生中作兄弟江南歲晚水風寒關河戰國東秦地。',60,'全唐诗/poet.song.93000.json','["詩題：白公守蘇時劉夢得守杭（和）有歲暮贈劉詩三首因效其體寄齊州無咎二歌首句：過去生中作兄弟江南歲晚水風寒關河戰國東秦地。"]'),
('aabf3c1d-5d26-415d-ba2f-4d577eaebef2','自題肖像','釋惟照','宋','宋诗','song-poetry','','[]','雨洗淡紅桃萼嫩，風搖淺碧柳絲輕。',32,'全唐诗/poet.song.93000.json','["雨洗淡紅桃萼嫩，風搖淺碧柳絲輕。", "白雲影裏怪石露，流水光中枯木春。"]'),
('29a034ca-00b9-4a38-ae01-68f2b3675c43','和陸元鈞頌四首  其一','釋惟照','宋','宋诗','song-poetry','','[]','芙蓉已入雙林寂，掛角羚羊無氣息。',32,'全唐诗/poet.song.93000.json','["芙蓉已入雙林寂，掛角羚羊無氣息。", "立關拔轉異中來，借問時人何處覓。"]'),
('c18bea97-958e-4a5a-866d-0af8e1f906b0','和陸元鈞頌四首  其二','釋惟照','宋','宋诗','song-poetry','','[]','山谷今傳佛祖衣，一回拈起一回疑。',32,'全唐诗/poet.song.93000.json','["山谷今傳佛祖衣，一回拈起一回疑。", "豐干饒舌可知也，引得寒山不肯歸。"]'),
('45c402e9-cbd0-464a-a476-f85ddcb0dfba','和陸元鈞頌四首  其三','釋惟照','宋','宋诗','song-poetry','','[]','千里客來何所遇，一念超然無去住。',32,'全唐诗/poet.song.93000.json','["千里客來何所遇，一念超然無去住。", "全身放下火中蓮，誰能更爲無生路。"]'),
('338ef470-2c4e-4102-945b-053765258450','和陸元鈞頌四首  其四','釋惟照','宋','宋诗','song-poetry','','[]','夜堂人靜雨霏霏，潤澤焦枯總不知。',32,'全唐诗/poet.song.93000.json','["夜堂人靜雨霏霏，潤澤焦枯總不知。", "堪笑當年淨名老，對文殊語恰如癡。"]'),
('a68ac7d2-4287-40df-9163-90b0cc82179b','頌古五首  其一','釋惟照','宋','宋诗','song-poetry','','[]','縮水酒越濃，負心人越窮。',40,'全唐诗/poet.song.93000.json','["縮水酒越濃，負心人越窮。", "鐵剛刀自利，不用苦磨礱。", "草鞋頭戴今何在，我見牽來劈面舂。"]'),
('5522cfbf-8790-480a-bfee-c6772312df18','頌古五首  其二','釋惟照','宋','宋诗','song-poetry','','[]','小樹子，傍山栽，華從葉裏開。',26,'全唐诗/poet.song.93000.json','["小樹子，傍山栽，華從葉裏開。", "枝高攀不得，和樹折將來。"]'),
('3060f532-e4df-4cf4-896c-978862cbb74b','頌古五首  其三','釋惟照','宋','宋诗','song-poetry','','[]','梨華一枝春带雨，金色頭陀笑不語。',52,'全唐诗/poet.song.93000.json','["梨華一枝春带雨，金色頭陀笑不語。", "龍宮海藏月明前，織女姮娥相對舞。", "笑者笑，舞者舞。", "十方無虛空，大地無寸土。"]'),
('abfdf459-1ff5-42a0-aee8-afd29815681d','頌古五首  其四','釋惟照','宋','宋诗','song-poetry','','[]','千尺絲輪0直下垂，一波才動萬波隨。',33,'全唐诗/poet.song.93000.json','["千尺絲輪0直下垂，一波才動萬波隨。", "江上晚來堪畫處，漁人披得一蓑歸。"]'),
('0a61888d-ea91-45a6-99b8-3017d527305b','頌古五首  其五','釋惟照','宋','宋诗','song-poetry','','[]','齋時一鉢飯，飯後一覺睡。',24,'全唐诗/poet.song.93000.json','["齋時一鉢飯，飯後一覺睡。", "睡起去放尿，洗手成變異。"]'),
('8dee6964-7326-4ea5-a767-8e21f2f095cf','自贊','釋惟照','宋','宋诗','song-poetry','','[]','自小來打硬，佛祖不奈何。',48,'全唐诗/poet.song.93000.json','["自小來打硬，佛祖不奈何。", "放藞苴住院，殃害殺禪和。", "道行闡提道，歌唱闡提歌。", "歡喜入地獄，誰管你閻羅。"]'),
('b49517fe-b495-4e18-bee3-89e48ca20479','和陸德先尚書歌','釋惟照','宋','宋诗','song-poetry','','[]','大道坦然兮殊不用功，殊不用功兮何必研窮。',80,'全唐诗/poet.song.93000.json','["大道坦然兮殊不用功，殊不用功兮何必研窮。", "豁虛離礙兮從空背空，不守自性兮雖同不同。", "百無所依兮自西自東，照體獨立兮滿目清風。", "廓落大度兮無不包容，全身異類兮觸處皆通。"]'),
('0cdc9265-334c-493d-90d1-7b75342cc245','勸徒銘','釋惟照','宋','宋诗','song-poetry','','[]','身心無拘，動寂無知。',160,'全唐诗/poet.song.93000.json','["身心無拘，動寂無知。", "如大死人，無倚無依。", "無拘者寬，無知者安。", "無內無外，無定無觀。", "無適無莫，無造無作。", "無去無來，無好無惡。", "一道清虛，萬法如如。", "愚極成智，智極成愚。", "超諸數量，孰云比況。", "淨盡不留，無法可尚。", "識不可識，智不可知。", "誰家之子，兀然巍巍。", "巍巍不存，根塵穎脫。", "如憨如癡，落落魄魄。", "不惜口業，爲了說破。", "笑殺闍梨，山僧罪過。"]'),
('adadb508-7002-43ee-8104-575486bee592','頌古六首  其一','釋惟照','宋','宋诗','song-poetry','','[]','拂拭瑤琴月下彈，調高雪曲和還難。',32,'全唐诗/poet.song.93000.json','["拂拭瑤琴月下彈，調高雪曲和還難。", "五侯費盡平生志，從此詩書懶更看。"]'),
('d4a98759-5050-44c6-beaf-605a1a5eb362','頌古六首  其二','釋惟照','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，鷓鴣啼在深花裏。',32,'全唐诗/poet.song.93000.json','["一口吸盡西江水，鷓鴣啼在深花裏。", "自有知音笑點頭，其來不入聾人耳。"]'),
('9b3b7ecd-0b9f-4edd-8145-1131dd36df7d','頌古六首  其三','釋惟照','宋','宋诗','song-poetry','','[]','甜瓜徹蒂甜，苦瓠連根苦。',24,'全唐诗/poet.song.93000.json','["甜瓜徹蒂甜，苦瓠連根苦。", "拈起枕子時，新羅夜打鼓。"]'),
('493680d9-b3f5-4b1f-84ff-223d98bc756c','頌古六首  其四','釋惟照','宋','宋诗','song-poetry','','[]','煙塵掃蕩將軍令，正勑流行宣德音。',32,'全唐诗/poet.song.93000.json','["煙塵掃蕩將軍令，正勑流行宣德音。", "公子只知歌既醉，夜深還被活生擒。"]'),
('d6106303-fd8f-4a2b-a1da-6f7f303d8829','頌古六首  其五','釋惟照','宋','宋诗','song-poetry','','[]','枯木堂中第一人，坐觀成敗枉精神。',32,'全唐诗/poet.song.93000.json','["枯木堂中第一人，坐觀成敗枉精神。", "可憐明一色邊事，直至而今沒眼筋。"]'),
('1fa6da7c-e185-46ee-a123-21d0ae248c7b','頌古六首  其六','釋惟照','宋','宋诗','song-poetry','','[]','黯黯雲攢覆雪峰，青青趙老一雙瞳。',32,'全唐诗/poet.song.93000.json','["黯黯雲攢覆雪峰，青青趙老一雙瞳。", "從前汗馬無人識，只要重論蓋代功。"]'),
('104aaac9-e9ab-4479-9b19-20976f2d7038','登齊雲樓','章憲','宋','宋诗','song-poetry','','[]','飛樓縹緲瞰吳邦，表裏江湖自一方。',64,'全唐诗/poet.song.93000.json','["飛樓縹緲瞰吳邦，表裏江湖自一方。", "曲檻高窗雲細薄，落霞孤鶩水蒼茫。", "固知興廢因時有，獨覺江山共古長。", "回首中原正愁思，不堪殘日半規黄。"]'),
('04116726-447e-48fb-a54a-2c8d1bc513b0','漫莊','章憲','宋','宋诗','song-poetry','','[]','何許明人眼，松間見古堂。',48,'全唐诗/poet.song.93000.json','["何許明人眼，松間見古堂。", "泉聲到棐几幾，山影覆繩牀。", "愛酒陶元亮，聽蛙孔德璋。", "紛戰蠻觸，丘壑信難忘。"]'),
('fb584837-fa1c-4ec8-8e27-a30da5b3d7cf','復軒歌','章憲','宋','宋诗','song-poetry','','[]','洞視兮八荒，了無物兮往無旁。',54,'全唐诗/poet.song.93000.json','["洞視兮八荒，了無物兮往無旁。", "往古來今兮無際，起復代謝兮不失吾常。", "復乎，復乎。", "吾所寓兮廣莫之野，而無何有之鄉。"]'),
('551ffd34-f3fb-45d5-84d8-a9890cf50b99','清曠堂','章憲','宋','宋诗','song-poetry','','[]','吾慕仲公理，卜居樂清曠。',72,'全唐诗/poet.song.93000.json','["吾慕仲公理，卜居樂清曠。", "茲焉愜吾願，名堂以自況。", "我無適俗韻，且乏肉食相。", "何許寄吾生，棲遲翳窮巷。", "境幽有經行，心遠無得喪。", "從容大化中，信是羲皇上。"]'),
('3bca5aff-557e-4f68-aea8-d72de873b7ac','永歸亭','章憲','宋','宋诗','song-poetry','','[]','吾慕曾夫子，舍瑟言所志。',72,'全唐诗/poet.song.93000.json','["吾慕曾夫子，舍瑟言所志。", "所志則非邦，獨契聖者意。", "暮春春服成，從我才一二。", "風乎林岫間，所樂有餘味。", "邈兮千載上，神交得冥契。", "當知結駟非，不易窮閻是。"]'),
('0c28bed5-df4b-42ab-85d6-fa55fc980575','清閟亭','章憲','宋','宋诗','song-poetry','','[]','吾慕韓昌黎，文章妙百世。',72,'全唐诗/poet.song.93000.json','["吾慕韓昌黎，文章妙百世。", "體物語尤工，賦竹誇清悶。", "唯我獨好之，則亦有深意。", "虛中可受道，貫時無險易。", "復苦魏文貞，直節而嫵媚。", "伊餘清閟中，賞玩有遺味。"]'),
('c579e0e1-7f69-46c5-8387-3589a17853bc','遐觀亭','章憲','宋','宋诗','song-poetry','','[]','吾慕陶靖節，處約而平寬。',72,'全唐诗/poet.song.93000.json','["吾慕陶靖節，處約而平寬。", "涉園自成趣，矯首復遐觀。", "我亦散遊目，俛仰天地間。", "雲煙自舒卷，湖嶺相迴環。", "永與形役謝，豈有俗慮干。", "想像斜川遊，千載乃相關。"]'),
('378da4a7-8fb6-4198-9abf-883a5101b895','松江謁王文孺令宰','章憲','宋','宋诗','song-poetry','','[]','暑退涼生過雨天，鳧飛鷺浴暮江前。',64,'全唐诗/poet.song.93000.json','["暑退涼生過雨天，鳧飛鷺浴暮江前。", "秋風小浪鴨頭水，斜日輕帆燕尾船。", "青眼卻欣逢地主，白頭相對聳詩肩。", "林塘勝處開樽俎，只欠冰輪特地圓。"]'),
('94382d74-c26a-4976-b721-09c5aa38083d','晚泊松江','章憲','宋','宋诗','song-poetry','','[]','長堤牽百丈，舴艋泝清漪。',48,'全唐诗/poet.song.93000.json','["長堤牽百丈，舴艋泝清漪。", "山與殘霞暝，水將秋色宜。", "江寒征雁度，天遠暮帆遲。", "賸欲浮家去，煙波學子皮。"]'),
('5f4e7bf5-04c4-495a-93e7-70133791af64','挽著作王先生蘋  其一','章憲','宋','宋诗','song-poetry','','[]','伊洛流風在，丘軻道德尊。',48,'全唐诗/poet.song.93000.json','["伊洛流風在，丘軻道德尊。", "遺經啟幽眇，後學有淵源。", "鑽仰知由戶，衰遲阻及門。", "三年思晬面，一旦絕微言。"]'),
('33d0a957-18aa-41e9-87bf-a095e1894c6d','挽著作王先生蘋  其二','章憲','宋','宋诗','song-poetry','','[]','行義時逢可，澤民事卻睽。',48,'全唐诗/poet.song.93000.json','["行義時逢可，澤民事卻睽。", "斯文猶有寄，俗學豈終迷。", "不復等三鱣，空聞見白雞。", "誅茅方檇李，卜葬已苕溪。"]'),
('2ac9f014-4402-493d-9d30-722ff0a61281','挽著作王先生蘋  其三','章憲','宋','宋诗','song-poetry','','[]','西觀才黔突，題輿卻佐州。',48,'全唐诗/poet.song.93000.json','["西觀才黔突，題輿卻佐州。", "濟時卑管晏，齎志在春秋。", "曖曖孤雲沒，沈沈厚夜幽。", "升堂聞禮樂，終覺愧程仇。"]'),
('e2381c93-08db-44bb-bcf7-fdf08bf5f8ed','句','趙相','宋','宋诗','song-poetry','','[]','夕陽綠澗明。',6,'全唐诗/poet.song.93000.json','["夕陽綠澗明。"]'),
('39c161ca-6060-41f7-acc2-10a156c82135','春晚','李怤','宋','宋诗','song-poetry','','[]','花瘦煙羸可奈何，不關渠事鳥聲和。',32,'全唐诗/poet.song.93000.json','["花瘦煙羸可奈何，不關渠事鳥聲和。", "無人掃地驚殘夢，分付輕紅上碧莎。"]'),
('11911cf9-7070-4d5c-a085-681b6ef46e49','句  其一','李怤','宋','宋诗','song-poetry','','[]','去國春城桃李花，楓林葉病尚天涯。',32,'全唐诗/poet.song.93000.json','["去國春城桃李花，楓林葉病尚天涯。", "今年九日風前帽，北客南舟雨後沙。"]'),
('6d8dbdc9-345a-41d9-ac63-2769745d9080','句  其二','李怤','宋','宋诗','song-poetry','','[]','蒼黄避地小兒女，漂泊連床老弟兄。',16,'全唐诗/poet.song.93000.json','["蒼黄避地小兒女，漂泊連床老弟兄。"]'),
('63d45dd8-93f3-4f45-a295-cb72e8d66163','漁父','方豐之','宋','宋诗','song-poetry','','[]','已攜巨鯉換新秔，尚有鰷鯈得自烹。',32,'全唐诗/poet.song.93000.json','["已攜巨鯉換新秔，尚有鰷鯈得自烹。", "聞道烹鮮易煩碎，呼兒勿用苦爲羹。"]'),
('a5de21d5-dcb4-408a-9502-37b8f03f66b0','歷崎道中','方豐之','宋','宋诗','song-poetry','','[]','漠漠春陽接海低，濛濛晚雨傍山飛。',32,'全唐诗/poet.song.93000.json','["漠漠春陽接海低，濛濛晚雨傍山飛。", "半敧古埭無人過，時有村童護鴨歸。"]'),
('e71302d3-4095-4d5f-a4c8-72f74fd64016','絕句','方豐之','宋','宋诗','song-poetry','','[]','舍人早定江西派，句法須將活處參。',32,'全唐诗/poet.song.93000.json','["舍人早定江西派，句法須將活處參。", "參取陵陽正法眼，寒花承露落毿毿。"]'),
('c5a35b92-65a7-466e-a1c2-12eb0e3930c9','句  其一','方豐之','宋','宋诗','song-poetry','','[]','天女終降大居士，登伽惟撓小乘禪。',16,'全唐诗/poet.song.93000.json','["天女終降大居士，登伽惟撓小乘禪。"]'),
('56a76311-5419-45a7-9730-894a375be08c','句  其二','方豐之','宋','宋诗','song-poetry','','[]','老夫六賊銷磨盡，時爲幽香一敗禪。',16,'全唐诗/poet.song.93000.json','["老夫六賊銷磨盡，時爲幽香一敗禪。"]'),
('b6c76650-6789-4351-b3cf-37393137c4c3','句  其三','方豐之','宋','宋诗','song-poetry','','[]','白是鹽埕青是麥，誰云斥鹵不堪田。',16,'全唐诗/poet.song.93000.json','["白是鹽埕青是麥，誰云斥鹵不堪田。"]'),
('7569e64b-a093-446a-9fd1-355063bc91eb','句  其四','方豐之','宋','宋诗','song-poetry','','[]','魂夢無金印，生涯有瓦盆。',12,'全唐诗/poet.song.93000.json','["魂夢無金印，生涯有瓦盆。"]'),
('5909b10b-456a-4ae6-9db7-61a371fa63c3','句  其五','方豐之','宋','宋诗','song-poetry','','[]','漢室雖然和冒頓，賈生終願繫單于。',16,'全唐诗/poet.song.93000.json','["漢室雖然和冒頓，賈生終願繫單于。"]'),
('f000f150-6f5c-4657-981c-1e3e5ccd52bb','江都燕','釋正宗','宋','宋诗','song-poetry','','[]','荒城春色裏，花濺淚潺湲。',24,'全唐诗/poet.song.93000.json','["荒城春色裏，花濺淚潺湲。", "社燕歸無屋，營巢寄客船。"]'),
('14c84200-acbc-49ce-a2f4-bd5a4b21715a','觀孫司戶畫壁','釋正宗','宋','宋诗','song-poetry','','[]','若人胸次閑，能容書四庫。',84,'全唐诗/poet.song.93000.json','["若人胸次閑，能容書四庫。", "餘地著山川，得酒欲飛去。", "摩挲雪色壁，吐作無聲句。", "寒屯水際雲，瘦立煙中樹。", "雖非桃花源，亦自有佳處。", "未休蝸角兵，欲問樵蘇路。", "只恐山中人，笑我來何暮。"]'),
('4228592e-6089-4f4e-9c3b-a5b8656788a9','次韻蔡堅老秋日登擬峴台','釋正宗','宋','宋诗','song-poetry','','[]','秋容淡薄晚煙孤，千里誰開水墨圖。',32,'全唐诗/poet.song.93000.json','["秋容淡薄晚煙孤，千里誰開水墨圖。", "欲借扁舟乘興去，臥看月影弄風蒲。"]'),
('9d9079b5-7864-4b8c-a03e-589aa63f36fd','山寺晚歸','釋正宗','宋','宋诗','song-poetry','','[]','登臨興未盡，落日苦催歸。',24,'全唐诗/poet.song.93000.json','["登臨興未盡，落日苦催歸。", "扶持出門去，山寒露濕衣。"]'),
('0967b44c-5cf7-4824-b3cc-12bff9c8c856','招福寺作','釋正宗','宋','宋诗','song-poetry','','[]','自顧不材同社櫟，乘流得坎便爲家。',32,'全唐诗/poet.song.93000.json','["自顧不材同社櫟，乘流得坎便爲家。", "體中不快思讀易，睡思欲來還煮茶。"]'),
('1c8f40e5-00c3-4f61-b409-ba221a42a572','句  其一','釋正宗','宋','宋诗','song-poetry','','[]','松風欹風聽。',6,'全唐诗/poet.song.93000.json','["松風欹風聽。"]'),
('25c60441-579e-4db6-a9e8-b6e0822cd987','句  其二','釋正宗','宋','宋诗','song-poetry','','[]','四海無拘繫。',6,'全唐诗/poet.song.93000.json','["四海無拘繫。"]'),
('387f6e47-ce0c-40d7-8d84-55c436564c4a','句  其三','釋正宗','宋','宋诗','song-poetry','','[]','地僻人稀到。',6,'全唐诗/poet.song.93000.json','["地僻人稀到。"]'),
('a85fc447-2103-4602-87ad-7804be7a446d','句  其四','釋正宗','宋','宋诗','song-poetry','','[]','夕陽分手柘岡西。',8,'全唐诗/poet.song.93000.json','["夕陽分手柘岡西。"]'),
('ba929701-9b1d-48e9-add6-0bbc40d9b810','捲煙閣','釋顯萬','宋','宋诗','song-poetry','','[]','僧屋數椽巢木末，風煙日與翠俱浮。',64,'全唐诗/poet.song.93000.json','["僧屋數椽巢木末，風煙日與翠俱浮。", "自無俗物敗人意，況有春江拍岸流。", "艇子得魚歸別浦，鳧雛傍母睡芳洲。", "夜晴兔月摩雲角，翻作廣寒宮殿秋。"]'),
('b16b2475-e49a-4e55-b2dd-fc58aa95a701','送炭與湘山西堂惠然師','釋顯萬','宋','宋诗','song-poetry','','[]','紛紛向火乞兒多，獨有君如擇乳鵝。',64,'全唐诗/poet.song.93000.json','["紛紛向火乞兒多，獨有君如擇乳鵝。", "萬煆爐中尋粲可，一堆灰裏拔陰何。", "雪欺敗屋閑犀柄，草臥空庭任雀羅。", "亟送烏薪相暖熱，恐隨春夢入南柯。"]'),
('192e45c3-66a8-4fb2-aef3-a76cf6a26c04','別鶴操','釋顯萬','宋','宋诗','song-poetry','','[]','三山邈何許，煙霧如海深。',48,'全唐诗/poet.song.93000.json','["三山邈何許，煙霧如海深。", "兩鶴翅相接，意欲棲瑤林。", "驚風起中路，沙塵揚夕陰。", "哀鳴失儔侶，俯啄何苦心。"]'),
('e7c43b2f-62fb-4977-aea3-e4ac6ba96f55','曉發山店','釋顯萬','宋','宋诗','song-poetry','','[]','蓐食小人家，寒燈碎落花。',48,'全唐诗/poet.song.93000.json','["蓐食小人家，寒燈碎落花。", "雞鳴窗半曉，路暗月西斜。", "世故欺懷抱，風霜迫歲華。", "劇憐詩思苦，悽惻向長沙。"]'),
('f703cfc0-7402-48c9-97d8-cde8379e9247','次喬口','釋顯萬','宋','宋诗','song-poetry','','[]','喬口知名久，煙沈水國寒。',48,'全唐诗/poet.song.93000.json','["喬口知名久，煙沈水國寒。", "受風帆腹飽，歇雨櫓臍乾。", "五渚源流異，長沙氣象寬。", "山川濟吾勝，待月倚牆竿。"]'),
('0563fb02-c741-46c1-a207-75a16307dcaa','明溪','釋顯萬','宋','宋诗','song-poetry','','[]','夏木藏崖塢，晴沙抱柳溪。',48,'全唐诗/poet.song.93000.json','["夏木藏崖塢，晴沙抱柳溪。", "茅茨村遠近，隴畝路東西。", "野老連檣語，山禽隔竹啼。", "此中風物美，吾欲卜幽棲。"]'),
('7116f1e6-0411-4b59-accf-843841b7d356','元日不出','釋顯萬','宋','宋诗','song-poetry','','[]','坐意湘西野客家，詩筒茶竈舊生涯。',64,'全唐诗/poet.song.93000.json','["坐意湘西野客家，詩筒茶竈舊生涯。", "癡雲閣雨山腰重，老樹衝波岸腳斜。", "避繳沖蘆憐雁陣，採花釀蜜厭蜂衙。", "故溪幸可浮茅屋，歸聽崖翁響釣車。"]'),
('efda7a4e-5693-45d5-b45b-7d8de2c5c0a9','謾興','釋顯萬','宋','宋诗','song-poetry','','[]','雨沈飛絮綠陰寒，梅子枝頭點點酸。',32,'全唐诗/poet.song.93000.json','["雨沈飛絮綠陰寒，梅子枝頭點點酸。", "心事向來吟不盡，梨花院落一春殘。"]'),
('7199e61f-014f-494a-b585-6d8c6c58192c','春日','釋顯萬','宋','宋诗','song-poetry','','[]','窗外晴山竹半遮，竹根流水細鳴沙。',32,'全唐诗/poet.song.93000.json','["窗外晴山竹半遮，竹根流水細鳴沙。", "小園寂寞春無賴，蝴蝶飛來遶菜花。"]'),
('84b3a032-93c8-4645-a081-a07f99609ef2','庵中自題','釋顯萬','宋','宋诗','song-poetry','','[]','萬松嶺上一間屋，老僧半間雲半間。',32,'全唐诗/poet.song.93000.json','["萬松嶺上一間屋，老僧半間雲半間。", "三更雲去作行雨，回頭方羨老僧閑。"]'),
('a1f41d39-1d6c-4345-beed-ac34ff5b1d11','義帝陵','釋顯萬','宋','宋诗','song-poetry','','[]','祖龍智昏日月蝕，南公力欲麒麟鬬。',128,'全唐诗/poet.song.93000.json','["祖龍智昏日月蝕，南公力欲麒麟鬬。", "楚雖三戶必亡秦，盛德宜然有其後。", "魯公違約火咸陽，咄嗟擊出群雄右。", "豆分瓜剖聽指頤，忍使黥徒賊孤幼。", "籍也狐埋狐搰之，項伯寧不爲家寇。", "真人如龍翔霸上，縞袒長風起襟袖。", "終據皇圖豈力爲，雅張赤幟皆天授。", "可憐郴北東上墳，恨碧淒紅春不茂。"]'),
('27765611-c199-41cb-aaa0-25dbf9e1ca63','蘇仙宅','釋顯萬','宋','宋诗','song-poetry','','[]','蘇君善養志，以孝格神明。',144,'全唐诗/poet.song.93000.json','["蘇君善養志，以孝格神明。", "一朝蛻塵鞅，通籍赤霞城。", "相看疑夢寐，去若鵝毛輕。", "玉笙墮哀響，煙髦錯霓旌。", "丹井愈沈屙，橘葉通仙靈。", "至今華屋底，想像雙眉青。", "雲裝挹飛袖，蕊佩敲風鳴。", "茲事既茫邈，無階接蓬瀛。", "掬月漱吟齒，餐霞壽頹齡。", "藴真思遠託，何從保長生。", "漢武梓棺朽，秦皇鮑魚腥。", "空山鶴未歸，花發春冥冥。"]'),
('f27cd82e-f64c-4cb9-ba74-3570c9c508f8','郴陽道中二首  其一','釋顯萬','宋','宋诗','song-poetry','','[]','草荒驛路欲迷人，未見梅花信息真。',32,'全唐诗/poet.song.93000.json','["草荒驛路欲迷人，未見梅花信息真。", "意著舊家煙雨外，犯寒斜放竹籬春。"]'),
('53876b6e-91c5-45fd-b1e1-d4ed3bb16997','郴陽道中二首  其二','釋顯萬','宋','宋诗','song-poetry','','[]','曉村寒水碧悠悠，雨歇浮雲漫不收。',32,'全唐诗/poet.song.93000.json','["曉村寒水碧悠悠，雨歇浮雲漫不收。", "且緩晨炊三十里，不妨亭午到郴州。"]'),
('757d68cb-0392-4870-a6a2-3c7f4e917586','句  其一','釋顯萬','宋','宋诗','song-poetry','','[]','雨葉工驚夢，春心巧卷愁。',12,'全唐诗/poet.song.93000.json','["雨葉工驚夢，春心巧卷愁。"]'),
('ff10db25-baab-4513-8dbd-af8576334c44','句  其二','釋顯萬','宋','宋诗','song-poetry','','[]','探枝春色牆頭朵，闌入風光竹外梢。',16,'全唐诗/poet.song.93000.json','["探枝春色牆頭朵，闌入風光竹外梢。"]'),
('93a93aa4-4270-4437-90d5-85a3e7c745a5','句  其三','釋顯萬','宋','宋诗','song-poetry','','[]','河橫星斗三更後，月過梧桐一丈高。',16,'全唐诗/poet.song.93000.json','["河橫星斗三更後，月過梧桐一丈高。"]'),
('358934e4-28b1-41e0-aaaf-e7929fa161a9','題獨秀山','沈晦','宋','宋诗','song-poetry','','[]','老鶴下遙天，昂昂在林表。',72,'全唐诗/poet.song.93000.json','["老鶴下遙天，昂昂在林表。", "霜毛臨野人，逸氣秋天杳。", "矯矯顔始安，不受冠带繞。", "清真自嵇阮，一醉萬事了。", "讀書空谷中，生芻白駒皎。", "長哦五君詠，極目送飛鳥。"]'),
('655abaf7-5302-400a-acbb-6b0e9704b56c','竹溪','沈晦','宋','宋诗','song-poetry','','[]','寒流穿清閟，支徑入翠微。',48,'全唐诗/poet.song.93000.json','["寒流穿清閟，支徑入翠微。", "山深古木合，林靜珍禽飛。", "居人本避世，遊客亦忘機。", "歸路晚煙暝，新月照柴扉。"]'),
('de057510-6b42-41ac-8311-ea10966394a8','遊松陽百仞山','沈晦','宋','宋诗','song-poetry','','[]','山頭白雲如擘絮，竹雞無聲鳩喚婦。',96,'全唐诗/poet.song.93000.json','["山頭白雲如擘絮，竹雞無聲鳩喚婦。", "團團朝日在林梢，寒日梨花谿口路。", "一峰獨秀橫溪陰，青林倒影千丈深。", "上有白龍蟄幽洞，歲旱往往能爲霖。", "如今寂寞空山裏，古屋荒壇冷紅紫。", "會看前度種花人，他年來作巢居子。"]'),
('7f7d5cce-865e-4830-a2b1-37d663657bf4','竹山㟯嶺','沈晦','宋','宋诗','song-poetry','','[]','九月亂山中，崎嶇處處同。',48,'全唐诗/poet.song.93000.json','["九月亂山中，崎嶇處處同。", "谿流因雨漲，木葉着霜紅。", "人蹟千巖絕，松聲萬壑空。", "尋幽自可問，不復歡途窮。"]'),
('e16a289d-53c6-4e43-b555-002872af6b38','松陽上方山居五首  其一','沈晦','宋','宋诗','song-poetry','','[]','月餘樹影穿窗入，雨過山泉遶舍鳴。',32,'全唐诗/poet.song.93000.json','["月餘樹影穿窗入，雨過山泉遶舍鳴。", "野寺中宵人不睡，蒲團布衲悟無生。"]'),
('cbdf2439-ccc1-47b3-8021-2a329a45fd8d','松陽上方山居五首  其二','沈晦','宋','宋诗','song-poetry','','[]','山中寒早野陰薄，慘慘黄昏欲雨時。',32,'全唐诗/poet.song.93000.json','["山中寒早野陰薄，慘慘黄昏欲雨時。", "市遠無人與沽酒，地爐松火自燒梨。"]'),
('62d41212-82c5-4f2b-b029-3a25cf54e431','松陽上方山居五首  其三','沈晦','宋','宋诗','song-poetry','','[]','天畔群峰一草亭，半溪煙雨花冥冥。',32,'全唐诗/poet.song.93000.json','["天畔群峰一草亭，半溪煙雨花冥冥。", "老翁投老得此景，日與谿山同醉醒。"]'),
('34499ec0-1ecc-4b01-bc89-d019828f906b','松陽上方山居五首  其四','沈晦','宋','宋诗','song-poetry','','[]','此生真與世相忘，投老生涯寄上方。',32,'全唐诗/poet.song.93000.json','["此生真與世相忘，投老生涯寄上方。", "洗足關門枕書睡，連山松檜雨浪浪。"]'),
('8ce1d613-5faa-4a40-baaf-6f9667a16815','松陽上方山居五首  其五','沈晦','宋','宋诗','song-poetry','','[]','學道空山水月深，丹成初試馬蹄金。',32,'全唐诗/poet.song.93000.json','["學道空山水月深，丹成初試馬蹄金。", "猶餘一勺丹泉水，洗盡人間名利心。"]'),
('d287084b-beb9-4d99-9bf2-e48014e19d33','侍先人遊石橋','沈晦','宋','宋诗','song-poetry','','[]','一別台山四十年，石橋風景尚依然。',32,'全唐诗/poet.song.93000.json','["一別台山四十年，石橋風景尚依然。", "慈顔不見身空老，感恨多如澗底泉。"]'),
('b5127a4f-d72b-4d24-a790-2bb5741fd2e5','留題紫巖寺  其一','沈晦','宋','宋诗','song-poetry','','[]','松嶺楓岡勢接連，梵宮危傍紫巖前。',64,'全唐诗/poet.song.93000.json','["松嶺楓岡勢接連，梵宮危傍紫巖前。", "夜深鍾磬敲清月，日暮樓臺鎖淡煙。", "大抵登臨須有分，不因遷謫到無緣。", "一程已見佳山水，何憚東川路五千。"]'),
('0ba333cc-d6ad-4320-b9ab-3e8fe0bd691b','留題紫巖寺  其二','沈晦','宋','宋诗','song-poetry','','[]','爲愛溪山著意尋，因行每每便登臨。',32,'全唐诗/poet.song.93000.json','["爲愛溪山著意尋，因行每每便登臨。", "寒窗夜久陪僧話，一陣西風月滿林。"]'),
('8f23045d-11df-4982-98f7-de6529acfced','句','沈晦','宋','宋诗','song-poetry','','[]','五嶺炎蒸地，從來着逐臣。',12,'全唐诗/poet.song.93000.json','["五嶺炎蒸地，從來着逐臣。"]'),
('12ca29fb-3745-45b8-b0ae-918c9aa74915','觀水磨牌文有省','釋法忠','宋','宋诗','song-poetry','','[]','轉大法輪，目前包裹。',20,'全唐诗/poet.song.93000.json','["轉大法輪，目前包裹。", "更問如何，水推石磨。"]'),
('35817f96-c8a5-456b-af14-7e5b2d127fd9','諷死心禪師','釋法忠','宋','宋诗','song-poetry','','[]','莫怪狂僧罵死心，死心結夏破叢林。',32,'全唐诗/poet.song.93000.json','["莫怪狂僧罵死心，死心結夏破叢林。", "叢林明眼如相委，此話須教播古今。"]'),
('113de8ae-5a92-4cd8-8f0b-c1e33305ea71','示寂頌','釋法忠','宋','宋诗','song-poetry','','[]','六十六年，遊夢幻中。',20,'全唐诗/poet.song.93000.json','["六十六年，遊夢幻中。", "浩歌歸去，撒手長空。"]'),
('de967608-45a1-467c-8023-b8e5c458b7ea','偈二首  其一','釋法忠','宋','宋诗','song-poetry','','[]','張公喫酒李公醉，子細思量不思議。',44,'全唐诗/poet.song.93000.json','["張公喫酒李公醉，子細思量不思議。", "李公醉醒問張公，恰使張公無好氣。", "無好氣，不如歸家且打睡。"]'),
('06a120da-78bd-45c3-83b5-4dda23d6c5e8','偈二首  其二','釋法忠','宋','宋诗','song-poetry','','[]','今朝正月半，有事爲君斷。',24,'全唐诗/poet.song.93000.json','["今朝正月半，有事爲君斷。", "切忌兩眼睛，被他燈火換。"]'),
('adc75e1e-477b-4aef-b664-f9d515e7142e','頌古三首  其一','釋法忠','宋','宋诗','song-poetry','','[]','秤鎚落井，只有秤衡。',63,'全唐诗/poet.song.93000.json','["秤鎚落井，只有秤衡。", "兩兩相憶，分物不平。", "方始取出乎鎚，忽又失卻秤衡。", "始去鄰家借覓，衡上不曾釘星。", "休休，重者從他重，輕者從他輕。"]'),
('81c1d97c-32d3-453b-a117-d2c08dfee77b','頌古三首  其二','釋法忠','宋','宋诗','song-poetry','','[]','柳惲江頭賞白蘋，小風吹處曉煙輕。',32,'全唐诗/poet.song.93000.json','["柳惲江頭賞白蘋，小風吹處曉煙輕。", "漁翁坐釣秋亭月，翻憶苕溪說性情。"]'),
('afc3ab45-8be3-4cb8-ac3d-d1038509c3ce','頌古三首  其三','釋法忠','宋','宋诗','song-poetry','','[]','二月春光景氣浮，少年公子御街游。',32,'全唐诗/poet.song.93000.json','["二月春光景氣浮，少年公子御街游。", "銀床踞坐傾盃樂，三個孩童打馬毬。"]'),
('5b0a2c02-e705-4d8c-a738-a208b599c7a8','頌古五首  其一','釋法忠','宋','宋诗','song-poetry','','[]','馬駒蹴踏非驢事，要使兒孫腳下行。',32,'全唐诗/poet.song.93000.json','["馬駒蹴踏非驢事，要使兒孫腳下行。", "三日耳聾猶可怪，謾勞灼卜聽虛聲。"]'),
('0a81906b-8e28-4008-b5e5-659ef97de75c','頌古五首  其二','釋法忠','宋','宋诗','song-poetry','','[]','諦觀五百生前事，不昧何如不落親。',32,'全唐诗/poet.song.93000.json','["諦觀五百生前事，不昧何如不落親。", "因果歷然殊可怕，人人盡道野狐精。"]'),
('06c6385d-aa86-470f-ab14-06bb01eddde7','頌古五首  其三','釋法忠','宋','宋诗','song-poetry','','[]','展開兩手當時說，大義流通滿世間。',32,'全唐诗/poet.song.93000.json','["展開兩手當時說，大義流通滿世間。", "莫謂入荒田不揀，而今到處草漫漫。"]'),
('05f8db00-e107-4f59-996d-6e17c60a2d7e','頌古五首  其四','釋法忠','宋','宋诗','song-poetry','','[]','曾到不曾到，且喫一杯茶。',24,'全唐诗/poet.song.93000.json','["曾到不曾到，且喫一杯茶。", "待客只如此，冷淡是僧家。"]'),
('3394365a-7e3d-4ef5-9c71-5722c1c3802a','頌古五首  其五','釋法忠','宋','宋诗','song-poetry','','[]','新婦騎驢阿家牽，草裏尋常萬萬千。',32,'全唐诗/poet.song.93000.json','["新婦騎驢阿家牽，草裏尋常萬萬千。", "誰在後兮誰在先，不須特地苦加鞭。"]'),
('3af69417-0719-4089-993a-fecdb02792d4','次方德順和貧士韻','富直柔','宋','宋诗','song-poetry','','[]','崔嵬孔明柏，結陰衆所依。',72,'全唐诗/poet.song.93000.json','["崔嵬孔明柏，結陰衆所依。", "移根天衢上，曾撫日月暉。", "如何去大廈，卻遶烏鵲飛。", "終當煩萬牛，挽取廊廟歸。", "鄭公澤既遠，何以慰調饑。", "公其踵前修，一洗貧士悲。"]'),
('3418e6cc-ef64-4e48-91c6-ab0fb15fcb12','萬象亭','富直柔','宋','宋诗','song-poetry','','[]','堂後山川面面通，向來奇觀有蒿蓬。',64,'全唐诗/poet.song.93000.json','["堂後山川面面通，向來奇觀有蒿蓬。", "元戎小試經綸手，萬象都歸指顧中。", "雨罷捲簾憑爽氣，酒酣極目送飛鴻。", "明年鳳閣鸞臺上，好寄新詩下北風。"]'),
('86bd79cb-a547-4a8b-b2af-28fe13a8ad22','絕句  其一','富直柔','宋','宋诗','song-poetry','','[]','青衫短簿汝陽天，鶚牘當時誤薦賢。',32,'全唐诗/poet.song.93000.json','["青衫短簿汝陽天，鶚牘當時誤薦賢。", "承乏西樞了無補，還依丈席聽韋編。"]'),
('e6e1c6ad-5995-4cd5-9b00-c02031a49d38','絕句  其二','富直柔','宋','宋诗','song-poetry','','[]','洛陳花骨巧裁詩，曾把梅篇爲玉墀。',32,'全唐诗/poet.song.93000.json','["洛陳花骨巧裁詩，曾把梅篇爲玉墀。", "未說他年調鼎事，只今身已鳳凰池。"]'),
('4c6b490a-d1a9-4f1d-99a8-76dcb39ae38e','絕句  其三','富直柔','宋','宋诗','song-poetry','','[]','陳君談論席生風，段子文詞氣吐虹。',32,'全唐诗/poet.song.93000.json','["陳君談論席生風，段子文詞氣吐虹。", "參朮膎胰皆入篋，知人誰過葛仙翁。"]'),
('ca4609b2-7735-46d2-a00c-5e534bb0d4b7','偈三首  其一','釋法一','宋','宋诗','song-poetry','','[]','衲僧正法眼，照破鐵圍山。',48,'全唐诗/poet.song.93000.json','["衲僧正法眼，照破鐵圍山。", "四方幷八面，尖角更團圞。", "雙椎轟法鼓，一擊透玄關。", "乾坤收不得，留與後人看。"]'),
('18bea3ae-1d96-444e-a0b5-2c03251242f7','偈三首  其二','釋法一','宋','宋诗','song-poetry','','[]','仰面不見天，低頭不見地。',24,'全唐诗/poet.song.93000.json','["仰面不見天，低頭不見地。", "古劍髑髏前，大海波濤沸。"]'),
('965d1906-3ed7-4b40-bfb2-82e34d789077','偈三首  其三','釋法一','宋','宋诗','song-poetry','','[]','今年七十五，歸作庵中主。',24,'全唐诗/poet.song.93000.json','["今年七十五，歸作庵中主。", "珍重觀世音，泥蛇吞石虎。"]'),
('e634e01e-9fdc-4249-9688-e26b5da7f36e','頌古二首  其一','釋法一','宋','宋诗','song-poetry','','[]','世尊隻眼通三界，外道雙眸貫五天。',32,'全唐诗/poet.song.93000.json','["世尊隻眼通三界，外道雙眸貫五天。", "華意正濃桃臉笑，春光不在柳梢邊。"]'),
('017e02fe-fa07-49de-b5dc-c3f452381319','頌古二首  其二','釋法一','宋','宋诗','song-poetry','','[]','背觸人難會，憑君子細看。',24,'全唐诗/poet.song.93000.json','["背觸人難會，憑君子細看。", "片雲才出洞，遮卻面前山。"]'),
('a35fdc83-ddea-41f8-85ac-2d8540b830e7','白雲洞','王延軌','宋','宋诗','song-poetry','','[]','早向珠囊見，今親歷洞門。',48,'全唐诗/poet.song.93000.json','["早向珠囊見，今親歷洞門。", "削成青玉壁，擘破白雲根。", "冷射筇□色，濃□古蘚痕。", "坐來肌骨爽，□□濕琴樽。"]'),
('9986ddd2-7c69-4e69-8606-dcd8981d9845','梅','董貞元','宋','宋诗','song-poetry','','[]','諛佞盈廷不可聞，那堪世事日侵尋。',32,'全唐诗/poet.song.93000.json','["諛佞盈廷不可聞，那堪世事日侵尋。", "三槐九棘浮雲外，一樹寒梅寄我心。"]'),
('51f59201-5bb5-4c6a-ba22-7b0c274c40b0','次宋居卿韻寄題靈巖','劉公度','宋','宋诗','song-poetry','','[]','十里靈巖翠路陰，當時登陟到雲林。',64,'全唐诗/poet.song.93000.json','["十里靈巖翠路陰，當時登陟到雲林。", "佛衣化鐵存真跡，錫杖流泉慰渴心。", "山擁精藍多勝概，松含清籟少繁音。", "歸來每厭紅塵擾，夢寐猶能去遠尋。"]'),
('d03ef32d-60fd-42d0-8424-6fa4bc5cb10a','抱元觀','劉希真','宋','宋诗','song-poetry','','[]','龍岡十里秀蟠雲，天斵靈墟館異人。',64,'全唐诗/poet.song.93000.json','["龍岡十里秀蟠雲，天斵靈墟館異人。", "柳眼長年駐春色，金精一掬吐寒津。", "田公羽駕隨飆遠，長史琅函得語真。", "今日我來師接否，半窗飛雪話蒙屯。"]'),
('8a69c6d4-9146-415d-af83-68222e1f1d21','句','孟長文','宋','宋诗','song-poetry','','[]','世事無窮貧不盡，人生有著到思量。',16,'全唐诗/poet.song.93000.json','["世事無窮貧不盡，人生有著到思量。"]'),
('229f70b3-123b-47cf-86f1-8e170f5e6c5a','句  其一','王仲嶷','宋','宋诗','song-poetry','','[]','白髮衰天癸，丹砂養地丁。',12,'全唐诗/poet.song.93000.json','["白髮衰天癸，丹砂養地丁。"]'),
('fcac7faf-d6ff-4c31-9562-eceb2bbaec76','句  其二','王仲嶷','宋','宋诗','song-poetry','','[]','老境得爲丘壑伴，醉鄉還勝子孫扶。',16,'全唐诗/poet.song.93000.json','["老境得爲丘壑伴，醉鄉還勝子孫扶。"]'),
('54d2b51d-894e-49cb-a4a8-15efa0ae89bd','長安上元','賈宗諒','宋','宋诗','song-poetry','','[]','雍國唯今夜，通衢嘉致新。',48,'全唐诗/poet.song.93000.json','["雍國唯今夜，通衢嘉致新。", "朱樓萬家月，芳樹一城春。", "遠近笙簧韻，往來車馬塵。", "星移天欲曉，猶有未歸人。"]'),
('268e7fac-7c52-41bb-9fc2-d50c8491d289','渝南寒食','賈宗諒','宋','宋诗','song-poetry','','[]','異地逢寒食，客情誰與儔。',48,'全唐诗/poet.song.93000.json','["異地逢寒食，客情誰與儔。", "心搖隴雲下，身寄楚江頭。", "落絮絲絲恨，飛花片片愁。", "東風似相念，終日倚扁舟。"]'),
('515e9696-facb-456d-8169-372cbe3af538','除夜陽口舟中','賈宗諒','宋','宋诗','song-poetry','','[]','一年節律今還盡，猶向天涯寄客舟。',64,'全唐诗/poet.song.93000.json','["一年節律今還盡，猶向天涯寄客舟。", "巫舍簫竽喧竹塢，漁家燈火傍沙洲。", "殷勤共敬新桃醒，棄廢堪嗟舊歷頭。", "守歲通宵欲無寐，煎茶幾啜淥瓷甌。"]'),
('90c5a5ba-0b32-4be4-8470-52a9767c7ced','存目','賈宗諒','宋','宋诗','song-poetry','','[]','詩題：上元日駕幸太乙宮燒香首句：金鑾晨動暖風微。',24,'全唐诗/poet.song.93000.json','["詩題：上元日駕幸太乙宮燒香首句：金鑾晨動暖風微。"]'),
('a847861c-b4ed-4889-932a-99930d3fe19d','齊雲閣','何誠孺','宋','宋诗','song-poetry','','[]','巍閣壯兮翬飛，跳嶕嶢兮雲齊。',34,'全唐诗/poet.song.93000.json','["巍閣壯兮翬飛，跳嶕嶢兮雲齊。", "緩步於斯兮仰者睥睨，青天不遠兮尺五其幾。"]'),
('bc6fd44a-16c8-4c89-acbe-bf7f14e8e8eb','登九疑齊雲閣','何誠孺','宋','宋诗','song-poetry','','[]','齊□巍閣壓山顛，下視岡陵盡窅然。',64,'全唐诗/poet.song.93000.json','["齊□巍閣壓山顛，下視岡陵盡窅然。", "豈並奇峰當盛夏，幾因呈瑞類非煙。", "夜深星斗垂簷畔，雨霽虹蜺掛□邊。", "從此青天平步上，城南尺五更誰□。"]'),
('67859a05-8d71-4c38-b90d-61901a3557a6','又一章十二句用臧德次禪老□','何誠孺','宋','宋诗','song-poetry','','[]','□名□事取齊雲，挺特孤高似法身。',96,'全唐诗/poet.song.93000.json','["□名□事取齊雲，挺特孤高似法身。", "永鎮洞天□□□，直□畫棟□神□。", "□□易見千般態，□□□留一點塵。", "衲帔□須□□□，□□□□□□□。", "□□□道□□得，□□□□□□□。", "□□□□□□□，□□□□□□□。"]'),
('027ee548-ef81-4340-ba9e-606527efb37e','句','安時','宋','宋诗','song-poetry','','[]','仙骨留來不記春，仙巖石欲化爲塵。',16,'全唐诗/poet.song.93000.json','["仙骨留來不記春，仙巖石欲化爲塵。"]'),
('66a9b1c1-e647-49da-bd68-c760be843caa','題梅仙館','朱粹','宋','宋诗','song-poetry','','[]','書投北闕言無用，吏隱南昌寄此間。',64,'全唐诗/poet.song.93000.json','["書投北闕言無用，吏隱南昌寄此間。", "身陟九霄歸紫府，名垂千古寄青山。", "夜壇星斗誰瞻仰，曉殿雲煙自往還。", "幾疊高峰人罕到，分明真境異塵寰。"]'),
('fb54e25d-fdd3-4221-afb0-f1f110fc7712','寄淮南親舊','陳應祥','宋','宋诗','song-poetry','','[]','一別淮南二十年，壽陽風物想依然。',64,'全唐诗/poet.song.93000.json','["一別淮南二十年，壽陽風物想依然。", "秋深峽石山頭寺，夜靜浮橋月下船。", "茅酒沽來常滿斗，白魚買得不論錢。", "甚時脫此塵埃地，快意飛帆入楚煙。"]'),
('22218b42-d53a-43f9-80f5-8f0aee9f53fd','西興晚望','陳應祥','宋','宋诗','song-poetry','','[]','晚色催吟思，江風掠斷霞。',48,'全唐诗/poet.song.93000.json','["晚色催吟思，江風掠斷霞。", "亂烏投岸木，幽鷺集河沙。", "月出海門近，人歸渡口譁。", "會須操舴艋，隨處是天涯。"]'),
('17602c50-1adb-4741-9d76-0cc98b84948a','紫庭經','陳楠','宋','宋诗','song-poetry','','[]','絳宮天子統乾乾，乾龍飛上九華天。',384,'全唐诗/poet.song.93000.json','["絳宮天子統乾乾，乾龍飛上九華天。", "天中妙有無極宮，宮中萬卷指玄篇。", "篇篇皆露金丹旨，千句萬句會一言。", "教人只在尋汞鉛，二物採入鼎中煎。", "夜來火發崑崙山，山頭火冷月光寒。", "曲江之上金烏飛，姮娥已與斗牛歡。", "採之鍊之未片餉，一氣渺渺通三關。", "三關來往氣無窮，一道白脈朝泥丸。", "泥丸之上紫金鼎，鼎中一塊紫金團。", "化爲玉漿流入口，香甜清爽透舌端。", "吞吞服服入五內，臟腑暢甚身康安。", "赤蛇蒼龍交合時，風恬浪靜虎龍蟠。", "神水湛湛華池靜，白雪紛紛飛四山。", "七寶樓臺十二時，樓前黄花深可觀。", "即此可謂鉛汞精，化作精髓盈關源。", "但去身中尋周天，前弦以後後弦前。", "藥物平平氣象足，天地日月交會間。", "虛空自然百雜碎，嚼破混沌軟如綿。", "番來覆去成一錢，遍體玉潤而金堅。", "赤血換兮白血流，金光滿室森森然。", "一池秋水浸明月，一朵金花如紅蓮。", "此時身中神氣全，不須求道復參禪。", "我今知君如此賢，知君有分爲神仙。", "分明指示無兩語，默默運用而抽添。"]'),
('2073c2f0-07c3-4698-9623-48ba0468c06d','大道歌','陳楠','宋','宋诗','song-poetry','','[]','真陰真陽是真道，只在眼前何遠討。',384,'全唐诗/poet.song.93000.json','["真陰真陽是真道，只在眼前何遠討。", "凡流歲歲燒還丹，或見青黄自云好。", "志士應願承法則，莫損心神須見道。", "但知求得真黄芽，人得食之壽無老。", "黄芽不與世鉛同，徒以勞身不見功。", "虛度光陰空白首，何處悠悠訪赤松。", "神水華池世所希，流傳不與俗人知。", "還將世上凡鉛汞，相似令人迷不知。", "青龍逐虎虎隨龍，赤禽交會聲嗈嗈。", "調氣運火逐禽宮，丹砂人腹身沖沖。", "五行深妙義難知，龍虎隱藏在坎離。", "還丹之術過數百，最妙須得真華池。", "丹砂其位元非赤，四季排來在南宅。", "流珠本性無定居，若識其原如秋石。", "日魂月華二氣真，含胎育子自堪神。", "變轉欲終君自見，分明化作明窗塵。", "鉛汞一門不可依，金丹秘訣聖無知。", "莫將世人凡鉛汞，論年運火共相持。", "天生二物應虛無，爲妻爲子復爲夫。", "三五之門爲日月，能分卯酉別終初。", "全養天然稟至神，沖和之氣結成身。", "富貴只緣懷五彩，心知鉛汞共成親。", "乾坤不互相爲避，採取元和在天地。", "十月養成子母分，賢者何曾更運氣。"]'),
('8cac4a12-6c56-48ae-9a30-ee9e25380805','羅浮翠虛吟','陳楠','宋','宋诗','song-poetry','','[]','嘉定壬申八月秋，翠虛道人在羅浮。',383,'全唐诗/poet.song.93000.json','["嘉定壬申八月秋，翠虛道人在羅浮。", "眼前萬事去如水，天地何處一沙鷗。", "吾將蛻形歸玉闕，遂以金丹火候訣。", "說與瓊山白玉蟾，使之深識造化骨。", "道光禪師薛紫賢，付我歸根復命篇。", "指示鉛汞兩箇字，所謂真的玄中玄。", "辛苦都來只十月，漸漸採取漸凝結。", "而今通神是白血，已覺四肢無寒熱。", "後來依舊去參人，勘破多少野狐精。", "箇箇不是真一處，都是旁門不是真。", "恐君虛度此青春，從頭一一爲君陳。", "若非金液還丹訣，不必空自勞精神。", "有如迷者學採戰，心心只向房中戀。", "謂之陰丹御女方，手按眉間吸氣嚥。", "奪人精氣補吾身，執著三峰信邪見。", "產門喚作生身處，九淺一深行幾遍。", "軒後彭祖老容成，黄谷壽光趙飛燕。", "他家別有通霄路，酒肆淫坊戲歷鍊。", "莫言花裏遇神仙，即把金篦換瓦片。", "樹根已朽葉徒青，氣海波翻死如箭。", "其他有若諸旁門，尚自可結安樂緣。", "有如服氣爲中黄，有如守頂爲混元。", "有如運氣爲先天，有如嚥液爲靈泉。", "或者脾邊認一穴，執定爲呼吸根。"]'),
('41df458d-551b-4926-800a-98f29c3e0946','金丹詩訣  其一','陳楠','宋','宋诗','song-poetry','','[]','半斤真汞半斤鉛，隱在靈源太極先。',32,'全唐诗/poet.song.93000.json','["半斤真汞半斤鉛，隱在靈源太極先。", "須趁子時當採取，鍊成金液入丹田。"]'),
('0760a68d-6f90-405a-bc60-6c4501c253b1','金丹詩訣  其二','陳楠','宋','宋诗','song-poetry','','[]','神符白雪結玄珠，此時金丹第一爐。',32,'全唐诗/poet.song.93000.json','["神符白雪結玄珠，此時金丹第一爐。", "十二時辰須認子，莫教金鼎汞花枯。"]'),
('3c608152-c316-4259-9a85-448305d9a7c1','金丹詩訣  其三','陳楠','宋','宋诗','song-poetry','','[]','水火相交虎遇龍，金翁姹女兩爭雄。',32,'全唐诗/poet.song.93000.json','["水火相交虎遇龍，金翁姹女兩爭雄。", "青去白來然後黑，到紅方且入黄宮。"]'),
('0a70d8da-95f2-4f03-ad89-30b0fc3e555d','金丹詩訣  其四','陳楠','宋','宋诗','song-poetry','','[]','玉爐三轉見黄芽，火裏紅蓮解發花。',32,'全唐诗/poet.song.93000.json','["玉爐三轉見黄芽，火裏紅蓮解發花。", "人在絳宮貪夜月，一杯美酒餌丹砂。"]'),
('98b58ff3-a36a-487e-9724-667af848141b','金丹詩訣  其五','陳楠','宋','宋诗','song-poetry','','[]','四轉紅爐轉四神，添符進火養胎精。',32,'全唐诗/poet.song.93000.json','["四轉紅爐轉四神，添符進火養胎精。", "龍虎繞爐爭造化，巽風吹起水中燈。"]'),
('15be5a58-f35c-48be-8310-2c333653258a','金丹詩訣  其六','陳楠','宋','宋诗','song-poetry','','[]','五轉方成白馬芽，卻教六賊運河車。',32,'全唐诗/poet.song.93000.json','["五轉方成白馬芽，卻教六賊運河車。", "五行俱備雷聲震，正好登樓看汞花。"]'),
('e604a3ef-c635-485c-a153-6623205e8967','金丹詩訣  其七','陳楠','宋','宋诗','song-poetry','','[]','鍊成玉液玉神丹，擒制龜蛇頃刻間。',32,'全唐诗/poet.song.93000.json','["鍊成玉液玉神丹，擒制龜蛇頃刻間。", "已是中成消息處，玉爐養火莫教寒。"]'),
('86a95454-5faa-48fa-aa07-925f8da39a6b','金丹詩訣  其八','陳楠','宋','宋诗','song-poetry','','[]','天上七星地七寶，人有七竅權歸腦。',32,'全唐诗/poet.song.93000.json','["天上七星地七寶，人有七竅權歸腦。", "七返靈砂陰氣消，鉛爐只使溫溫火。"]'),
('1a11fc50-ad14-42dc-a546-55ad24755727','金丹詩訣  其九','陳楠','宋','宋诗','song-poetry','','[]','八轉神錦玉清砂，卯酉抽添火不差。',32,'全唐诗/poet.song.93000.json','["八轉神錦玉清砂，卯酉抽添火不差。", "渴飲華池饑嚼氣，黄婆終日看金花。"]'),
('e19085bd-ef59-460f-9e94-82c470a9d802','金丹詩訣  其一○','陳楠','宋','宋诗','song-poetry','','[]','九轉紫金成至寶，天門地戶自關瑣。',32,'全唐诗/poet.song.93000.json','["九轉紫金成至寶，天門地戶自關瑣。", "三百八十有四銖，散爲三萬六午顆。"]'),
('408ffc32-e2fc-46a4-90d8-beb22ec70922','金丹詩訣  其一一','陳楠','宋','宋诗','song-poetry','','[]','青童把鏡照泥丸，五臟祥雲徹上關。',32,'全唐诗/poet.song.93000.json','["青童把鏡照泥丸，五臟祥雲徹上關。", "子午寅申和已亥，胎圓數足出崑崙。"]'),
('a0b4084b-b665-40c7-9641-69d522da9359','金丹詩訣  其一二','陳楠','宋','宋诗','song-poetry','','[]','移將北斗向南辰，穿過黄庭入紫庭。',32,'全唐诗/poet.song.93000.json','["移將北斗向南辰，穿過黄庭入紫庭。", "攢簇一年真造化，太陽正照月三更。"]'),
('e367437a-1cb7-4e87-a66b-c7a315ed22d8','金丹詩訣  其一三','陳楠','宋','宋诗','song-poetry','','[]','上應星辰下應鉛，太陽三十六交躔。',32,'全唐诗/poet.song.93000.json','["上應星辰下應鉛，太陽三十六交躔。", "不因法象無由採，誰語生於天地先。"]'),
('6e09c574-9ed5-4a98-95e9-1bc739f5f3d8','金丹詩訣  其一四','陳楠','宋','宋诗','song-poetry','','[]','黄丹胡粉密陀僧，此是嘉州告別穹能。',33,'全唐诗/poet.song.93000.json','["黄丹胡粉密陀僧，此是嘉州告別穹能。", "若不見陽真一法，世間還有幾人曾。"]'),
('e18ea333-c0e9-4161-a1c7-3491b8a520ba','金丹詩訣  其一五','陳楠','宋','宋诗','song-poetry','','[]','紅鉛之髓名真汞，黑汞之精是正鉛。',32,'全唐诗/poet.song.93000.json','["紅鉛之髓名真汞，黑汞之精是正鉛。", "莫向腎中求造化，卻須心裏覓先天。"]'),
('0bc7d09a-d506-4a09-befb-7106b8dc0c7f','金丹詩訣  其一六','陳楠','宋','宋诗','song-poetry','','[]','靈汞元非是水銀，丹砂不赤太迷人。',32,'全唐诗/poet.song.93000.json','["靈汞元非是水銀，丹砂不赤太迷人。", "此般真物誰能識，識者驂鸞脫世塵。"]'),
('41c5bf28-8302-410f-92fc-a6259b60333a','金丹詩訣  其一七','陳楠','宋','宋诗','song-poetry','','[]','三種真形一種稀，結成靈異少人知。',32,'全唐诗/poet.song.93000.json','["三種真形一種稀，結成靈異少人知。", "莫言龍虎同源出，便是神仙立兆基。"]'),
('38711571-5f60-4c4f-977c-cc7350f7354f','金丹詩訣  其一八','陳楠','宋','宋诗','song-poetry','','[]','鎮星合得配中央，偃水能交色變黄。',32,'全唐诗/poet.song.93000.json','["鎮星合得配中央，偃水能交色變黄。", "不此凡金銀與鐵，成時全是賴陰陽。"]'),
('2c17017d-5cef-48f6-a3ae-d9cf7b7da5a1','金丹詩訣  其一九','陳楠','宋','宋诗','song-poetry','','[]','莫近丘墳穢污田，亦嫌戰地產人眠。',32,'全唐诗/poet.song.93000.json','["莫近丘墳穢污田，亦嫌戰地產人眠。", "坤來靈氣形爲福，便是求仙小洞天。"]'),
('f5e7766f-d05b-4a06-a5f9-faaf24da5a4b','金丹詩訣  其二○','陳楠','宋','宋诗','song-poetry','','[]','山林靜處最宜良，或在塵中或在鄉。',32,'全唐诗/poet.song.93000.json','["山林靜處最宜良，或在塵中或在鄉。", "土德厚時丹得厚，妄爲立見有迍殃。"]'),
('139afebc-64ed-4d31-ac25-3b68da6107d4','金丹詩訣  其二一','陳楠','宋','宋诗','song-poetry','','[]','室宜向木對朝陽，兌有明窗對夕光。',32,'全唐诗/poet.song.93000.json','["室宜向木對朝陽，兌有明窗對夕光。", "照顧有名人莫曉，暮陰不得閉金牆。"]'),
('b5a96142-10ee-42ad-88a4-fa55bf27c3ed','金丹詩訣  其二二','陳楠','宋','宋诗','song-poetry','','[]','八門運化應時開，進退隨金定往業。',32,'全唐诗/poet.song.93000.json','["八門運化應時開，進退隨金定往業。", "莫息明爐幷百戶，安然二鼎位三台。"]'),
