('702f5088-6007-4afc-be21-c920a6eb472d','翠微山居詩  其一六','釋沖邈','宋','宋诗','song-poetry','','[]','三界無家誰最親，十方惟有一空身。',32,'全唐诗/poet.song.93000.json','["三界無家誰最親，十方惟有一空身。", "但隨雲水伴明月，到處名山是主人。"]'),
('890015cf-f7d2-49f1-adaa-e7099e24ea7e','翠微山居詩  其一七','釋沖邈','宋','宋诗','song-poetry','','[]','茅簷靜對千山月，竹戶閑樓一片雲。',32,'全唐诗/poet.song.93000.json','["茅簷靜對千山月，竹戶閑樓一片雲。", "莫送往來名利客，階前踏破綠苔紋。"]'),
('afee9834-0b55-4475-ab6f-1c84759359ea','翠微山居詩  其一八','釋沖邈','宋','宋诗','song-poetry','','[]','踏石窗山一老僧，白雲爲伴水爲朋。',32,'全唐诗/poet.song.93000.json','["踏石窗山一老僧，白雲爲伴水爲朋。", "通宵只在洞中宿，月上青山便是燈。"]'),
('71dbd50a-ec41-4bdf-bdd3-de438fead406','翠微山居詩  其一九','釋沖邈','宋','宋诗','song-poetry','','[]','人生在世急如風，昨夜今朝事不同。',32,'全唐诗/poet.song.93000.json','["人生在世急如風，昨夜今朝事不同。", "不信但看桃李樹，花開能得幾時紅。"]'),
('b0edb86a-aea5-4866-a29d-971615ce3e96','翠微山居詩  其二○','釋沖邈','宋','宋诗','song-poetry','','[]','僧家無事最幽閑，近對青松遠對山。',32,'全唐诗/poet.song.93000.json','["僧家無事最幽閑，近對青松遠對山。", "詩句不曾題落葉，恐隨流水到人間。"]'),
('da9e4668-55dd-4d41-a6d8-e40ceb17b90a','翠微山居詩  其二一','釋沖邈','宋','宋诗','song-poetry','','[]','霜飛峭壁夜猿驚，手把松枝叫月明。',32,'全唐诗/poet.song.93000.json','["霜飛峭壁夜猿驚，手把松枝叫月明。", "知有石龕僧入定，朝來不作斷腸聲。"]'),
('8441965e-c6ac-4c89-8c5b-e207898d8aa9','翠微山居詩  其二二','釋沖邈','宋','宋诗','song-poetry','','[]','任性隨緣一比丘，一生無喜亦無憂。',32,'全唐诗/poet.song.93000.json','["任性隨緣一比丘，一生無喜亦無憂。", "白雲縱聽飛來去，但得青山在即休。"]'),
('2d531f72-5690-4779-8bba-b14c44960bd8','翠微山居詩  其二三','釋沖邈','宋','宋诗','song-poetry','','[]','爐中無火已多時，早起惟將一衲披。',32,'全唐诗/poet.song.93000.json','["爐中無火已多時，早起惟將一衲披。", "莫怪山僧常冷澹，夜深無處拾松枝。"]'),
('1718df0f-91a8-42b8-ab14-8b005c801ae3','翠微山居詩  其二四','釋沖邈','宋','宋诗','song-poetry','','[]','豈是栽松待茯苓，且圖山色鎮長青。',32,'全唐诗/poet.song.93000.json','["豈是栽松待茯苓，且圖山色鎮長青。", "他年行腳不將去，留與人間作畫屏。"]'),
('1da4e104-af7b-494f-98fa-5d058d1b1227','翠微山居詩  其二五','釋沖邈','宋','宋诗','song-poetry','','[]','高高峰頂恣情田，買斷清閑不用錢。',32,'全唐诗/poet.song.93000.json','["高高峰頂恣情田，買斷清閑不用錢。", "堪笑白雲無定止，被他風送出山前。"]'),
('6964df64-4e81-47a7-bace-443fcdca47b9','句','王逸民','宋','宋诗','song-poetry','','[]','我生不背佛，而自外道取。',12,'全唐诗/poet.song.93000.json','["我生不背佛，而自外道取。"]'),
('2e8606eb-e17e-4c6e-9e5d-6094dd1f3bb6','爲蚊所擾得一絕句','徐端崇','宋','宋诗','song-poetry','','[]','空堂夜合勢如雲，溝壑寧知過去身。',32,'全唐诗/poet.song.93000.json','["空堂夜合勢如雲，溝壑寧知過去身。", "滿腹經營盡膏血，那知通夕不眠人。"]'),
('184790b1-7d7e-4524-a921-dbb49948a2c3','句','徐端崇','宋','宋诗','song-poetry','','[]','魯邦司寇陳義高，三閭大夫心徒勞。',32,'全唐诗/poet.song.93000.json','["魯邦司寇陳義高，三閭大夫心徒勞。", "相逢一笑無言說，去宿蘆花又明月。"]'),
('c444f7d3-ecf5-4a90-a9f6-fa4c3f6b7430','句','王綯','宋','宋诗','song-poetry','','[]','我欲掛冠去，君當衣錦還。',12,'全唐诗/poet.song.93000.json','["我欲掛冠去，君當衣錦還。"]'),
('e0ed5bf7-10e9-4d81-912f-6ff326a9e83b','建炎丞相成國呂忠穆公退老堂  其一','胡世將','宋','宋诗','song-poetry','','[]','雲水郊深退老堂，公來野服換龍章。',64,'全唐诗/poet.song.93000.json','["雲水郊深退老堂，公來野服換龍章。", "四朝盡瘁身猶健，一德同寅福未央。", "小隱聊堪供放浪，神州終倚致平康。", "功成他日歸休地，海表家風有故鄉。"]'),
('30b37798-e30a-4253-a5c9-b8c3763ee7fd','建炎丞相成國呂忠穆公退老堂  其二','胡世將','宋','宋诗','song-poetry','','[]','卜宅他鄉得偃休，忘懷遇坎復乘流。',64,'全唐诗/poet.song.93000.json','["卜宅他鄉得偃休，忘懷遇坎復乘流。", "功高天地雲龍會，心寄丘園水石幽。", "墨客騷人多賦詠，金堂玉室縱追遊。", "公念問舍真無負，自是豪英百尺樓。"]'),
('a8edd5dd-d8f6-4be7-a8b2-d2e5ed48e4bf','癸醜三月十日自湧泉寺過吳文叟山居臨溪觀魚輒題二詩  其一','胡世將','宋','宋诗','song-poetry','','[]','雲物起爭巖石秀，水拉行带野花香。',32,'全唐诗/poet.song.93000.json','["雲物起爭巖石秀，水拉行带野花香。", "一山應接知無暇，賴有青春白日長。"]'),
('798b2fdc-5f94-4a1b-9802-e33591e64e84','癸醜三月十日自湧泉寺過吳文叟山居臨溪觀魚輒題二詩  其二','胡世將','宋','宋诗','song-poetry','','[]','偶尋勝賞到山扉，谿影涵暉動翠微。',32,'全唐诗/poet.song.93000.json','["偶尋勝賞到山扉，谿影涵暉動翠微。", "正欲臨流看魚樂，扁舟寧待夜潮歸。"]'),
('c4021401-cda5-45d6-9617-c14b10685eb1','蘇子翼送黄精酒','朱弁','宋','宋诗','song-poetry','','[]','仙經何物堪却老，較功無如太陽草。',320,'全唐诗/poet.song.93000.json','["仙經何物堪却老，較功無如太陽草。", "龍銜雞銜名雖異，菟公羊公事可考。", "蘇君真是神仙裔，橘井陰功貫穹昊。", "雲笈書成數萬言，銀關珠宫用心早。", "獨知此物有奇効，福地名山爲儲寶。", "不惮林泉新斸掘，斥去杵臼謝飾擣。", "况從髙士論麹糜，更課公田收秫稻。", "一朝靈液浮瓮盎，三冬浩氣生襟抱。", "且欣軟飽得澆腸，漫說逆流工補腦。", "眼碧那憂散黒花，髮白故應還翠葆。", "賈傅只嫌松醥陋，劉墮敢誇桑落好。", "直須五斗論解酲，寧待三柸乃通道。", "誰知萬里落旄人，亦許匏尊自傾倒。", "爲君喚迴雪窖春，八載覊愁供一掃。", "曼倩宜分此日桃，安期莫詫他年棗。", "何煩更採石斛花，巳覺容顔不枯槁。", "根連石室喜入夢，句擬桐溪媿摛藻。", "平生我亦愛書扎，朱髓緑腸勤探討。", "幸君汲引成此志，鶴駕駸駸望仙島。", "吞腥啄腐非夙心，歲晚兹言良可保。"]'),
('d2cc99a0-0355-4a53-aeaf-81277c0532f4','初春以蔓菁作虀因憶往年避難大隗山采蘋澗中爲虀虀成汁爲粉紅色而香美特異乃信鄭人所言爲不誣矣今食新虀因成長韻','朱弁','宋','宋诗','song-poetry','','[]','藏蔬飽三冬，媚盤無靃靡。',276,'全唐诗/poet.song.93000.json','["藏蔬飽三冬，媚盤無靃靡。", "陳虀解束縛，冰雹散刀几。", "春畦蕪菁苗，入眼漸可喜。", "青黄含風露，採摘從此始。", "持歸作新虀，一飽競鮮美。", "芬香溢肺肝，甘脆響牙齒。", "捫腹幽窻下，芻豢詎能比。", "憶昔避難初，竄身重嵓裏。", "雲煙昬具茨，老稚且棲止。", "燕兵大捜索，焚蕩石牛底。", "脫命擉虎山，野哭紛四起。", "暮投山前店，茅棟例燒毀。", "潜伏窟室中，衣敝不蓋體。", "妻孥坐相對，生意薄於紙。", "晨朝行澗中，采芹澗邊洗。", "鄭人誇此虀，他菜非所擬。", "氤氲投瓦盎，觸鼻似蘭芷。", "一杯紅粉羮，析酲勝仙醴。", "乃知野人獻，涼薄未宜鄙。", "今來滯殊郷，白首家萬里。", "猶能對葷羶，咀嚼出宫徴。", "回思十年夢，爭奪殊未巳。", "飽食但謀身，吾顙良有泚。"]'),
('12cd42c4-0f9a-43a3-8cfc-cc968e564c7c','北人以松皮爲菜予初不知味虞侍郎分餉一小把因飯素授厨人與薗蔬雜進珎美可喜因作一詩','朱弁','宋','宋诗','song-poetry','','[]','吾老似出家，晚悟愧根鈍。',192,'全唐诗/poet.song.93000.json','["吾老似出家，晚悟愧根鈍。", "滋旨却羶葷，禅蛻要親近。", "偉哉十八公，兹道亦精進。", "舎身奉刀几，割體絕嗔恨。", "鱗皴老龍皮，鳴齒溢芳潤。", "流膏爲伏龜，千歲未須問。", "便堪奴笋蕨，詎肯友芝菌。", "跏趺得一飽，萬事皆可擯。", "侍郎文懿後，落落衆推俊。", "澹然丗味薄，內典得所信。", "香厨留淨供，頻食不言頓。", "晏然黙不語，草木雷音震。", "得法於此公，骨髓傳心印。", "應怜持節人，餉此爲問訊。", "欲將無上味，爲我洗塵坌。", "食之不敢餘，感激在方寸。"]'),
('456dcbe0-6746-4bc0-beb9-cdb1c3632c30','予以年事漸髙氣海不能熟生煖冷旅中又無藥物遂用火攻之策灼艾凡二百壯吟呻之際得詩二十韻','朱弁','宋','宋诗','song-poetry','','[]','不作漳濵卧，年侵血氣衰。',240,'全唐诗/poet.song.93000.json','["不作漳濵卧，年侵血氣衰。", "據鞍思少壯，攬鏡嘆清羸。", "有病方求艾，無營莫問蓍。", "心知出下策，理勝遇中醫。", "陽燧神逾速，銅仙術盡施。", "論功鄙炮製，取穴辨毫釐。", "火帝恩光異，炎官績用奇。", "書螢比差似，珠蟻迫方知。", "忖物嗟炮鱉，觀形笑灼龜。", "煙微初炙手，氣烈漸鑚皮。", "閉目書徒展，支頭枕屢移。", "發狂還自哂，賈勇僅能支。", "宋鷁追風日，吴牛喘月時。", "忠言勞緩頰，善謔爲開眉。", "服氣工夫逺，燒丹歲月遟。", "衞生防後患，伐性釋前疑。", "展轉那成夢，呻吟且當詩。", "因心念民瘼，出位嘆身卑。", "欲巳七年病，當從百丗師。", "保身將保國，未可廢箴規。"]'),
('b64c6a8f-5c4b-4ba9-92b0-6576e41776ad','元夕有感','朱弁','宋','宋诗','song-poetry','','[]','朔雪餘千里，東風徧九州。',48,'全唐诗/poet.song.93000.json','["朔雪餘千里，東風徧九州。", "關河中土異，燈火上元愁。", "緑蟻甞新釀，青貂戀故裘。", "紫姑無用卜，丗事正悠悠。"]'),
('fee063b9-da1e-4068-b2c0-da7ecb3dd84e','憶鍾離濬','朱弁','宋','宋诗','song-poetry','','[]','浚都同聚讀書螢，楚岸春風憶送行。',64,'全唐诗/poet.song.93000.json','["浚都同聚讀書螢，楚岸春風憶送行。", "三十年前初識靣，四千里外更關情。", "出疆我亦徒勞爾，入仕君今何似生。", "旅鴈相逢須一問，要從郵上得新聲。"]'),
('ff3e585c-0f51-42dd-963a-a29759dd02c8','炕寢三十韻','朱弁','宋','宋诗','song-poetry','','[]','風土南北殊，習尚非一躅。',288,'全唐诗/poet.song.93000.json','["風土南北殊，習尚非一躅。", "出疆雖仗節，入國蹔同俗。", "淹留歲再残，朔雪滿崖谷。", "禦冬貂裘弊，一炕且跧伏。", "西山石爲薪，黝色驚射目。", "方熾絕可邇，將盡還自續。", "飛飛湧玄雲，焰焰積紅玉。", "稍疑雷出地，又似風薄木。", "誰容鼠棲冰，信是龍銜燭。", "陽曦助喘息，未害揺空腹。", "惠氣生袴襦，仍工展拳足。", "豈惟脫膚鱗，兼復平體粟。", "負暄那用詫，執熱定思沃。", "收功在歲寒，較德比時燠。", "雖餘炙手熖，寧有爛額酷。", "矧當凝泫辰，炎帝獨回轂。", "玄冥真退聽，祝融端可録。", "嗟予亦何者，萬里歌黄鵠。", "偃仰對窻扉，妍煖謝衾褥。", "壯懷羞竈媚，晚悟笑突曲。", "因思墮指人，暴露苦皸瘃。", "頻年未解甲，蹈此鋒刃毒。", "遥知革輅中，旰食安豆粥。", "陪臣將命來，意懇誠亦篤。"]'),
('c47e764a-9941-4a2c-bbcb-09b9ef67c8e6','秋泉次韻','朱弁','宋','宋诗','song-poetry','','[]','新醅滃滃溢瓶盆，漱石秋泉带雨渾。',64,'全唐诗/poet.song.93000.json','["新醅滃滃溢瓶盆，漱石秋泉带雨渾。", "翡翠杯深雲液凝，鸕鷀杓滿月波翻。", "照人光入樽罍瑩，流齒香隨語笑噴。", "巳拚扶頭日三丈，朝酲未解任昬昬。"]'),
('67ac14ce-c384-49d9-8fcc-0f85e2023276','夜雨枕上','朱弁','宋','宋诗','song-poetry','','[]','淅淅風聲止，凄凄雨氣凉。',48,'全唐诗/poet.song.93000.json','["淅淅風聲止，凄凄雨氣凉。", "愁工縈客思，夢故遶江郷。", "書疏親朋少，干戈歲月長。", "平城弭節地，可復見秋霜。"]'),
('7746f4b6-309d-4073-8168-4984c6f0c7b1','客懷','朱弁','宋','宋诗','song-poetry','','[]','兵氣常時見，客懷何日開。',48,'全唐诗/poet.song.93000.json','["兵氣常時見，客懷何日開。", "形骸病自瘦，鬢髮老相催。", "巳負秦庭哭，終期漢節回。", "風雷識意我，一雨洗氛埃。"]'),
('e147fec5-0ed6-4be1-9476-7d9ba05587d6','歲序','朱弁','宋','宋诗','song-poetry','','[]','歲序忽將晏，節旄嗟未還。',48,'全唐诗/poet.song.93000.json','["歲序忽將晏，節旄嗟未還。", "低雲慘衆木，寒雨失群山。", "喪亂關詩思，謳謡發病顔。", "夢魂識舊隱，時到碧溪灣。"]'),
('d609b3e4-e910-4df8-8dea-d66ec8ae70ec','白髮','朱弁','宋','宋诗','song-poetry','','[]','白髮使車前，煙波思渺然。',48,'全唐诗/poet.song.93000.json','["白髮使車前，煙波思渺然。", "霜清穫稻日，風急授衣天。", "客館但愁坐，釣舟誰醉眠。", "乘槎會有便，真到斗牛邊。"]'),
('fea0d8b4-c1d5-4e77-bf48-97fbe356ca80','有感','朱弁','宋','宋诗','song-poetry','','[]','容貌與年改，鬢毛隨意斑。',48,'全唐诗/poet.song.93000.json','["容貌與年改，鬢毛隨意斑。", "鴈邊雲度塞，鳥外日銜山。", "仗節功奚在，捐軀志未閑。", "不知垂老眼，何日覩龍顔。"]'),
('9280b20b-63dd-470d-90dd-4c513b1c7647','劉善長出示李伯時畫馬圖','朱弁','宋','宋诗','song-poetry','','[]','俯首舉尾拳一蹄，掣韁欲嗅驕不嘶。',96,'全唐诗/poet.song.93000.json','["俯首舉尾拳一蹄，掣韁欲嗅驕不嘶。", "奚官聳肩兩足垂，意皃自與造父齊。", "雞目麟鬐鳯皇臆，玉山禾逺未容食。", "籋雲追雹有餘地，置之畫圖人豈識。", "精神權奇孰可班，當在白兔青龍閒。", "君知此馬從何來，龍眠胸中十二閑。"]'),
('944b659e-2787-4c68-8257-7308d93208a5','謝崔致君餉天花','朱弁','宋','宋诗','song-poetry','','[]','三年北饌飽羶葷，佳蔬頗憶南州味。',192,'全唐诗/poet.song.93000.json','["三年北饌飽羶葷，佳蔬頗憶南州味。", "地菜方爲九夏珎，天花忽從五臺至。", "崔侯胸中散千卷，金甌名相傳雲裔。", "愛山亦如謝康樂，得此携歸豈容易。", "應怜使館久寂寥，分餉明明見深意。", "堆槃初見瑶草瘦，鳴齒稍覺瓊枝脆。", "樹雞濕爛慚扣門，桒蛾青黄謾趨市。", "赤城菌子立萬釘，今日因君不知貴。", "乖龍耳僅兔一割，沙門業巳通三丗。", "偃戈息民未有術，雖復加飡秖増媿。", "雲山去此縱不逺，口腹何容更相累。", "報君此詩永爲好，捧腹一笑萬事置。"]'),
('654732c7-f6cd-40a5-b622-bdba69ea17c6','戰伐','朱弁','宋','宋诗','song-poetry','','[]','戰伐何年定，悲愁是處同。',48,'全唐诗/poet.song.93000.json','["戰伐何年定，悲愁是處同。", "黄雲縈晚塞，白露下秋空。", "魚躍深波月，烏啼落葉風。", "誰知渡江夢，一夜繞行宫。"]'),
('1f7f32cd-1f3b-430e-97fc-54f1961ca097','龍福寺煑東坡羮戲作','朱弁','宋','宋诗','song-poetry','','[]','山寺解塵鞅，溪邊有微行。',48,'全唐诗/poet.song.93000.json','["山寺解塵鞅，溪邊有微行。", "手摘諸葛菜，自煑東坡羮。", "雖無錦繡腸，亦飽風露清。", "鉤簾坐捫腹，落日千峯明。"]'),
('cfe40b50-01c0-4c3b-8622-cc242a2dca8f','丙申中秋不見月','朱弁','宋','宋诗','song-poetry','','[]','中秋萬里月，何處駕冰輪。',48,'全唐诗/poet.song.93000.json','["中秋萬里月，何處駕冰輪。", "底事隔年會，不憐今夕人。", "兔疑停杵臼，蟾豈避風塵。", "黙識常娥意，氶平賞更新。"]'),
('ed2cbdda-0c87-4b49-9c0b-7b92a036625a','十七夜對月','朱弁','宋','宋诗','song-poetry','','[]','病骨怯風露，愁懷厭甲兵。',48,'全唐诗/poet.song.93000.json','["病骨怯風露，愁懷厭甲兵。", "人居絕域久，月向此宵明。", "輪仄初經漢，光分半隱城。", "遟遟不肯下，應識異郷情。"]'),
('92d46c4f-3c38-4444-b5b4-bd2fabb7513f','睡軒爲趙光道作','朱弁','宋','宋诗','song-poetry','','[]','深炷爐香睡息匀，蕭然一覺得天真。',64,'全唐诗/poet.song.93000.json','["深炷爐香睡息匀，蕭然一覺得天真。", "生涯聊示人閒丗，縁境都忘藥褁身。", "窺牖屢來從汝喚，叩門空去任渠嗔。", "更須滿壁圖雲水，卧想江湖渺莾春。"]'),
('4f26ef4c-d790-43c8-a99f-bd0209a816ed','南齋即事','朱弁','宋','宋诗','song-poetry','','[]','頻年行役夢庭闈，陟岵常嗟脚力疲。',64,'全唐诗/poet.song.93000.json','["頻年行役夢庭闈，陟岵常嗟脚力疲。", "毎訴酒巡嫌客惡，力營官事笑兒癡。", "雲山幸不持錢買，花竹何妨带雨移。", "此味責人元未識，恐縁詩好被渠知。"]'),
('f70ff03d-faf9-4caa-bfc5-a82dc3875b4a','餞和父之并州','朱弁','宋','宋诗','song-poetry','','[]','有北何堪說，如南未是歸。',48,'全唐诗/poet.song.93000.json','["有北何堪說，如南未是歸。", "并門子徑往，漢節我方鞿。", "筆硯論心久，干戈會面稀。", "新程相憶處，路入嶺雲微。"]'),
('ac9c7054-3bed-4965-9194-6f6d4d184f8b','獨坐','朱弁','宋','宋诗','song-poetry','','[]','草凍慵抽碧，桃癡懶暈紅。',48,'全唐诗/poet.song.93000.json','["草凍慵抽碧，桃癡懶暈紅。", "黄雲猶漢野，紫塞漫春風。", "使節空留滯，侯圭未會同。", "堦除雪不掃，獨立數歸鴻。"]'),
('aa036de9-62c1-41d9-9b52-4680017f66e2','寒食','朱弁','宋','宋诗','song-poetry','','[]','絕域年華久，衰顔淚點新。',48,'全唐诗/poet.song.93000.json','["絕域年華久，衰顔淚點新。", "毎逢寒食節，頻夢故郷春。", "草緑唯供恨，花紅只笑人。", "南轅定何日，無地不風塵。"]'),
('7be0cef9-2c49-469c-9cf3-311aadc16549','上巳','朱弁','宋','宋诗','song-poetry','','[]','行行春向暮，猶未見花枝。',48,'全唐诗/poet.song.93000.json','["行行春向暮，猶未見花枝。", "晦朔中原隔，風煙上巳疑。", "常令漢節在，莫作楚囚悲。", "早晚鸞旗發，吾歸敢恨遟。"]'),
('7281b815-52d1-4d32-ad28-bcbc4add0845','送春','朱弁','宋','宋诗','song-poetry','','[]','風煙節物眼中稀，三月人猶戀褚衣。',64,'全唐诗/poet.song.93000.json','["風煙節物眼中稀，三月人猶戀褚衣。", "結就客愁雲片叚，喚回郷夢雨霏微。", "小桃山下花初見，弱柳沙頭絮禾飛。", "把酒送春無别語，羡君纔到便成歸。"]'),
('11ff0338-3c84-4b9c-8bab-293654469997','天問絕句','朱弁','宋','宋诗','song-poetry','','[]','穴邊酣戰君臣蟻，波上群嬉婢妾魚。',32,'全唐诗/poet.song.93000.json','["穴邊酣戰君臣蟻，波上群嬉婢妾魚。", "苦樂不同同一宇，問天此理竟何如。"]'),
('0d6fcb32-5f7f-44ae-8b29-658a2b5dd87b','客夜','朱弁','宋','宋诗','song-poetry','','[]','城月四更上，窻風一室幽。',48,'全唐诗/poet.song.93000.json','["城月四更上，窻風一室幽。", "纎雲縈鴈塞，重霧逼貂裘。", "兵革何年息，乾坤此夜愁。", "殊郷兩行淚，騷屑洒清秋。"]'),
('06d1c68a-375e-4177-86d6-afbbd06875bc','攄抱','朱弁','宋','宋诗','song-poetry','','[]','客滯殊方久，山圍絕塞深。',48,'全唐诗/poet.song.93000.json','["客滯殊方久，山圍絕塞深。", "秋風入撗笛，夜月傍沾襟。", "造膝他時語，捐軀此日心。", "飛霜滿明鏡，髮短不勝簪。"]'),
('d85e4bbe-4c73-4900-bda3-077e84bd676e','重九','朱弁','宋','宋诗','song-poetry','','[]','九日今何地，寒深紫塞霜。',48,'全唐诗/poet.song.93000.json','["九日今何地，寒深紫塞霜。", "敢嫌蘆酒濁，且對菊花甞。", "歲月雙蓬鬢，乾坤百戰場。", "賜茰知未舉，夢自識鴛行。"]'),
('49fc8d4c-05d6-43be-acd4-b3bddf25bf41','次韻劉太師苦吟之什','朱弁','宋','宋诗','song-poetry','','[]','長城五字屹逶迤，可笑偏師敢出奇。',64,'全唐诗/poet.song.93000.json','["長城五字屹逶迤，可笑偏師敢出奇。", "句補推敲未安處，韻更瘀絮益難時。", "癡迷竟作禽填海，辛苦真成蟻度絲。", "却羡彌明攻具速，劉侯漫說也能詩。"]'),
('01c9446d-2d1e-4208-abdd-ee6602ca003e','善長命作歲除日立春','朱弁','宋','宋诗','song-poetry','','[]','土牛巳着勸農鞭，葦索仍專捕鬼權。',64,'全唐诗/poet.song.93000.json','["土牛巳着勸農鞭，葦索仍專捕鬼權。", "且喜春盤兼守歲，莫嗟臘酒易經年。", "東風漸入江梅夢，朔雪猶迷塞柳天。", "元會明朝定何處，覊臣揮淚節旄前。"]'),
('ce6acf4a-3bff-4927-b1c6-49a1dd75f12d','次韻子文秋興','朱弁','宋','宋诗','song-poetry','','[]','逸興常時有，逢秋一倍多。',48,'全唐诗/poet.song.93000.json','["逸興常時有，逢秋一倍多。", "山長含楚雨，天逺接吴波。", "尋壑同元亮，浮家伴志和。", "釣竿行入手，還着向來蓑。"]'),
('c242310c-d69e-46c3-a417-2959108de73d','冬雨','朱弁','宋','宋诗','song-poetry','','[]','冬雨不成雪，北風寒未深。',48,'全唐诗/poet.song.93000.json','["冬雨不成雪，北風寒未深。", "山藏千壘秀，雲結四垂陰。", "逈洒凌朝閣，残聲入夜衾。", "端能洗兵甲，足慰此時心。"]'),
('5d815d8a-fb2a-45c9-91e8-17ddd3348ded','寒食感懷次韻吴英叔','朱弁','宋','宋诗','song-poetry','','[]','疾風甚雨老難禁，嶺外無餳誰解吟。',64,'全唐诗/poet.song.93000.json','["疾風甚雨老難禁，嶺外無餳誰解吟。", "雙鬢客塵諳丗變，兩眉郷思儘愁侵。", "榆錢何處迎新火，杏粥頻年繫此心。", "落日髙城魂易断，天臨牛斗五湖深。"]'),
('361308a0-6949-4930-96dc-c7476e1b6555','春陰','朱弁','宋','宋诗','song-poetry','','[]','關河迢逓繞黄沙，慘慘陰風塞柳斜。',64,'全唐诗/poet.song.93000.json','["關河迢逓繞黄沙，慘慘陰風塞柳斜。", "花带露寒無戲蝶，草連雲暗有藏鴉。", "詩窮莫寫愁如海，酒薄難將夢到家。", "絕域東風竟何事，秖應催我鬢邊華。"]'),
('439fd449-3ca9-448a-acde-b1b20eb7a85c','寒食','朱弁','宋','宋诗','song-poetry','','[]','清明六到客愁邊，雙鬢星星只自憐。',64,'全唐诗/poet.song.93000.json','["清明六到客愁邊，雙鬢星星只自憐。", "兵氣尚纒巢鳳閣，節旄巳落牧羊天。", "紙錢灰入松楸夢，餳粥香隨榆柳煙。", "北向鴈來寒霧隔，音書不比上林傳。"]'),
('3ec1f65d-9852-441d-8e46-7326f9bb445f','題雲館二星集後','朱弁','宋','宋诗','song-poetry','','[]','絕域山川飽所經，客蓬歲晚任飄零。',64,'全唐诗/poet.song.93000.json','["絕域山川飽所經，客蓬歲晚任飄零。", "詞源未得窺三峽，使節何容比二星。", "蘿蔦施松慙弱質，蒹葭倚玉怪殊形。", "齊名李杜吾安敢，千載公言有汗青。"]'),
('01f5dcb1-47a9-4aba-8651-fea8482f4f69','秋夜','朱弁','宋','宋诗','song-poetry','','[]','秋夜雖漸永，未抵客愁長。',60,'全唐诗/poet.song.93000.json','["秋夜雖漸永，未抵客愁長。", "秋月雖巳圎，不照寸心方。", "將心貯此愁，莫作萬斛量。", "爲月憐此夜，誰共千里光。", "空令還家夢，欲趂征鴻翔。"]'),
('179fbd74-b0e0-4eee-92e4-bddd0aa74da2','別百一侄寄念二兄','朱弁','宋','宋诗','song-poetry','','[]','昔我別汝父，見汝立扶牀。',180,'全唐诗/poet.song.93000.json','["昔我別汝父，見汝立扶牀。", "汝今已婚宦，我鬚宜俱蒼。", "向來青雲器，不佩紫羅囊。", "竹林我未孤，玉樹汝非常。", "青衫初一尉，遠在子真鄉。", "念將東南歸，拜我溱洧傍。", "上能論道義，次猶及文章。", "自慚老仍僻，何以相激昂。", "日暮嵩雲飛，秋高塞鴻翔。", "了知還家夢，先汝渡江航。", "迢迢建業水，高臺下鳳凰。", "鼻祖有故廬，勿令草樹荒。", "我欲種松菊，繼此百年芳。", "汝歸約我兄，晚歲同耕桑。", "請策葛陂龍，來尋金華羊。"]'),
('1396f2c0-8cf8-4df6-b82f-cc552a5ff035','葡萄','朱弁','宋','宋诗','song-poetry','','[]','葡萄產西域，漢使斸根回。',24,'全唐诗/poet.song.93000.json','["葡萄產西域，漢使斸根回。", "自到中原後，先從上苑栽。"]'),
('b523238a-df62-41b2-897e-29cbc8d4c2ae','紹興十三年自雲中奉使回送伴至虹縣以舟入萬安湖','朱弁','宋','宋诗','song-poetry','','[]','雲中六閏食無魚，清夜時時夢斵鱸。',32,'全唐诗/poet.song.93000.json','["雲中六閏食無魚，清夜時時夢斵鱸。", "離汶未逾千里道，度淮先泛萬象湖。"]'),
('09ccaa92-cc98-4cf1-9412-1fe10d0a1054','元夕廳設醮','朱弁','宋','宋诗','song-poetry','','[]','春容先督府，月色滿江城。',48,'全唐诗/poet.song.93000.json','["春容先督府，月色滿江城。", "燈賞無仙夢，齋居絕市聲。", "兩年憂旱虐，八郡望秋成。", "憑藉剛風力，青章達九清。"]'),
('3995bcd3-9436-4b40-9bc4-d533added93c','元夕','朱弁','宋','宋诗','song-poetry','','[]','立馬行歌隘市門，賣薪攜子出前村。',64,'全唐诗/poet.song.93000.json','["立馬行歌隘市門，賣薪攜子出前村。", "聲翻寶界金鼇動，光奪瓊樓玉兔昏。", "守舍呻吟宜老病，通宵奔走付兒孫。", "潘郎豈是無情思，點檢霜髭愧綠尊。"]'),
('8f1a369e-dd91-413b-8f08-5bc14dc90812','栽花','朱弁','宋','宋诗','song-poetry','','[]','種柳五年高出屋，攀條坐愛春陰綠。',32,'全唐诗/poet.song.93000.json','["種柳五年高出屋，攀條坐愛春陰綠。", "環池又栽數品花，蜀葵玫瑰與石竹。"]'),
('607c018a-0bba-44c4-ab85-d3ee13203bfa','句  其一','朱弁','宋','宋诗','song-poetry','','[]','花到上林開。',6,'全唐诗/poet.song.93000.json','["花到上林開。"]'),
('eb264008-539f-4dfa-8d72-fb2bf08828bb','句  其二','朱弁','宋','宋诗','song-poetry','','[]','平生所愛曾莫倦，天遣花王慰吾願。',32,'全唐诗/poet.song.93000.json','["平生所愛曾莫倦，天遣花王慰吾願。", "姚黄三月開洛陽，曾觀一尺春風面。"]'),
('700ece5d-1e12-4ad5-ae5b-7cf00de41301','句  其三','朱弁','宋','宋诗','song-poetry','','[]','萬頃玻璃一葉船，衝蘆曳藻入蒼煙。',16,'全唐诗/poet.song.93000.json','["萬頃玻璃一葉船，衝蘆曳藻入蒼煙。"]'),
('d925971f-92ce-41d7-a5c2-c2b9b78826b3','延平江上呈吳國華先生','陳淵','宋','宋诗','song-poetry','','[]','青山如偉人，可望不可制。',84,'全唐诗/poet.song.93000.json','["青山如偉人，可望不可制。", "屹然瞰碧流，龍翔虎豹視。", "春風何時來，草木舞深翠。", "禽鳥暖相依，飛鳴得真意。", "誰言靜無作，坐致無邊利。", "願言斬茅茨，結室傍薈蔚。", "且要觀此身，功業亦細事。"]'),
('6867c2b9-b5e1-4526-afe5-014396c2705d','玉山驛見周東老題詩和之','陳淵','宋','宋诗','song-poetry','','[]','塵勞千種祇紛紛，之子歸來始一春。',32,'全唐诗/poet.song.93000.json','["塵勞千種祇紛紛，之子歸來始一春。", "掉舌不知何處去，又還攜劍出南閩。"]'),
('1131d109-c61c-4d06-86f8-7f088288ff5c','立我軒','陳淵','宋','宋诗','song-poetry','','[]','是身猶逆旅，真吾所寄耳。',168,'全唐诗/poet.song.93000.json','["是身猶逆旅，真吾所寄耳。", "若人問真吾，本空何可擬。", "立我物必隨，我應爲物使。", "捐物更求我，是以物爲已。", "文章鏡面塵，富貴路傍屣。", "胡爲認而有，展轉迷不已。", "此迷自何得，定以有我起。", "達人齊萬變，視彼猶視此。", "隤然天地間，形稿心如水。", "獨有長存者，萬刼不能死。", "夷齊與盜跖，趣操定誰美。", "是非儻難分，物我那相訿。", "君懷經濟心，題牓故云爾。", "我乏異俗才，詩言亦其理。"]'),
('f8bb54b3-2bb5-45f4-a7dc-99ec98e79d9a','和人獨酌二絕  其一','陳淵','宋','宋诗','song-poetry','','[]','共矜春色盡銜盃，文字紅裙各有儕。',32,'全唐诗/poet.song.93000.json','["共矜春色盡銜盃，文字紅裙各有儕。", "何似西園閑處士，一盃花下畏人來。"]'),
('daca6f19-a670-4363-97df-02d2d6866d04','和人獨酌二絕  其二','陳淵','宋','宋诗','song-poetry','','[]','休論身外千端事，且醉花前一榻風。',32,'全唐诗/poet.song.93000.json','["休論身外千端事，且醉花前一榻風。", "舉盞但能邀皓月，隔籬何必喚鄰翁。"]'),
('937f7f66-17fc-4da4-a112-6eca1b50a07c','鄰有張生者病革勢不可救忽夢醫人鄧舜臣言萬病圓如說服之遂安感而作詩','陳淵','宋','宋诗','song-poetry','','[]','醫王脱超如蜕蟬，幻身變滅成飛煙。',264,'全唐诗/poet.song.93000.json','["醫王脱超如蜕蟬，幻身變滅成飛煙。", "百年薪盡火猶傳，直驅神馬窮青天。", "自從和扁不少延，冀北萬疋今蕭然。", "挾方儲藥人摩肩，閑花野卉紛爭妍。", "昨夢宵蝶正蹁蹮，忽忽神遇高人前。", "舊交量見意終圓，相顧眼笑如忘年。", "因言癘疫興哀憐，語我妙藥醒沉緜。", "唯有岐婆世所賢，此物病極猶能痊。", "覺來攬衣視星躔，明月墮落遥山巔。", "挑燈草簡便求旃，十粒入手收淮蠙。", "平明攻疾才下咽，頓活始信真天全。", "先生愛習不忍捐，尚念故國多凡緣。", "祇應造物相留連，閔此衆萬刼火煎。", "故令丹成猶未仙，妙畀神力司陰權。", "世間愚術謀相先，不計性命徒論錢。", "誰能如公心不偏，此詩義直何當宣。", "付與末俗懲輕悁。"]'),
('90d8ffeb-f208-4195-bf46-a7e01f48eeba','崇安分水嶺','陳淵','宋','宋诗','song-poetry','','[]','已見江南草木菲，筍輿愁下亂山圍。',32,'全唐诗/poet.song.93000.json','["已見江南草木菲，筍輿愁下亂山圍。", "但將雙淚憑西注，寄語江神穩送歸。"]'),
('c61cb364-4305-4b9c-b290-1c0bfe6c62a0','離紫溪驛','陳淵','宋','宋诗','song-poetry','','[]','小風吹面雨廉纖，輕薄衣裳懶更添。',32,'全唐诗/poet.song.93000.json','["小風吹面雨廉纖，輕薄衣裳懶更添。", "一線離情裁不斷，暮雲將過粵山尖。"]'),
('af843a0e-0b8c-47c5-8ddf-f1867a475d72','鉛山','陳淵','宋','宋诗','song-poetry','','[]','欲留無計去還悲，漸遠閩山物象非。',32,'全唐诗/poet.song.93000.json','["欲留無計去還悲，漸遠閩山物象非。", "家在天南今北首，忍看歸鳥背人飛。"]'),
('249261d8-f3dd-4dd6-abc6-1cf94f2e6fcc','信州禪月院晚眺','陳淵','宋','宋诗','song-poetry','','[]','一覺華胥日又曛，晚來愁緒亂紛紛。',32,'全唐诗/poet.song.93000.json','["一覺華胥日又曛，晚來愁緒亂紛紛。", "角聲對起重城近，吹動靈山萬疊雲。"]'),
('706c6adf-0f58-4812-8f34-e4429789390c','舟中初晴','陳淵','宋','宋诗','song-poetry','','[]','碧玉空江漾曉暉，水光浮簟影交飛。',32,'全唐诗/poet.song.93000.json','["碧玉空江漾曉暉，水光浮簟影交飛。", "酒昏頭重慵扶起，卧看蛟龍上客衣。"]'),
('5fceb150-cc4d-40a8-9e25-c308e37241da','登睦州環峰亭','陳淵','宋','宋诗','song-poetry','','[]','月照空山杜宇啼，喚歸漁艇夜天低。',32,'全唐诗/poet.song.93000.json','["月照空山杜宇啼，喚歸漁艇夜天低。", "那堪又是雙溪水，獨上危樓十二梯。"]'),
('3b8dfde6-12cd-49ef-a667-35f8c0fe19cf','泊姑蘇憑匯亭候同行不至','陳淵','宋','宋诗','song-poetry','','[]','扁舟繫岸五六日，草屨遶亭千百迴。',64,'全唐诗/poet.song.93000.json','["扁舟繫岸五六日，草屨遶亭千百迴。", "欲行無計住不可，夢想萬事心如摧。", "燕雀飛鳴意自適，翩翩簷外相往來。", "乃知荆棘殊不惡，培風萬里真勞哉。"]'),
('fd78b706-d58b-4614-b51e-cbd6de6d421c','次韻李仲虎召伯相遇','陳淵','宋','宋诗','song-poetry','','[]','區區千里爲浮名，小隱終慙鄭子真。',64,'全唐诗/poet.song.93000.json','["區區千里爲浮名，小隱終慙鄭子真。", "雙闕幾時瞻北極，萬山無處望南閩。", "尊前壯士今如夢，胯下真王迹已塵。", "共俯淮流追往事，玉蟾依舊水粼粼。"]'),
('f4b33340-43a2-4f6c-91f7-ff43f71da071','重陽後送謹常兄之符離','陳淵','宋','宋诗','song-poetry','','[]','鎖外分攜處，離觴話遠途。',48,'全唐诗/poet.song.93000.json','["鎖外分攜處，離觴話遠途。", "黄花看不足，寒雁去何孤。", "農圃非吾業，衣冠本世儒。", "應當慎行止，無使世氛汙。"]'),
('6075e072-8b2f-44f7-89d0-47d42a3b685e','九月二十二日秋舉失利出門用中相餞夜步河上留别','陳淵','宋','宋诗','song-poetry','','[]','太平今日古無鄰，觸目郊原事事新。',64,'全唐诗/poet.song.93000.json','["太平今日古無鄰，觸目郊原事事新。", "年少自應迷鼓吹，野人終是厭塵埃。", "忘懷處世思同俗，有事關心不爲身。", "藥石有能醫久痼，此生寧復怨垂綸。"]'),
('e967a44a-7ae5-450d-8c04-25f61735c46d','錢塘過廖次山以詩見贈次韻','陳淵','宋','宋诗','song-poetry','','[]','往來江海兩年餘，自怪鄉音已變吳。',64,'全唐诗/poet.song.93000.json','["往來江海兩年餘，自怪鄉音已變吳。", "樽酒每思難會面，客鄉何意復趨隅。", "雨寒君未瞻天竺，水涸吾妨適鏡湖。", "幸此徘徊緩分袂，笑談猶得對冰壺。"]'),
('4c192325-66fb-4284-a00a-c4395ee60c84','次韻欲游西湖阻雨','陳淵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年賞西湖，薄暑扳躋難。',108,'全唐诗/poet.song.93000.json','["去年賞西湖，薄暑扳躋難。", "同游幸勝士，酒沃衣巾斑。", "今歲來錢塘，臘雨扁舟寒。", "友朋適四集，局蹙樊籠間。", "此生分林泉，造物猶余慳。", "未爲登岳禱，且作訪戴還。", "無私本天理，敢怨陰雲頑。", "向來旱蝗惡，征賦亦未寛。", "寧令風作雪，要看麥堆山。"]'),
('b2243561-95c3-4de2-8168-11b734bed5ce','蕭山覺苑寺雪後杜門','陳淵','宋','宋诗','song-poetry','','[]','雪融簷溜如秋霖，古寺掩關無足音。',96,'全唐诗/poet.song.93000.json','["雪融簷溜如秋霖，古寺掩關無足音。", "詩書廢放道眼淨，鐘鼓杳隔禪房深。", "老僧勸坐媒以火，茶鼎靜聽蒼蠅吟。", "胸中激梗造澄澈，一念不作千憂沉。", "浮生半日未易得，邂逅勝境聊安心。", "明日孤帆落何許，歲晚濁醪誰共斟。"]'),
('77f23736-41a7-44ee-9115-d480bd4d0acc','錢清待潮','陳淵','宋','宋诗','song-poetry','','[]','江潮來去自有時，扁舟閣淺心如飛。',64,'全唐诗/poet.song.93000.json','["江潮來去自有時，扁舟閣淺心如飛。", "岸容霜竹青照眼，春信雪梅香撲衣。", "天寒鄞江道路阻，歲晏錢清風俗非。", "故園回首二千里，落日看盡行雲歸。"]'),
('654f4b2f-b2eb-4e4d-8e2c-d03dc111c3da','錢清過堰','陳淵','宋','宋诗','song-poetry','','[]','小風吹樹寒流止，始覺西江潮正起。',128,'全唐诗/poet.song.93000.json','["小風吹樹寒流止，始覺西江潮正起。", "須臾倒卷縠紋來，已没岸痕猶未已。", "江流自下河自高，逆上更堪行罔水。", "九牛回首竹索細，十丈沙泥拒舟底。", "舟師絕叫鼙鼓喧，觀者駢肩汗如洗。", "未經破碎亦偶然，得造漣漪真幸爾。", "世間何事非人力，計久終須倚天理。", "他年我欲治河源，要使黄流貫清泚。"]'),
('24ef03b8-b8de-4ee4-a45c-e6c6bae8a42c','蕭山雪中寄季修','陳淵','宋','宋诗','song-poetry','','[]','南雪一尺餘，茲事豈常有。',120,'全唐诗/poet.song.93000.json','["南雪一尺餘，茲事豈常有。", "直恐春氣融，不忍加以帚。", "我友隔十里，無人共觴酒。", "披衣坐短蓬，吟苦千呵手。", "疾風穿簾幕，陰霧低窗牖。", "思君欲乘興，奈此衣見肘。", "吾生爲已疏，未即學耕耦。", "要令天下肥，自以一身後。", "三登今告祥，此意亦云偶。", "端能歌豐年，擊壤和田叟。"]'),
('177822e9-0b64-48f9-bccc-445b0005e0fb','過鑑湖','陳淵','宋','宋诗','song-poetry','','[]','稽山霸業已蕪没，賀老鑑湖今幾時。',96,'全唐诗/poet.song.93000.json','["稽山霸業已蕪没，賀老鑑湖今幾時。", "當年乞得亦清絕，不道後日知誰尸。", "人生底物乃吾有，謬辱君賜寧非癡。", "遊人依舊逐勝賞，歌舞自昔皆塵泥。", "荷枯葦折洲渚出，深處不變清琉璃。", "汪汪萬頃撓不濁，坐令我憶牛醫兒。"]'),
('7c3101dc-70bc-45f8-985f-9a79c813f432','季修欲之仰山預作詩送之','陳淵','宋','宋诗','song-poetry','','[]','飄零今日海東偏，見子奔馳不自憐。',64,'全唐诗/poet.song.93000.json','["飄零今日海東偏，見子奔馳不自憐。", "洛社求師霜入屨，仰山尋隱草連天。", "白雲南望家雖近，璧水東來計已然。", "賴有從前息心地，不令塵土化流年。"]'),
('ff839546-cf49-4234-8e3a-092163f64702','病減枕上五首  其一','陳淵','宋','宋诗','song-poetry','','[]','階草無期日自生，獨餘貧病破元正。',32,'全唐诗/poet.song.93000.json','["階草無期日自生，獨餘貧病破元正。", "春風一種生生意，誰道年來也世情。"]'),
('d23f6e6c-9ccb-4313-b56a-312345c14918','病減枕上五首  其二','陳淵','宋','宋诗','song-poetry','','[]','飄零古寺倚江邊，高卧春風百病纒。',32,'全唐诗/poet.song.93000.json','["飄零古寺倚江邊，高卧春風百病纒。", "造化小兒真戲我，不令歌酒趁新年。"]'),
('92489a32-a24a-47aa-847c-719bb97d6468','病減枕上五首  其三','陳淵','宋','宋诗','song-poetry','','[]','多情春夢草生池，起欲尋芳力尚疲。',32,'全唐诗/poet.song.93000.json','["多情春夢草生池，起欲尋芳力尚疲。", "未解維摩無一語，故應習氣欲題詩。"]'),
('fddc9f13-b1fe-4c43-aa3b-beac4621816e','病減枕上五首  其四','陳淵','宋','宋诗','song-poetry','','[]','塵埃子石蒙蛛網，殘落霜毫暗蘚紋。',32,'全唐诗/poet.song.93000.json','["塵埃子石蒙蛛網，殘落霜毫暗蘚紋。", "未把語言爲戲劇，新年不作送窮文。"]'),
('67e941c2-88d5-4551-85e8-797cc6c12b5a','病減枕上五首  其五','陳淵','宋','宋诗','song-poetry','','[]','三釡承親計已疏，萬鍾行道竟何如。',32,'全唐诗/poet.song.93000.json','["三釡承親計已疏，萬鍾行道竟何如。", "安貧未赴闍黎飯，信命寧裁宰相書。"]'),
('94890716-e05b-47de-849c-321983e0bbd4','季脩有詩求公晦顔公書元次山碑銘既而公晦和成使病者亦賦之','陳淵','宋','宋诗','song-poetry','','[]','英雄仙去形骸薧，空有遺銘卧荒草。',208,'全唐诗/poet.song.93000.json','["英雄仙去形骸薧，空有遺銘卧荒草。", "誰將後事付平原，石刻長隨天不老。", "古來筆法多神逸，斷碣塵埃誰復掃。", "顧無清議藹人間，末技縱工何足道。", "往年好古搜奇蹟，百過曾看爭坐稾。", "直詞無復假軍容，僣逆知公能辯早。", "教兒祇欲傳家法，揮金可笑歐陽媪。", "豈知名義重丘山，遺屨終令魯人寶。", "此碑文墨兩奇偉，千載漫郎猶有考。", "當時談笑傲豺狼，首領不求明哲保。", "至今心畫落銀鈎，逸若驊騮初脱皁。", "先生年來好收書，兼愛此翁忠有餘。", "豈惟筆力求深造，定要聲名不減渠。"]'),
('1f55e570-2332-4b48-9260-a9a7c0985475','季脩舍舟趨諸暨謁劉元成獨泛錢清江有懷其人','陳淵','宋','宋诗','song-poetry','','[]','人遠牛羊暮，春深草樹滋。',48,'全唐诗/poet.song.93000.json','["人遠牛羊暮，春深草樹滋。", "野橋低映水，溪岸曲縈籬。", "風雨江湖思，乾坤杖屨疑。", "論心竟誰是，短棹欲何之。"]'),
('6a32dfd0-f9aa-4bea-92fd-07328f9c2746','聞許景受上書被召二首  其一','陳淵','宋','宋诗','song-poetry','','[]','九萬須憑負翼風，男兒端不爲貧窮。',32,'全唐诗/poet.song.93000.json','["九萬須憑負翼風，男兒端不爲貧窮。", "當時三顧應虚出，畢竟論功要有終。"]'),
('3ad88bc4-cc95-4444-8178-405a732f5085','聞許景受上書被召二首  其二','陳淵','宋','宋诗','song-poetry','','[]','男兒出處欲如神，莫謾將身過許人。',32,'全唐诗/poet.song.93000.json','["男兒出處欲如神，莫謾將身過許人。", "今日萬人看中鵠，挾弓持矢且逡巡。"]'),
('7e5160cc-c071-493d-bdc8-43ea25e8800b','聞公晦叔往廉州以詩送之','陳淵','宋','宋诗','song-poetry','','[]','宗之瀟洒玉爲顔，叔夜粗疏萬事寛。',64,'全唐诗/poet.song.93000.json','["宗之瀟洒玉爲顔，叔夜粗疏萬事寛。", "天與海邊嘗瘴癘，意令他日慣艱難。", "功名自古誰能必，忠孝于今衆所觀。", "志士殺身當不顧，小人懷土但求安。"]'),
('fa18a7d2-f964-4449-a056-97def5c8d9b4','觀獵','陳淵','宋','宋诗','song-poetry','','[]','蒼鷹黄犬五花騘，木落風高箭上弓。',32,'全唐诗/poet.song.93000.json','["蒼鷹黄犬五花騘，木落風高箭上弓。", "三穴若能搜狡兔，九天方可下冥鴻。"]'),
('806fef0a-7028-4fae-9db3-5915733ec782','登奔牛堰山亭','陳淵','宋','宋诗','song-poetry','','[]','桑陰濃處已深春，小市喧呼迥不聞。',32,'全唐诗/poet.song.93000.json','["桑陰濃處已深春，小市喧呼迥不聞。", "誰與山頭共遊戲，靜看禽鳥鬬紛紛。"]'),
('2f193c67-55e1-416c-b19d-2b4f2c72df38','謁滿處沖歸以詩贈之','陳淵','宋','宋诗','song-poetry','','[]','八年重見各蹉跎，把酒論文奈別何。',64,'全唐诗/poet.song.93000.json','["八年重見各蹉跎，把酒論文奈別何。", "行止未應經掃地，是非安用辯傾河。", "陽春屬和從來少，流水知音不必多。", "妙語驚人慵舉似，歸來如學病維摩。"]'),
('0092594b-9c30-40a2-9eb5-c1af5821ba68','處沖見和復次韻二首  其一','陳淵','宋','宋诗','song-poetry','','[]','高談無補自風波，畢竟平生意若何。',64,'全唐诗/poet.song.93000.json','["高談無補自風波，畢竟平生意若何。", "萬里悞遊梁苑囿，三年悔寄楚山河。", "軒裳氣味情終可，林壑風流興已多。", "賴有故人真遠器，會看鵬翼九天摩。"]'),
('d288819d-64a4-4ce5-81e3-30d8d5c987fd','處沖見和復次韻二首  其二','陳淵','宋','宋诗','song-poetry','','[]','歲月空驚去若波，樗材渾欲樹無何。',64,'全唐诗/poet.song.93000.json','["歲月空驚去若波，樗材渾欲樹無何。", "人情不似春生草，末學方矜水灌河。", "顧我嶔崎徒意廣，如君飄逸患才多。", "周南縱復嗟留滯，未便懸頭學揣摩。"]'),
('4afe5739-3685-4905-8740-81bb5c8cd00e','處沖又和頗及佛理亦次韻答之','陳淵','宋','宋诗','song-poetry','','[]','相逢雖許借餘波，此理而今更問何。',64,'全唐诗/poet.song.93000.json','["相逢雖許借餘波，此理而今更問何。", "便合形骸同槁木，不須文墨騁懸河。", "五千遺教元非實，三萬藏書亦太多。", "此外別傳應有路，頓根無物可漸摩。"]'),
('9bdcbee0-ff75-43f6-a115-ad26c46269ac','處沖爲棲神導氣之術每曉起得意成詩前後四首次其韻  其一','陳淵','宋','宋诗','song-poetry','','[]','功名亦誤人，自古誰能了。',48,'全唐诗/poet.song.93000.json','["功名亦誤人，自古誰能了。", "老大欲退藏，少壯知幾少。", "彤墀班已齊，宿鳥尚木杪。", "豈無山林心，路長天杳杳。"]'),
('31fbe864-958b-473c-b3ae-b26288b1a2b0','處沖爲棲神導氣之術每曉起得意成詩前後四首次其韻  其二','陳淵','宋','宋诗','song-poetry','','[]','少時自樹立，勁氣干雲霄。',48,'全唐诗/poet.song.93000.json','["少時自樹立，勁氣干雲霄。", "一枕夢初覺，萬古心何寥。", "年來畏禍機，自悟空嶢嶢。", "小窮不必送，真隱誰能招。"]'),
('12f8d2cb-2f45-4fb7-afe1-677d133e80c2','處沖爲棲神導氣之術每曉起得意成詩前後四首次其韻  其三','陳淵','宋','宋诗','song-poetry','','[]','交鬬存龍虎，經申學熊鳥。',48,'全唐诗/poet.song.93000.json','["交鬬存龍虎，經申學熊鳥。", "嬰兒檢奔放，姹女棲窈窕。", "神仙豈無術，自爲志已湫。", "晨興一炷香，吾意窮三藐。"]'),
('5b5a3e1d-0558-43e2-b0b5-168b01caee04','處沖爲棲神導氣之術每曉起得意成詩前後四首次其韻  其四','陳淵','宋','宋诗','song-poetry','','[]','朝氣爽不昏，清淨天無霞。',48,'全唐诗/poet.song.93000.json','["朝氣爽不昏，清淨天無霞。", "善惡兩相融，世慮遺塵沙。", "疏鐘下殘月，餘響遞幽遐。", "了失去來心，淤泥出荷茄。"]'),
('ab2a7d25-1ffd-42d2-b9d2-b2258b252b5f','秋夕','陳淵','宋','宋诗','song-poetry','','[]','衰榆弱柳未經霜，已見飄零片片黄。',32,'全唐诗/poet.song.93000.json','["衰榆弱柳未經霜，已見飄零片片黄。", "雨後晚風生户牖，莫將燈火汗清涼。"]'),
('e034b57d-2f34-42bd-b32e-5022f297f3dd','七夕三首  其一','陳淵','宋','宋诗','song-poetry','','[]','北里南鄰錦綉陳，萬端千疊日初晴。',32,'全唐诗/poet.song.93000.json','["北里南鄰錦綉陳，萬端千疊日初晴。", "收藏犢鼻何須挂，不與人間鬬獨清。"]'),
('718745e4-2b15-4740-a38c-c1414144ac5f','七夕三首  其二','陳淵','宋','宋诗','song-poetry','','[]','天上銀蟾曲似鈎，人間簫鼓萬家浮。',32,'全唐诗/poet.song.93000.json','["天上銀蟾曲似鈎，人間簫鼓萬家浮。", "從來世事俱兒戲，不獨秦娥乞巧樓。"]'),
('6e655143-d1a6-4735-b72d-508ef03ab4bd','七夕三首  其三','陳淵','宋','宋诗','song-poetry','','[]','信馬隨車力不勝，聊將觴豆樂交朋。',32,'全唐诗/poet.song.93000.json','["信馬隨車力不勝，聊將觴豆樂交朋。", "青樓乞巧真兒女，我亦如今拙未能。"]'),
('9ea1f05b-62fa-4ac3-91ed-d5952b616ae1','七夕閨意戲范濟美三首  其一','陳淵','宋','宋诗','song-poetry','','[]','衡陽新雁幾時歸，惆悵佳人萬事非。',32,'全唐诗/poet.song.93000.json','["衡陽新雁幾時歸，惆悵佳人萬事非。", "蓬首西風還拜月，夜涼贏得露沾衣。"]'),
('8a7bfe43-77ff-4aa3-8576-5ba24a6cf317','七夕閨意戲范濟美三首  其二','陳淵','宋','宋诗','song-poetry','','[]','經年不復到庭除，又見秋風柳欲疏。',32,'全唐诗/poet.song.93000.json','["經年不復到庭除，又見秋風柳欲疏。", "看罷巧樓歸小閣，牀頭重撿近來書。"]'),
('33b08bf0-6cb3-4ede-90c6-286c4e9a7402','七夕閨意戲范濟美三首  其三','陳淵','宋','宋诗','song-poetry','','[]','祝君樽酒醉羅裳，此夜應須石作腸。',32,'全唐诗/poet.song.93000.json','["祝君樽酒醉羅裳，此夜應須石作腸。", "幸自書生惡滋味，那堪千里羡牛郎。"]'),
('aceb934d-4d2d-4c10-8826-38ca7c82ac5c','九日登莊樓二首  其一','陳淵','宋','宋诗','song-poetry','','[]','久客驚秋意，天涯思不窮。',48,'全唐诗/poet.song.93000.json','["久客驚秋意，天涯思不窮。", "三年猶北國，萬里對西風。", "時序悲歌裏，乾坤醉眼中。", "黄花一樽酒，千古此心同。"]'),
('964df8fd-1520-42ca-a776-a4073a03ca6b','九日登莊樓二首  其二','陳淵','宋','宋诗','song-poetry','','[]','木落秋容淨，時平國勢雄。',48,'全唐诗/poet.song.93000.json','["木落秋容淨，時平國勢雄。", "望雲心自遠，采菊興誰同。", "詩酒浮生過，功名一笑空。", "留連憑痛飲，冠幘任高風。"]'),
('987f9816-e51f-498e-97c8-3f6b59348002','次韻范濟美秋雨感懷','陳淵','宋','宋诗','song-poetry','','[]','一別劍谿水，三換京塵秋。',96,'全唐诗/poet.song.93000.json','["一別劍谿水，三換京塵秋。", "夜聽空階雨，歲月驚如流。", "豈不念故國，水清山亦幽。", "螻蟻有微情，未忍追浮丘。", "平生老蒼交，夫子賢其尤。", "窮經三十年，一字不見收。", "賴有管城公，落紙無全牛。", "他時恐不免，速達吾所羞。"]'),
('96739f24-5866-4672-9d35-79406b47b479','代句龍君輔上潼州令','陳淵','宋','宋诗','song-poetry','','[]','卓魯當時事，風流莫與班。',120,'全唐诗/poet.song.93000.json','["卓魯當時事，風流莫與班。", "最成三載後，名在兩川間。", "桑梓深聆德，絃歌幸毖頑。", "牛刀淹試可，驥足暫投閑。", "偃室何當造，膺門早許扳。", "丹墀初受命，墨綬遽言還。", "何子方游學，終童未出關。", "梁園今萬里，蜀道自千山。", "籍眼終多白，萊衣念戲斑。", "歸期春服就，潼水會承顔。"]'),
('40d2bdec-576f-4d60-8bb4-d897523ae210','同魏季脩雪中閑步二首  其一','陳淵','宋','宋诗','song-poetry','','[]','纖纖月色淡黄昏，城郭千家雪炤人。',32,'全唐诗/poet.song.93000.json','["纖纖月色淡黄昏，城郭千家雪炤人。", "攜手望春同茗飲，小坊燈火自相親。"]'),
('bdad58a9-8faa-47a2-827c-b75027f0a266','同魏季脩雪中閑步二首  其二','陳淵','宋','宋诗','song-poetry','','[]','草草瑶池小宴終，玉人招我廣寒宫。',32,'全唐诗/poet.song.93000.json','["草草瑶池小宴終，玉人招我廣寒宫。", "歸來懷袖天香滿，月照梅梢雪未融。"]'),
('f77e7348-1850-4943-b0d6-6667c835a939','次韻俞德翁述懷二首  其一','陳淵','宋','宋诗','song-poetry','','[]','事業無媒祗漫勞，平生於世一牛毛。',32,'全唐诗/poet.song.93000.json','["事業無媒祗漫勞，平生於世一牛毛。", "三年萬里看飛雪，不向人前愧緼袍。"]'),
('ceddcb7c-1605-46c9-be2e-a7453d1ebf3f','次韻俞德翁述懷二首  其二','陳淵','宋','宋诗','song-poetry','','[]','飄泊天涯不繫舟，又還窮臘動離愁。',32,'全唐诗/poet.song.93000.json','["飄泊天涯不繫舟，又還窮臘動離愁。", "軒裳瑣瑣知何者，直自時平未肯休。"]'),
('2aa37ee0-3a91-4945-8ecc-aa7460044731','寄內','陳淵','宋','宋诗','song-poetry','','[]','去住初難料，行藏只是嫌。',48,'全唐诗/poet.song.93000.json','["去住初難料，行藏只是嫌。", "天高山簇劍，江靜月磨鎌。", "久别平安否，新愁覺夢兼。", "雙魚何日寄，迢遞歲將淹。"]'),
('03a3a983-0272-4f5b-81f0-302c2c6a01fa','春雪','陳淵','宋','宋诗','song-poetry','','[]','陰風度嚴切，密雪紛如霧。',72,'全唐诗/poet.song.93000.json','["陰風度嚴切，密雪紛如霧。", "虚窗覺逾明，臘紙粘飛絮。", "文書不掛眼，對榻聊箕踞。", "春愁暗乘人，匆匆出非慮。", "門前亦有酒，官禁不可酤。", "永懷傲江湖，何當脱羈馵。"]'),
('a61deea9-02c6-406b-8752-03c74d3eda40','歲暮述懷寄安常兄','陳淵','宋','宋诗','song-poetry','','[]','意廣詩餘怨，才狂酒見真。',48,'全唐诗/poet.song.93000.json','["意廣詩餘怨，才狂酒見真。", "雪梅新濺淚，霜月冷傷神。", "短劍深藏匣，哀絃久委塵。", "良游惜遲暮，雲物又驚春。"]'),
('87887135-aaa0-4f2d-a71c-0baecb67dcf6','三月十一日欲往荆南景德寺睡起呈曹令德','陳淵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','風門自開闔，門外黄塵暮。',120,'全唐诗/poet.song.93000.json','["風門自開闔，門外黄塵暮。", "午衾温留人，春夢如飛絮。", "我行指洞庭，千里始頓屨。", "僕夫呼起起，寸心撮百慮。", "此生睡不足，正坐奔馳故。", "四年四往來，日月途中度。", "美人亦念我，贈以别知賦。", "英辭粲星斗，深語發妙悟。", "坐起再三讀，一一明月句。", "何似謝所投，靜黙有佳趣。"]'),
('8fefe84b-ec6e-4b00-880a-efb987d5e0f0','令德送余都門外眷眷惜别余恨不款作詩寄之','陳淵','宋','宋诗','song-poetry','','[]','行人不忍别，遇酒輒醉倒。',120,'全唐诗/poet.song.93000.json','["行人不忍别，遇酒輒醉倒。", "僕夫怪何遲，謬應行亦好。", "憐君如弟兄，每見開懷抱。", "天涯重分攜，祖席都門道。", "城頭傾落日，酒盡迹還掃。", "留連意雖勤，晤語終草草。", "君如汗血駒，千里未脱皁。", "我若隨波魚，圉圉依寒藻。", "去住各有謀，聚散初不保。", "惟餘一寸心，耿耿遲君老。"]'),
('445bcc3b-df18-4f23-9227-d91715c6ad7d','同楊遵道出京本欲作詩而吟咏久廢恐取道襄陽吊古遺迹遵道有作不能多繼也先以詩謝之','陳淵','宋','宋诗','song-poetry','','[]','經年不作詩，意到無好語。',204,'全唐诗/poet.song.93000.json','["經年不作詩，意到無好語。", "强欲理短綆，頽井暗塵土。", "夫子賢達流，奔逸不受圉。", "風流夢鱣後，清德逼而祖。", "文章守家法，騷雅到前古。", "屈宋或交綏，曹劉真臭乳。", "而我獨何人，詞格本寒苦。", "枯腸費搜攪，况復久不吐。", "胡爲謬見假，亦使郊繼愈。", "無乃緣葭莩，遂與噲等伍。", "此行過襄陽，倒指不旬數。", "龐公亦安之，孟子不可覩。", "聲名向千載，石刻餘羊杜。", "山川空形勝，耆舊一仰俯。", "終當吊遺迹，尊酒酹江滸。", "恐君成感慨，嚴韻儻見侮。", "作詩謝不能，亦以丐斤斧。"]'),
('574e5c6a-baf2-4561-ab72-ab697635eec7','十五日過許夜雨暴作明日行四十里宿於穎橋又明日晴書時','陳淵','宋','宋诗','song-poetry','','[]','狂風撼平野，沙礫眯兩目。',168,'全唐诗/poet.song.93000.json','["狂風撼平野，沙礫眯兩目。", "筍輿我與君，道遠疲徵逐。", "驚雷一夜發，暴雨溢川谷。", "平明泥没趾，寸步不容續。", "我生賦窮蹇，觸處背天福。", "風雨豈不好，行路非所欲。", "中途聊息肩，村驛便可宿。", "我勞固其分，端恐僵僮僕。", "燎爐燃濕薪，傍舍酒初熟。", "安能浣愁腸，但取充饑腹。", "中宵耿不眠，明月忽挂屋。", "攬衣起視夜，秣馬亦膏轂。", "人情易喜愠，天道有飜覆。", "陰霽那可知，去去無欲速。"]'),
('f76781de-7ec5-4b44-ae73-2e0d39df789a','汝州道中呈遵道','陳淵','宋','宋诗','song-poetry','','[]','青煙漠漠柳依依，落日雲中雁北飛。',64,'全唐诗/poet.song.93000.json','["青煙漠漠柳依依，落日雲中雁北飛。", "咄咄書空誰的會，遲遲行道子同歸。", "桑陰蓋地牛羊困，麥秀漫山鳥雀肥。", "向晚未知投宿處，敗籬疏屋火煙微。"]'),
('22fefe93-42ab-47ca-9eb9-10a61ee926d2','承遵道和又用前韻書懷','陳淵','宋','宋诗','song-poetry','','[]','端的荆州得所依，羽翰終欲更南飛。',64,'全唐诗/poet.song.93000.json','["端的荆州得所依，羽翰終欲更南飛。", "閩山萬里長牽夢，蜀鳥千言只喚歸。", "當日朋儕俱草澤，而今兒女自輕肥。", "白雲南望三年客，長是尊前誦式微。"]'),
('fbe8163d-2d5a-4c0d-8380-e408a59ec175','春晚書事','陳淵','宋','宋诗','song-poetry','','[]','楊花撲面春如夢，麥穗齊腰日似年。',32,'全唐诗/poet.song.93000.json','["楊花撲面春如夢，麥穗齊腰日似年。", "多病不緣詩得瘦，放懷全藉酒能仙。"]'),
('f9ca02ed-a761-411c-90a6-e5923519cec7','楊花二首  其一','陳淵','宋','宋诗','song-poetry','','[]','出處陶潛宅，興亡煬帝堤。',48,'全唐诗/poet.song.93000.json','["出處陶潛宅，興亡煬帝堤。", "窗扉容點綴，原野自高低。", "地迥棲難穩，風高去易迷。", "顛忙能幾日，萍滿水東西。"]'),
('bd2fee6b-7250-4e8b-9006-22c5cb275fc5','楊花二首  其二','陳淵','宋','宋诗','song-poetry','','[]','漫天方作雪，糝徑忽鋪氊。',24,'全唐诗/poet.song.93000.json','["漫天方作雪，糝徑忽鋪氊。", "已是春如酒，那堪爾似綿。"]'),
('c38d3d39-2715-4a50-aba7-0849f4a4ca26','木香花二首  其一','陳淵','宋','宋诗','song-poetry','','[]','翠袖青裙襯雪膚，雨餘終日醉相扶。',32,'全唐诗/poet.song.93000.json','["翠袖青裙襯雪膚，雨餘終日醉相扶。", "祗應不使朱鉛汙，獨抱幽香與世疏。"]'),
('ea5a38d1-a89c-48d8-a0e8-ed167c678f02','木香花二首  其二','陳淵','宋','宋诗','song-poetry','','[]','直自江梅墮雪英，便遲幽艶到清明。',32,'全唐诗/poet.song.93000.json','["直自江梅墮雪英，便遲幽艶到清明。", "楊花著地香初破，乞與愁人一解酲。"]'),
('749c1bf3-9fa4-4892-bcb2-908149a9581b','自入襄城即有山水之興路中稍有賡唱因呈遵道','陳淵','宋','宋诗','song-poetry','','[]','風沙久迷神，山水忽照眼。',144,'全唐诗/poet.song.93000.json','["風沙久迷神，山水忽照眼。", "粼粼碧玉甃，叠叠青螺綰。", "人煙盛樂土，草樹亦精産。", "雲霞入杳冥，禽鳥度盃醆。", "放情千里迥，悟意一笑莞。", "胸襟得奇趣，酬唱出新撰。", "蟲魚怯嘲誚，文史困鳩僝。", "我詩實易成，淡薄非佳饌。", "君詞頗簡出，嚴絕類燒棧。", "自應即退縮，强爾取驚赧。", "微言固可錄，狂論猶未剗。", "勿使俗人知，歸途畏書簡。"]'),
('710b578c-1357-4651-b34c-8e7d1cca49d5','和遵道楊花','陳淵','宋','宋诗','song-poetry','','[]','金明池道綠陰稠，萬點顛忙正可愁。',32,'全唐诗/poet.song.93000.json','["金明池道綠陰稠，萬點顛忙正可愁。", "馬上只貪看舞雪，不知飛滿帽簷毬。"]'),
('f40f6e2f-0e64-4f19-b8bb-0efdea4ab422','漫興','陳淵','宋','宋诗','song-poetry','','[]','雲林恰恰鶯能友，沙路行行蟻有臣。',32,'全唐诗/poet.song.93000.json','["雲林恰恰鶯能友，沙路行行蟻有臣。", "雖有溪山供醉眼，亦嫌塵土汙芳春。"]'),
('e4aece53-7ff8-4bf4-abbe-5987d310c280','登峴山二首  其一','陳淵','宋','宋诗','song-poetry','','[]','五百年間一夢中，登臨回首興何窮。',64,'全唐诗/poet.song.93000.json','["五百年間一夢中，登臨回首興何窮。", "當時事業軒天起，此日風流掃地空。", "墮淚山頭春草長，沉碑江上晚煙濛。", "故令倦客成惆悵，目斷斜陽不忍東。"]'),
('172b09b6-bb3f-4048-a55a-24d10e38caf8','登峴山二首  其二','陳淵','宋','宋诗','song-poetry','','[]','路過青山曲轉腰，松門楸嶺背塵囂。',64,'全唐诗/poet.song.93000.json','["路過青山曲轉腰，松門楸嶺背塵囂。", "煙雲西望孤鴻没，舟楫東來一水朝。", "忠義有懷空鬱鬱，功名餘事漫寥寥。", "無人就與山西將，緩带輕裘敵自消。"]'),
('a39fb7db-0008-4c46-84bf-8b5f66b01001','晚行','陳淵','宋','宋诗','song-poetry','','[]','晚煙低掃樹千重，一簇人家接遠空。',32,'全唐诗/poet.song.93000.json','["晚煙低掃樹千重，一簇人家接遠空。", "日暮荒陂行客盡，只尋牛迹去匆匆。"]'),
('9f104f0a-0e3a-4f56-a842-bb8ca089e623','懷鄧南夫','陳淵','宋','宋诗','song-poetry','','[]','丈室經年疏玉麈，數行何日寄銀鈎。',32,'全唐诗/poet.song.93000.json','["丈室經年疏玉麈，數行何日寄銀鈎。", "只應立我軒前柳，滿眼飛綿綠正稠。"]'),
('ab0b8196-59e1-4b96-b53c-5e1a43378bd5','思安常兄','陳淵','宋','宋诗','song-poetry','','[]','凌虚閣下煙波闊，升俊坊前草木香。',32,'全唐诗/poet.song.93000.json','["凌虚閣下煙波闊，升俊坊前草木香。", "歸去溪南春正好，不應蕭索對松篁。"]'),
('e30d3656-dec4-4d26-b8d9-95a869f46ed4','春晚入荆州','陳淵','宋','宋诗','song-poetry','','[]','綠樹連雲草濕煙，亂花飄錦柳飛綿。',64,'全唐诗/poet.song.93000.json','["綠樹連雲草濕煙，亂花飄錦柳飛綿。", "三春别我無多日，萬點愁人又一年。", "池館勝游空過眼，江山佳處欲投鞭。", "從君預覓清涼地，准備南州五月天。"]'),
('150b6fa1-5f2e-4944-8d9d-41a0f6e96509','早行','陳淵','宋','宋诗','song-poetry','','[]','夢中聞得子規啼，燈下驚呼馬亦嘶。',64,'全唐诗/poet.song.93000.json','["夢中聞得子規啼，燈下驚呼馬亦嘶。", "宿霧故迷山遠近，肩輿才辨路高低。", "鷄鳴犬吠遥相應，野草幽花自不齊。", "待得晨光開霽色，不知行道幾人迷。"]'),
('9e056bc8-0e47-4033-a30f-84c93f8116cc','京師相善者鄉友四人各賦一篇以見其所慕 適正','陳淵','宋','宋诗','song-poetry','','[]','淡薄不易親，和平不可離。',48,'全唐诗/poet.song.93000.json','["淡薄不易親，和平不可離。", "平生一樽酒，萬事醒復醉。", "詩成稾不存，物至情無累。", "紛紛塵俗中，笑裏有真意。"]'),
('8da35b99-f970-4c60-ad4e-3d202a6a3405','京師相善者鄉友四人各賦一篇以見其所慕 載德','陳淵','宋','宋诗','song-poetry','','[]','辭寡覺我喧，氣定覺我煩。',48,'全唐诗/poet.song.93000.json','["辭寡覺我喧，氣定覺我煩。", "沉吟孤鶴立，戲謔陽春温。", "豈不苦鞭策，去馬終戀軒。", "由來君子德，寡怨非其恩。"]'),
('254685fa-0c51-4479-8b55-0c9d98f688fd','京師相善者鄉友四人各賦一篇以見其所慕 如愚','陳淵','宋','宋诗','song-poetry','','[]','義重財自輕，氣剛語還直。',48,'全唐诗/poet.song.93000.json','["義重財自輕，氣剛語還直。", "毁譽不掛懷，行坐頗自得。", "浮生困局蹙，世路亦艱棘。", "思君膽如斗，解我愁似織。"]'),
('f9afce8f-ddaa-455f-9974-e0e3ccf9653e','京師相善者鄉友四人各賦一篇以見其所慕 令德','陳淵','宋','宋诗','song-poetry','','[]','襟懷冬日温，容貌秋水淨。',48,'全唐诗/poet.song.93000.json','["襟懷冬日温，容貌秋水淨。", "惠然肯顧我，蒹葭玉相映。", "詩人固難肥，酒客亦多病。", "善保千金軀，愛子清而勁。"]'),
('5b73afd5-2a0d-4805-93f6-c02ccb3ce9af','至荆州寄用中','陳淵','宋','宋诗','song-poetry','','[]','前年攜手東水門，秋月夜看黄流奔。',192,'全唐诗/poet.song.93000.json','["前年攜手東水門，秋月夜看黄流奔。", "匆匆别話苦不盡，鳴鷄吠犬催朝暾。", "放船鎖外望回騎，清淚滴滴如泉源。", "飄零可念浪萍散，得喪未把秋毫論。", "閩山萬疊阻歸計，越國半年空斷魂。", "朅來璧水就朋友，聞子荆渚將魚軒。", "尺書迢遞忽寄我，消息久絕知生存。", "妻孥同活似慰意，伏臘不給誰可言。", "但期君馬當北首，豈謂我轡今南轅。", "客鄉邂逅不易得，想見妙語如春温。", "况聞邇來治經術，蟲魚瑣細窮朝昏。", "傾嚢倒廪幸見□，不須羞澀時所尊。"]'),
('5c6e9d61-6445-4fa1-93cb-b403c6e7dea4','用中既和成以示山口唐藴明藴明亦和再用前韻呈二公','陳淵','宋','宋诗','song-poetry','','[]','高城繚繞環居門，草樹蔽日鼪鼯奔。',192,'全唐诗/poet.song.93000.json','["高城繚繞環居門，草樹蔽日鼪鼯奔。", "疏篁轉影涼午枕，卧看鳥雀嬉晴暾。", "清香一縷爇沉水，濃茗十分烹壑源。", "乘風欲效玉川子，蓬莱無路心難論。", "虚堂愁坐漠無語，頃刻百慮空勞魂。", "緬懷皇祐賢御史，當日直氣何軒軒。", "臧孫强諫宜有後，奇士果見諸孫存。", "流傳佳語忽到我，展卷疾讀皆微言。", "平生廖子口如鐵，肯爲此友西其轅。", "故應目擊得深省，千載無愧孔與温。", "更將餘力事酬唱，巧注未以黄金昏。", "古來求友貴勝己，二子年德皆吾尊。"]'),
('78296a65-30be-463b-b0ca-aac318a67ade','容齋書事二首  其一','陳淵','宋','宋诗','song-poetry','','[]','南國餘梅潤，東墻更竹陰。',48,'全唐诗/poet.song.93000.json','["南國餘梅潤，東墻更竹陰。", "門庭迂市井，草樹似山林。", "客寄吾家是，齋居古意深。", "微風過枕簟，何有萬黄金。"]'),
('acb73b41-ac75-4e6c-9e35-5cc16cf54beb','容齋書事二首  其二','陳淵','宋','宋诗','song-poetry','','[]','方丈孤城角，風來夢亦醒。',48,'全唐诗/poet.song.93000.json','["方丈孤城角，風來夢亦醒。", "分明更無事，俯仰忽忘形。", "小室塵誰掃，空亭柏自青。", "生涯任流轉，天地一浮萍。"]'),
('84bdcce5-10b5-4d04-83b9-d3f7cb8e4b8c','和向和卿嘗茶','陳淵','宋','宋诗','song-poetry','','[]','俗子醉紅裙，羶葷敗人意。',120,'全唐诗/poet.song.93000.json','["俗子醉紅裙，羶葷敗人意。", "花甆烹月團，此樂天不畀。", "諸公各英姿，淡薄得真味。", "聊爲下季隱，不替江湖思。", "輕雲落杯醆，飛雪灑腸胃。", "笑談出冰玉，毫末視鼎貴。", "我作月旦評，全勝家置喙。", "傳聞茶後詩，便得古人配。", "誰能三百餅，一洗玉川睡。", "御風歸蓬萊，高論驚兒輩。"]'),
('d5898bfa-e7a3-41d3-92f1-0f76528d30a7','寄謝用中','陳淵','宋','宋诗','song-poetry','','[]','黄蘗無多法，維摩不二門。',48,'全唐诗/poet.song.93000.json','["黄蘗無多法，維摩不二門。", "此間堪折柱，吾道亦難言。", "學者初何有，師乎貴不煩。", "十年成我志，今日是君恩。"]'),
('91730947-fd83-4a7d-b9e3-b5ea6729d4d7','得用中書有禮人不答之悔作詩解之','陳淵','宋','宋诗','song-poetry','','[]','一時先達揔飄零，亦有陽春世莫聽。',64,'全唐诗/poet.song.93000.json','["一時先達揔飄零，亦有陽春世莫聽。", "漫刺從來無處着，曳裾今日欲誰經。", "只應舊友頭空白，難使新知眼便青。", "射獵南山休夜出，灞陵有尉宿君亭。"]'),
('a15ad19a-0fd2-4525-8451-8ebc93a7bf80','送遵道','陳淵','宋','宋诗','song-poetry','','[]','秋月隔疏簾，光體終隱微。',96,'全唐诗/poet.song.93000.json','["秋月隔疏簾，光體終隱微。", "捲簾試寓目，萬里餘清輝。", "人生異肝胆，同一造化機。", "君心乃余心，南北非相違。", "三年遲君來，一見悟前非。", "况乃度寒暑，葭玉容相依。", "與君忘年交，没齒其庶幾。", "月色亦良好，君胡捐我歸。"]'),
('c5ce19a8-e8eb-4f6b-8b83-e3ecb3fbc414','陳漕生辰','陳淵','宋','宋诗','song-poetry','','[]','六管陽初復，前宵月尚圓。',168,'全唐诗/poet.song.93000.json','["六管陽初復，前宵月尚圓。", "長庚俄夢李，崧岳故興宣。", "膚使新恩數，忠臣夙眷偏。", "節龍開遠目，衣綉聳華年。", "日月聲名起，風雷號令傳。", "自應威動岳，曾是力回天。", "相國關中粟，尚書地上錢。", "委藏淹府庫，飛輓亂車船。", "南獠元歸地，西方正拓邊。", "定知新將飽，尤賴我公賢。", "赫赫蘭臺舊，飄飄鳳沼仙。", "終焉還魏闕，聊亦駐荆川。", "曲學聯珠履，非才汙彩牋。", "千秋期鶴壽，萬里附鵬騫。"]'),
('b9e16b32-da27-435c-bf41-e054d297751e','席提舉生辰','陳淵','宋','宋诗','song-poetry','','[]','朔風迎臘換堯蓂，一葉階前尚吐英。',64,'全唐诗/poet.song.93000.json','["朔風迎臘換堯蓂，一葉階前尚吐英。", "天上麒麟來昨夢，河東鸑鷟自時名。", "錦衣故國今誰有，棣萼中朝日更榮。", "終上青冥環坐座，弧南長並一星明。"]'),
('25b973b1-0c36-4dde-b478-7a1fb0150af3','入荆州學四絕句呈昭祖  其一','陳淵','宋','宋诗','song-poetry','','[]','問舍求田不可遲，十年羈落意多違。',32,'全唐诗/poet.song.93000.json','["問舍求田不可遲，十年羈落意多違。", "須知澤雉樊中畜，不及蓬鳩地上飛。"]'),
('ed8b21d3-880b-42d1-bfa8-937778818034','入荆州學四絕句呈昭祖  其二','陳淵','宋','宋诗','song-poetry','','[]','拂天喬木映脩廊，滿目簾間白苧忙。',32,'全唐诗/poet.song.93000.json','["拂天喬木映脩廊，滿目簾間白苧忙。", "曾是璧池疏散慣，卧聽鳴鼓懶衣裳。"]'),
('f93a9641-049d-4623-a86c-5c3b7dbcb3f8','入荆州學四絕句呈昭祖  其三','陳淵','宋','宋诗','song-poetry','','[]','短柏森森團積雪，疏篁簌簌撼微風。',32,'全唐诗/poet.song.93000.json','["短柏森森團積雪，疏篁簌簌撼微風。", "從前不道容齋好，此景而今落夢中。"]'),
('ff79754b-676c-433e-b8a6-79d84fea82ab','入荆州學四絕句呈昭祖  其四','陳淵','宋','宋诗','song-poetry','','[]','明知安分即忘歸，故倚春風看落暉。',32,'全唐诗/poet.song.93000.json','["明知安分即忘歸，故倚春風看落暉。", "叔度汪汪波萬頃，未應如我苦懷歸。"]'),
('865e6994-541b-4d5a-a417-1cd33291d242','金鑾兩絕  其一','陳淵','宋','宋诗','song-poetry','','[]','雨過窗明夏簟虚，紛紛鳥雀靜庭除。',32,'全唐诗/poet.song.93000.json','["雨過窗明夏簟虚，紛紛鳥雀靜庭除。", "維摩丈室無人問，一枕薰風聽粥魚。"]'),
('18f66e5e-e9f0-46ac-90a1-2c163aa4ae35','金鑾兩絕  其二','陳淵','宋','宋诗','song-poetry','','[]','門外塗泥一尺深，高車誰復更幽尋。',32,'全唐诗/poet.song.93000.json','["門外塗泥一尺深，高車誰復更幽尋。", "不因雨後看亭柏，安得山僧數見臨。"]'),
('4580f71e-b7a3-4849-b983-f7cf8bb0fee1','次韻楊丈夜寒直舍  其一','陳淵','宋','宋诗','song-poetry','','[]','天寒官舍轉騷騷，敗壁饑蟲永夜號。',64,'全唐诗/poet.song.93000.json','["天寒官舍轉騷騷，敗壁饑蟲永夜號。", "應對短檠呵凍手，只將長卷掃冰毫。", "官游久矣空環轍，生事蕭然孰載醪。", "亦有從前經國意，拔賢人或望山濤。"]'),
('2fad2aeb-0e7b-4276-9d5f-d977ec1dc21d','次韻楊丈夜寒直舍  其二','陳淵','宋','宋诗','song-poetry','','[]','鑾輅鹽車等是勞，便逢良樂肯鳴號。',64,'全唐诗/poet.song.93000.json','["鑾輅鹽車等是勞，便逢良樂肯鳴號。", "秪應末路歌牛角，不及寒窗禿兔毫。", "世事分明如昨夢，人情端的勝春醪。", "終當短艇從公去，俯仰江湖戲怒濤。"]'),
('211ad3c9-0c11-4836-8c32-2a0688cb4a8a','春日偶題','陳淵','宋','宋诗','song-poetry','','[]','未可郊原縱曉鞍，人間猶似有輕寒。',32,'全唐诗/poet.song.93000.json','["未可郊原縱曉鞍，人間猶似有輕寒。", "春光不似常年短，過了清明更好看。"]'),
('a861d4e3-0145-4f3e-8ff8-446e5a8761a9','次韻張從道三首 石首道中','陳淵','宋','宋诗','song-poetry','','[]','匹馬江村路，長鞭短袂裘。',48,'全唐诗/poet.song.93000.json','["匹馬江村路，長鞭短袂裘。", "問民知所病，驅御去如流。", "霧卷千山曉，霜餘萬木秋。", "古来奔走吏，流落有奇謀。"]'),
('9f42265d-aa51-445c-9534-97a8b00089b4','次韻張從道三首 自建寧泛江至石首','陳淵','宋','宋诗','song-poetry','','[]','江注天圍盡，舟排浪陣輕。',48,'全唐诗/poet.song.93000.json','["江注天圍盡，舟排浪陣輕。", "岸容疏柳色，秋氣斷鴻聲。", "風日雖堪愛，雲煙易妒晴。", "鱸魚如有興，好在未知名。"]'),
('9a0fe656-ebd0-4c0c-9037-30d0bc139aa6','次韻張從道三首 月夜江行','陳淵','宋','宋诗','song-poetry','','[]','吏隱飄然在一涯，更堪行役退年華。',32,'全唐诗/poet.song.93000.json','["吏隱飄然在一涯，更堪行役退年華。", "多情却有空江月，長伴離人夢到家。"]'),
('5cdc8747-97b7-468c-958a-247ec8402f20','次韻從道夜宿推院','陳淵','宋','宋诗','song-poetry','','[]','誰遣參軍阨所長，夜聽鈴鼓度修廊。',64,'全唐诗/poet.song.93000.json','["誰遣參軍阨所長，夜聽鈴鼓度修廊。", "風流偶未逢狂客，歌頌空驚逼漫郎。", "莫恨驊騮縻皁櫪，要令松柏飽冰霜。", "如聞委吏真勞擾，不許歸田是孔方。"]'),
('1c27a80c-8703-43cd-ae2a-0193dd14bcea','送昭遠兼寄昭祖諸友','陳淵','宋','宋诗','song-poetry','','[]','離腸如亂絲，欲解紛無緒。',216,'全唐诗/poet.song.93000.json','["離腸如亂絲，欲解紛無緒。", "别話似泉源，袞袞日夜注。", "幾年見君文，萬里偶相聚。", "一日不易得，矧茲寒暑度。", "孤雲向北飛，三鳳各南騖。", "人生類泛梗，後約亦何據。", "傷心璧池東，塵土暗歸路。", "憑高極遠目，不見籃輿去。", "君如千里駒，奔放尤難御。", "强使就檢繩，不入駑駘步。", "何當宴瑶池，定欲求飛兔。", "鹽車未可嘶，俛首且羈馵。", "余生易語言，開口初莫慮。", "一從摩詰遊，便省黙黙處。", "何時遂攜孥，入隱高山霧。", "招君賢昆季，靜坐契深悟。", "濁醪聊共傾，清境煩君賦。", "况有林下人，解道因風絮。"]'),
('920eb553-a293-4934-b37a-53191851c691','寄內','陳淵','宋','宋诗','song-poetry','','[]','明月向人圓，愛之不忍睡。',96,'全唐诗/poet.song.93000.json','["明月向人圓，愛之不忍睡。", "坐久風露寒，忽忽心如醉。", "念君一適我，所遇無歡意。", "况乃久别離，相思到夢寐。", "我生百不堪，繆學屠龍技。", "于今半世人，升斗亦未遂。", "賴有室中友，素懷隱居志。", "肯與梁伯鸞，扁舟共東逝。"]'),
('174b36ec-f475-480a-86c9-e97b1fb8265f','奉酬楊達甫見贈','陳淵','宋','宋诗','song-poetry','','[]','春風不世情，暖入閑門草。',120,'全唐诗/poet.song.93000.json','["春風不世情，暖入閑門草。", "君詩其似之，披拂逮枯槁。", "平生金石友，歲晚迹如掃。", "一見楊夫子，胸腹便傾倒。", "間關六年别，一字寄不早。", "忽蒙錦繡贈，光彩照龍藻。", "嗟我獨何人，揖我謂我好。", "無乃嗜好偏，收拾到羊棗。", "從來詩人窮，君亦行此道。", "我欲從君遊，山林不知老。"]'),
('8c9f07b5-dc9f-40b4-98ab-1bbdcabf76c1','小軒觀月呈興宗叔','陳淵','宋','宋诗','song-poetry','','[]','茅簷手可攀，修竹出簷上。',144,'全唐诗/poet.song.93000.json','["茅簷手可攀，修竹出簷上。", "寒蟾漏疏明，碎影羅屏障。", "情知月色好，達覽在虚曠。", "東家富池臺，端坐不能訪。", "山林足寓目，細大初無相。", "但使人心安，景物自清暢。", "霜風中夜作，曲沼金飜浪。", "禽鳥斷飛鳴，杉松起酬唱。", "燎爐宿殘火，尚可温新釀。", "數盃遣沉冥，萬慮一時放。", "誰能外形骸，於世無所仰。", "晤語一亭間，頽然齊得喪。"]'),
('b081053c-ff89-4618-b56d-d831e4f43b6d','流長亭','陳淵','宋','宋诗','song-poetry','','[]','江拆亂山圍，西來素練飛。',48,'全唐诗/poet.song.93000.json','["江拆亂山圍，西來素練飛。", "嵐光環石窆，潭影漾松扉。", "欲盡風前樹，難忘草上暉。", "但期流澤遠，長與水東歸。"]'),
('9d08b513-5ce4-46ed-a23e-b3accb552f71','再用送昭遠詩韻寄昭遠昆仲','陳淵','宋','宋诗','song-poetry','','[]','六經學不傳，誰能尋墜緒。',216,'全唐诗/poet.song.93000.json','["六經學不傳，誰能尋墜緒。", "君家有師承，不數虫魚注。", "公子韋氏門，粲若五星聚。", "胸中容萬頃，一一黄叔度。", "人情悦紛華，世路爭馳騖。", "取樂須臾間，轉首已失據。", "余生末俗中，蚤幸識夷路。", "折桂從乃翁，頻年麾不去。", "冉有豈辭僕，樊遲亦能御。", "雍容荆渚間，夫子步亦步。", "初從言下入，筌蹄索魚兔。", "終遂義中行，良樂驅騏馽。", "有時坐終夕，收視息浮慮。", "了了不可言，明明有佳處。", "别來能幾時，心月翳雲霧。", "諸郎幸不遠，寄語多予悟。", "坐爲塵事攖，空詠別知賦。", "遥想玉華遊，春夢如飛絮。"]'),
('2876446b-159a-46c8-90b2-ec5861c88964','小軒閑題二首  其一','陳淵','宋','宋诗','song-poetry','','[]','舍南舍北梅，墻裏墻外竹。',96,'全唐诗/poet.song.93000.json','["舍南舍北梅，墻裏墻外竹。", "逌然寄其間，不見一物俗。", "東風將小雨，夜漲春池綠。", "俯檻數龜魚，仰簷送鴻鵠。", "交情石投水，坐客冰炤玉。", "從容得此生，已矣萬事足。", "誰言南軒小，正可陋華屋。", "但恐世故攖，不容長處獨。"]'),
('12bc084e-579c-49fc-a21f-008fa6ee5eda','小軒閑題二首  其二','陳淵','宋','宋诗','song-poetry','','[]','青山拱簷楹，淥水鑒毛髪。',96,'全唐诗/poet.song.93000.json','["青山拱簷楹，淥水鑒毛髪。", "花香晚更清，鳥語靜不聒。", "客至不能飲，舉觴聊自罰。", "坐嘯激清風，起舞弄明月。", "是身如浮漚，起滅在溟渤。", "百年一彈指，何者爲不没。", "文章會消磨，名譽易衰歇。", "淵明吾之師，茲理久已達。"]'),
('96bd55ff-4099-497d-b188-603c83b4917d','約令德郊行二首  其一','陳淵','宋','宋诗','song-poetry','','[]','簷前搖風拂面低，麥芽穿雪綠齊齊。',32,'全唐诗/poet.song.93000.json','["簷前搖風拂面低，麥芽穿雪綠齊齊。", "憑君便作遊春計，莫待花繁去路迷。"]'),
('1824d6a8-facf-4135-80fa-ced23e1c5a2c','約令德郊行二首  其二','陳淵','宋','宋诗','song-poetry','','[]','小雪纖纖蓋地皮，一飜風過忽成泥。',32,'全唐诗/poet.song.93000.json','["小雪纖纖蓋地皮，一飜風過忽成泥。", "東君似勸人行樂，不使塵埃趁馬蹄。"]'),
('4a951ebd-b9d7-4805-b1ec-ffbcb8ab5df2','酬晏伯達','陳淵','宋','宋诗','song-poetry','','[]','半生流轉任飛篷，萬里歸來興又東。',64,'全唐诗/poet.song.93000.json','["半生流轉任飛篷，萬里歸來興又東。", "寂寞倦投揚子宅，低徊却寄魯侯宫。", "阻尋雞黍他年約，長憶園林一醉同。", "何日過君花下飲，爛看濃艶舞春風。"]'),
('a1bac5b8-4599-4f59-b209-2eddbc828dfb','錢塘書懷二首  其一','陳淵','宋','宋诗','song-poetry','','[]','遠客真秦贅，清時謝楚狂。',48,'全唐诗/poet.song.93000.json','["遠客真秦贅，清時謝楚狂。", "斑衣辭故國，青佩久殊方。", "世俗蠻爭觸，余生穀似臧。", "正須逃姓字，毋使異庚桑。"]'),
('0d33ad89-b117-4217-8a7b-d8ba81e45ec1','錢塘書懷二首  其二','陳淵','宋','宋诗','song-poetry','','[]','客舍連朝雨，春愁醉夢如。',48,'全唐诗/poet.song.93000.json','["客舍連朝雨，春愁醉夢如。", "白雲千里目，黄犬萬金書。", "所幸交情薄，從來世事疏。", "只應狼疐尾，空自詠歸歟。"]'),
('9dd6f066-98b6-4305-aff6-680a48febb01','錢塘學中寄伯思六言五首  其一','陳淵','宋','宋诗','song-poetry','','[]','門外鶯驚短夢，窗間雨送清寒。',28,'全唐诗/poet.song.93000.json','["門外鶯驚短夢，窗間雨送清寒。", "亦有惜春情緒，分明不奈花殘。"]'),
('91297445-a903-4d62-876b-0fc9398bf64c','錢塘學中寄伯思六言五首  其二','陳淵','宋','宋诗','song-poetry','','[]','點點榆錢委砌，冥冥柳絮穿簾。',28,'全唐诗/poet.song.93000.json','["點點榆錢委砌，冥冥柳絮穿簾。", "日暖野禽爭食，紛綸忽墮危簷。"]'),
('9abb6b3b-0d7b-4d7f-9ee1-cb20a1268595','錢塘學中寄伯思六言五首  其三','陳淵','宋','宋诗','song-poetry','','[]','劍水庭闈底處，苕溪水月彌深。',28,'全唐诗/poet.song.93000.json','["劍水庭闈底處，苕溪水月彌深。", "綠草年年離恨，白雲日日歸心。"]'),
('5ba827b0-41ae-4724-a058-4bee0b3034b1','錢塘學中寄伯思六言五首  其四','陳淵','宋','宋诗','song-poetry','','[]','世路紅塵可厭，人情白首如新。',28,'全唐诗/poet.song.93000.json','["世路紅塵可厭，人情白首如新。", "便可閉門端坐，不須開眼看人。"]'),
('8f2a0d2d-3afe-4f41-b940-2fca00eebe38','錢塘學中寄伯思六言五首  其五','陳淵','宋','宋诗','song-poetry','','[]','部伍亭前歸路，鳳凰山下蕭齋。',28,'全唐诗/poet.song.93000.json','["部伍亭前歸路，鳳凰山下蕭齋。", "我自無聊不住，君如有興重來。"]'),
('685740dd-3ac3-4499-aafa-9d6d3d98a4b6','雪中入國門寄令德三首  其一','陳淵','宋','宋诗','song-poetry','','[]','紛紛輕薄欲誰從，愛子從來臭味同。',32,'全唐诗/poet.song.93000.json','["紛紛輕薄欲誰從，愛子從來臭味同。", "千里遠來應念我，速須鞭馬要從容。"]'),
('771e38ee-638b-453a-9226-46880ef9b633','雪中入國門寄令德三首  其二','陳淵','宋','宋诗','song-poetry','','[]','此生於世已心灰，自笑都城十往來。',32,'全唐诗/poet.song.93000.json','["此生於世已心灰，自笑都城十往來。", "爲有饑寒餘慮在，故應隨俗强低回。"]'),
('30faa643-2cc7-415a-8953-f483f6601148','雪中入國門寄令德三首  其三','陳淵','宋','宋诗','song-poetry','','[]','誰能一飲□千鍾，分付閑愁入酒中。',32,'全唐诗/poet.song.93000.json','["誰能一飲□千鍾，分付閑愁入酒中。", "共向重樓看曉景，一天飛絮舞春風。"]'),
('bae0f9b0-7881-406f-8d90-07d6ed0ae032','下汴','陳淵','宋','宋诗','song-poetry','','[]','參天古柳鳴蟬急，卷地黄流轉岸多。',32,'全唐诗/poet.song.93000.json','["參天古柳鳴蟬急，卷地黄流轉岸多。", "好去扁舟穩扶柂，秋風吹水易揚波。"]'),
('03c0d304-fe90-4cc9-b34f-aaf6757414c2','過淮','陳淵','宋','宋诗','song-poetry','','[]','天高秋月涼，風定秋水清。',72,'全唐诗/poet.song.93000.json','["天高秋月涼，風定秋水清。", "扁舟淮海間，愛此一葉輕。", "微生久覊旅，艱險已飽更。", "經今幾往來，始見波浪平。", "篙師且停櫂，莫遣魚龍驚。", "吾行欲安之，要待東方明。"]'),
('d5c2afa3-9a62-4d1b-8e10-df62a48d27aa','登召伯斗野亭','陳淵','宋','宋诗','song-poetry','','[]','落帆新城曲，維舟古河右。',72,'全唐诗/poet.song.93000.json','["落帆新城曲，維舟古河右。", "幽尋得危亭，星斗穿户牖。", "西風掃殘葉，庭宇不待帚。", "娟娟雲間月，亦復照杯酒。", "明朝又東南，汙流映衰柳。", "莫以此時心，熾然分淨垢。"]'),
('a7f32a92-f8e4-433d-bae3-939a6f3045ef','過浦城贈王令長源二首  其一','陳淵','宋','宋诗','song-poetry','','[]','化龍潭上濯滄浪，夢筆峰前憩小棠。',64,'全唐诗/poet.song.93000.json','["化龍潭上濯滄浪，夢筆峰前憩小棠。", "十載不辭淹簿領，一同聊欲課耕桑。", "經綸未展風霜力，文采空餘錦繡腸。", "莫歎窮荒縻驥足，萬人饑凍要扶傷。"]'),
('869b8cc6-83a7-4a3e-8333-6fad143abcbb','過浦城贈王令長源二首  其二','陳淵','宋','宋诗','song-poetry','','[]','半生流落倦塵埃，聞說英名首重回。',64,'全唐诗/poet.song.93000.json','["半生流落倦塵埃，聞說英名首重回。", "畫虎自慙非妙手，割鷄空復嘆高才。", "北堂戀戀思歸夢，南浦匆匆惜别杯。", "此去山林真已矣，看公雲翮振風雷。"]'),
('90cf5b8a-b986-4129-9915-922eff12271e','題綠波亭','陳淵','宋','宋诗','song-poetry','','[]','南浦江波綠，陽關柳色青。',24,'全唐诗/poet.song.93000.json','["南浦江波綠，陽關柳色青。", "夕陽千古恨，分付短長亭。"]'),
('0111e8c9-07a9-4bbb-a9b3-ea758a0daf63','還舍','陳淵','宋','宋诗','song-poetry','','[]','半生走長途，所冀亦已微。',120,'全唐诗/poet.song.93000.json','["半生走長途，所冀亦已微。", "田園已蕪没，及此徒手歸。", "妻孥攜幼稚，相望天一涯。", "所嗟垂老親，甘旨不得時。", "季妺復未嫁，長姊貧且嫠。", "皇皇三十口，未欲聽所之。", "平生道義交，歲晚無晨炊。", "豈不念我貧，閉户長苦饑。", "高門多自足，我復拙言辭。", "已矣可奈何，顔公猶食糜。"]'),
('594bfebe-d02d-42e7-b1d3-d87b0ecf550a','鄧元孚待制挽詞四首  其一','陳淵','宋','宋诗','song-poetry','','[]','從容紹聖末，直節更誰攀。',48,'全唐诗/poet.song.93000.json','["從容紹聖末，直節更誰攀。", "不見豺當路，懸知虎在山。", "石渠聊試可，江國竟投閑。", "尚冀調金鼎，那知去不還。"]'),
('9c1ecd63-3325-4b8b-b549-6faab2cfcd52','鄧元孚待制挽詞四首  其二','陳淵','宋','宋诗','song-poetry','','[]','永泰君臣分，欽慈母子恩。',48,'全唐诗/poet.song.93000.json','["永泰君臣分，欽慈母子恩。", "淵衷雖有在，孤迹自難論。", "身去朝廷遠，名垂簡策尊。", "秪應延閣命，猶未厭輿言。"]'),
('8da6f853-b95f-4b68-99f6-42e521d56e7d','鄧元孚待制挽詞四首  其三','陳淵','宋','宋诗','song-poetry','','[]','季父恩稽報，平生不自安。',48,'全唐诗/poet.song.93000.json','["季父恩稽報，平生不自安。", "諸郎方未命，猶子遽先官。", "義氣今何在，高風衆所難。", "惜哉耆老逝，閭里欲何觀。"]'),
('a5cfce62-1036-4530-8b48-e196e3cace44','鄧元孚待制挽詞四首  其四','陳淵','宋','宋诗','song-poetry','','[]','越岸方投紱，将回出岫雲。',48,'全唐诗/poet.song.93000.json','["越岸方投紱，将回出岫雲。", "楹間俄夢奠，地下去修文。", "落日川原靜，悲風草樹薰。", "但令千載後，掩涕想餘芬。"]'),
('781cfc41-42c8-4bd3-ada4-aa5452790c22','與楊如愚四首  其一','陳淵','宋','宋诗','song-poetry','','[]','文章初不計工拙，言語何常識重輕。',32,'全唐诗/poet.song.93000.json','["文章初不計工拙，言語何常識重輕。", "不向故人齊物我，一生懷抱爲誰傾。"]'),
('96449900-0f9e-4fd6-9b1b-053103a63d9a','與楊如愚四首  其二','陳淵','宋','宋诗','song-poetry','','[]','半生蹤迹辱泥沙，胸胆初無獻子家。',32,'全唐诗/poet.song.93000.json','["半生蹤迹辱泥沙，胸胆初無獻子家。", "臧穀亡羊俱可念，不須蠻觸故紛拏。"]'),
('bc66f0e0-28b0-45ee-861e-407948044b97','與楊如愚四首  其三','陳淵','宋','宋诗','song-poetry','','[]','十年相見不予疏，亦記平生戲笑無。',32,'全唐诗/poet.song.93000.json','["十年相見不予疏，亦記平生戲笑無。", "縱有伯禽堪寓意，可能終不記狂奴。"]'),
('ffd18bb0-e83e-48d5-8109-1b4c6da4052c','與楊如愚四首  其四','陳淵','宋','宋诗','song-poetry','','[]','谷風凄怨不堪歌，奈此人情世態何。',32,'全唐诗/poet.song.93000.json','["谷風凄怨不堪歌，奈此人情世態何。", "流俗但隨憂樂轉，故人應合起頹波。"]'),
('960b841e-e614-4b1a-b18c-5566d4eee386','存誠齋夏日呈龜山先生二首  其一','陳淵','宋','宋诗','song-poetry','','[]','長者一牀室，先生五柳門。',48,'全唐诗/poet.song.93000.json','["長者一牀室，先生五柳門。", "度人聊示病，觀物欲忘言。", "小圃池臺足，薰風草樹繁。", "杖藜隨處處，歸鳥報黄昏。"]'),
('a53b3109-db9b-491a-932e-fa0fe52e71b7','存誠齋夏日呈龜山先生二首  其二','陳淵','宋','宋诗','song-poetry','','[]','雙檜軒之北，高梧户以南。',48,'全唐诗/poet.song.93000.json','["雙檜軒之北，高梧户以南。", "午陰臨短夢，曉吹落清談。", "鬬老三無喜，嵇生七不堪。", "天涯復相值，此意得重參。"]'),
('7fe2c351-3496-447e-bd40-3834793ff6de','答朱晉老見責不赴會','陳淵','宋','宋诗','song-poetry','','[]','屠龍事業初何有，畫餅聲名不願求。',32,'全唐诗/poet.song.93000.json','["屠龍事業初何有，畫餅聲名不願求。", "春色未闌猶足賞，亂花深處要追遊。"]'),
('b8f1249a-aa2f-479c-8582-8c7a0510bef9','達觀軒','陳淵','宋','宋诗','song-poetry','','[]','林杪飛空出栱枅，登臨高處亂煙迷。',64,'全唐诗/poet.song.93000.json','["林杪飛空出栱枅，登臨高處亂煙迷。", "雲鵬撃水南溟近，霜劍凌空北斗低。", "千里江山圍萬井，一潭風月納雙溪。", "同誰此地呈胸腹，下視囂塵萬不齊。"]'),
('793d25ed-913f-4d83-adca-fc43cb500538','宿仙霞聖仙寺呈伯思子靜二首  其一','陳淵','宋','宋诗','song-poetry','','[]','風物吾鄉似，山川地勢分。',48,'全唐诗/poet.song.93000.json','["風物吾鄉似，山川地勢分。", "稻畦飜碧浪，麥壠布黄雲。", "客舍常爭席，山僧獨獻芹。", "茅柴餘瀝在，聊餉僕夫勤。"]'),
('a6480e55-91d1-4cab-ad2d-2c1a22dcbf16','宿仙霞聖仙寺呈伯思子靜二首  其二','陳淵','宋','宋诗','song-poetry','','[]','曉日山原靜，薰風杖屨輕。',48,'全唐诗/poet.song.93000.json','["曉日山原靜，薰風杖屨輕。", "開談時造極，得意自難名。", "奔走非前計，淹留見俗情。", "賴渠金石友，端的慰平生。"]'),
('28bf9982-2687-4cc4-8685-1fc160f83100','通州夏雨','陳淵','宋','宋诗','song-poetry','','[]','長風卷地驅炎暑，暴雨飜空送晚涼。',32,'全唐诗/poet.song.93000.json','["長風卷地驅炎暑，暴雨飜空送晚涼。", "只此蚊蠅俱掃跡，不須迢遞待秋霜。"]'),
('fc5c6ceb-6afa-41b3-8d21-8b1260dc90b3','延平林力道閣上觀水二首  其一','陳淵','宋','宋诗','song-poetry','','[]','千重翠巘分三岸，十里寒潭合兩溪。',32,'全唐诗/poet.song.93000.json','["千重翠巘分三岸，十里寒潭合兩溪。", "更得横流吞險瀨，豈嫌春水濁如泥。"]'),
('81fb6618-25b2-44c7-8bb4-b01fb29b3aeb','延平林力道閣上觀水二首  其二','陳淵','宋','宋诗','song-poetry','','[]','要看春水拍天流，更爲溪山一日留。',32,'全唐诗/poet.song.93000.json','["要看春水拍天流，更爲溪山一日留。", "誰遣白雲迷眼界，坐令歸思入扁舟。"]'),
('cc3cd8f2-fa47-439f-b487-35a3907fd49a','兩浙周提刑生日','陳淵','宋','宋诗','song-poetry','','[]','淮南草木亦知威，故國重看衣繡歸。',64,'全唐诗/poet.song.93000.json','["淮南草木亦知威，故國重看衣繡歸。", "不用埋輪留魏闕，故應持斧靜圜扉。", "天瞻柳舍雙丸會，地應蓂階五葉飛。", "此日長庚來吉夢，弧南終並一星暉。"]'),
('b2c3b1af-b0aa-406e-8dff-0a714d97cfa6','看論語四首  其一','陳淵','宋','宋诗','song-poetry','','[]','明明孔聖能毋四，的的曾參所貴三。',32,'全唐诗/poet.song.93000.json','["明明孔聖能毋四，的的曾參所貴三。", "一部魯論開聖域，古人無死要重參。"]'),
('000dbe19-0937-462f-af8e-f94bb4750947','看論語四首  其二','陳淵','宋','宋诗','song-poetry','','[]','天道文章豈兩岐，雷聲淵黙本同時。',32,'全唐诗/poet.song.93000.json','["天道文章豈兩岐，雷聲淵黙本同時。", "如何子貢能言者，說與無言更有疑。"]'),
('cfbf0841-6e70-450c-9aca-4929bd023dd9','看論語四首  其三','陳淵','宋','宋诗','song-poetry','','[]','陋巷從容一事無，不因鄰鬬出吾廬。',32,'全唐诗/poet.song.93000.json','["陋巷從容一事無，不因鄰鬬出吾廬。", "簞瓢豈是忘憂物，自是從容樂有餘。"]'),
('67786cc0-960e-4450-aaa1-83236fdba395','看論語四首  其四','陳淵','宋','宋诗','song-poetry','','[]','直從堯舜以中傳，又到東丘續斷絃。',32,'全唐诗/poet.song.93000.json','["直從堯舜以中傳，又到東丘續斷絃。", "看取子思親的處，始知論語自無偏。"]'),
('dea5da02-1131-47de-b008-744cff4828da','夢得亭上','陳淵','宋','宋诗','song-poetry','','[]','雷霆卷地灘聲急，旌斾搖空樹影寒。',32,'全唐诗/poet.song.93000.json','["雷霆卷地灘聲急，旌斾搖空樹影寒。", "千古西山留爽氣，雨餘容我倚欄看。"]'),
('cd153739-02e4-4cca-9854-04ddccb58328','留别鄧南夫四首  其一','陳淵','宋','宋诗','song-poetry','','[]','平生交友各飄蓬，只有丸丸雪後松。',32,'全唐诗/poet.song.93000.json','["平生交友各飄蓬，只有丸丸雪後松。", "萬里歸來還往絕，獨君時許略從容。"]'),
('10f1cae6-caf1-40c4-9c3d-c5a262408d12','留别鄧南夫四首  其二','陳淵','宋','宋诗','song-poetry','','[]','昂昂勁氣初無作，蕩蕩奇胸久息機。',32,'全唐诗/poet.song.93000.json','["昂昂勁氣初無作，蕩蕩奇胸久息機。", "容我醉時開讜論，一軒明月夜忘歸。"]'),
('8cff3085-7e9d-4d14-9741-f1ae387b04bd','留别鄧南夫四首  其三','陳淵','宋','宋诗','song-poetry','','[]','有子才如汗血駒，新門高大可容車。',32,'全唐诗/poet.song.93000.json','["有子才如汗血駒，新門高大可容車。", "故應袖手藏深渺，憐我冰霜涉畏途。"]'),
('9b972afa-13a9-4057-adab-ed6a8722d56d','留别鄧南夫四首  其四','陳淵','宋','宋诗','song-poetry','','[]','比余於玉有奇文，一落泥塗十二春。',32,'全唐诗/poet.song.93000.json','["比余於玉有奇文，一落泥塗十二春。", "慚愧深知同鮑叔，尚言荆璞定逢人。"]'),
('2e23850a-b0af-43ca-a59a-ca53c12d77c9','越州道中雜詩十三首  其一','陳淵','宋','宋诗','song-poetry','','[]','心息久相依，息調心自住。',48,'全唐诗/poet.song.93000.json','["心息久相依，息調心自住。", "忽焉不自知，根塵失所寓。", "向來尚有錐，今我已忘兔。", "似入無功鄉，不由嵇阮路。"]'),
('d0eb2d12-d620-4487-b8a7-fabbbea2cde1','越州道中雜詩十三首  其二','陳淵','宋','宋诗','song-poetry','','[]','暴氣燎原火，淺量盈澮水。',48,'全唐诗/poet.song.93000.json','["暴氣燎原火，淺量盈澮水。", "不見楊關西，此生真已矣。", "誰言佩豭由，不作緼袍耻。", "至道儻有聞，客塵如脱屣。"]'),
('53642261-2bc2-4923-9c1d-b146a173ea00','越州道中雜詩十三首  其三','陳淵','宋','宋诗','song-poetry','','[]','世儒讀論語，未脱小兒氣。',48,'全唐诗/poet.song.93000.json','["世儒讀論語，未脱小兒氣。", "豈悟無絃琴，中藏千古意。", "顔淵黙然處，曾子亦心醉。", "處處儻逢渠，字字皆有味。"]'),
('9a1e6881-30d3-40ae-be28-bad0e2db840c','越州道中雜詩十三首  其四','陳淵','宋','宋诗','song-poetry','','[]','人心有黙契，晤語不在多。',48,'全唐诗/poet.song.93000.json','["人心有黙契，晤語不在多。", "一笑離凡情，萬象皆含和。", "孰是忘言人，聽此無聲歌。", "有懷閲古堂，夢中時一過。"]'),
('129cb9a0-7be0-4469-b57e-9a92c0d75fed','越州道中雜詩十三首  其五','陳淵','宋','宋诗','song-poetry','','[]','浮雲作秋陰，細雨如朝霧。',48,'全唐诗/poet.song.93000.json','["浮雲作秋陰，細雨如朝霧。", "放形山水間，意適無艱步。", "忽遇古招提，空翠森回互。", "倚杖聽泉鳴，悠然不能去。"]'),
('d0cfae13-c79c-4472-af3a-065ac329d1e6','越州道中雜詩十三首  其六','陳淵','宋','宋诗','song-poetry','','[]','小舟適久雨，疏篷常自蔽。',48,'全唐诗/poet.song.93000.json','["小舟適久雨，疏篷常自蔽。", "形留一席間，心與天地際。", "逝者不可作，遺編等蟬蜕。", "一念無古今，千載若符契。"]'),
('4adbcb35-2a69-4518-a77b-8f1b1fa8d6af','越州道中雜詩十三首  其七','陳淵','宋','宋诗','song-poetry','','[]','胸中有佳處，妙意不期會。',48,'全唐诗/poet.song.93000.json','["胸中有佳處，妙意不期會。", "弄筆作五言，心手無內外。", "千古陶淵明，秀句含天籟。", "偶然游其藩，遂爾厭彫繪。"]'),
('d13d8f42-17bb-466e-bfd3-ea056f3cd6fa','越州道中雜詩十三首  其八','陳淵','宋','宋诗','song-poetry','','[]','淵明已黄壤，詩語餘奇趣。',48,'全唐诗/poet.song.93000.json','["淵明已黄壤，詩語餘奇趣。", "我行田野間，舉目輒相遇。", "誰云古人遠，正是無來去。", "展卷味其言，即今果何處。"]'),
('f052b5b8-181a-477d-b61b-08cffcbfe4c1','越州道中雜詩十三首  其九','陳淵','宋','宋诗','song-poetry','','[]','老珃言道德，頗復求自已。',48,'全唐诗/poet.song.93000.json','["老珃言道德，頗復求自已。", "但於閣闢機，未免容或使。", "列莊猶反約，申韓遂殊軌。", "所差適毫釐，奚翅繆千里。"]'),
('ea1888b8-1be8-4452-90e2-42a86c4847db','越州道中雜詩十三首  其一○','陳淵','宋','宋诗','song-poetry','','[]','揚雄窺聖域，何啻越距楚。',48,'全唐诗/poet.song.93000.json','["揚雄窺聖域，何啻越距楚。", "斷然著成書，凖易與論語。", "古來文字學，似此奚足數。", "誰謂千秋人，斯言果輕許。"]'),
('ad492054-cc37-4125-bd0b-10e7f8ab4ebf','越州道中雜詩十三首  其一一','陳淵','宋','宋诗','song-poetry','','[]','王通禮法士，談道則未然。',48,'全唐诗/poet.song.93000.json','["王通禮法士，談道則未然。", "雖聞一字中，尚倚諸子偏。", "區區尊孔子，未悟失其傳。", "自聖猶不疑，續經何足愆。"]'),
('601e3bcc-199b-4150-96f4-22e87b756705','越州道中雜詩十三首  其一二','陳淵','宋','宋诗','song-poetry','','[]','堂堂陸忠州，談辯如傾河。',48,'全唐诗/poet.song.93000.json','["堂堂陸忠州，談辯如傾河。", "從容仁義途，步武尋丘軻。", "一斥不復返，方書事研磨。", "至今諫草存，滄溟遺一波。"]'),
('805b6089-7842-4667-8877-c229a79a9e01','越州道中雜詩十三首  其一三','陳淵','宋','宋诗','song-poetry','','[]','我行何所挾，萬里一毛穎。',48,'全唐诗/poet.song.93000.json','["我行何所挾，萬里一毛穎。", "服勞髪欲禿，木語意先領。", "畸人如告我，心清事自省。", "從今中書君，亦復免馳騁。"]'),
('f032a6c7-5c1c-404f-800e-4c3fff29850e','和如愚思劍溪','陳淵','宋','宋诗','song-poetry','','[]','佳人經歲隔參辰，柳綠桃紅奈遠情。',32,'全唐诗/poet.song.93000.json','["佳人經歲隔參辰，柳綠桃紅奈遠情。", "遥想玉樓春睡起，一江風日弄清明。"]'),
('49f2616c-85f1-4447-8215-a30a1ada41d7','馮元用九日約白雲寺登高以追昔年都城望津之會偶以事不往蒙示長篇次韻','陳淵','宋','宋诗','song-poetry','','[]','與君都城别，星霜屢變易。',180,'全唐诗/poet.song.93000.json','["與君都城别，星霜屢變易。", "每懷望津游，悵然如有失。", "此生覊旅中，歲序驚心魄。", "還家幾何時，自愧不煖席。", "建溪古渡頭，短棹凌虚碧。", "掀篷忽見君，恍若夢中得。", "相攜定舍館，石徑走迂直。", "危亭至如歸，坐午及昏黒。", "黄花笑東籬，未許蓬蒿没。", "咫尺白雲樓，坐阻造毫逸。", "人生正似茲，有志誰能必。", "當時連鼇手，至今猶挾策。", "高才真楚璞，末技同齊瑟。", "無心效騫騰，自分投閑僻。", "望津儻同登，意氣那復昔。"]'),
('37672f01-0776-4649-9b97-912ef2c28458','次韻酬鄧天啓','陳淵','宋','宋诗','song-poetry','','[]','少年翰墨場，自姹穿楊箭。',120,'全唐诗/poet.song.93000.json','["少年翰墨場，自姹穿楊箭。", "誰論第一功，不數曹參戰。", "聖門窺管豹，一斑時許見。", "棄捐憂患中，更欲資陶錬。", "兩鄧富文采，端可同席硯。", "投璧或未知，賈石誰敢衒。", "小栟詩益奇，出語人所羡。", "過門遺新篇，無乃思與狷。", "我懷古作者，臨文頻撫卷。", "孰能掃千人，期君當八面。"]'),
('d056b201-fd93-4bc3-bf28-658ed2b5b8db','次韻邦美叔和天啓見寄','陳淵','宋','宋诗','song-poetry','','[]','竹風挾雨撼篷窗，靜聽秋聲轉騒窣。',128,'全唐诗/poet.song.93000.json','["竹風挾雨撼篷窗，靜聽秋聲轉騒窣。", "朝來饑卧媚微涼，叩門不作淵明乞。", "小栟見餉有新詩，七言端爲吾家出。", "共誰渠有古人風，孰識中藏謫仙骨。", "書如周鼓未差訛，語效商盤仍詰屈。", "誰與和者叔不癡，落筆成章一嗟咄。", "無用如今君豈樗，自寇從來我非漆。", "板茅它日儻相尋，好在山深林更密。"]'),
('3ef9bf2c-5752-4545-9926-e6b7dfacffff','三月二日泛舟下延平晚泊西芹','陳淵','宋','宋诗','song-poetry','','[]','扁舟劣容身，風浪困掀簸。',120,'全唐诗/poet.song.93000.json','["扁舟劣容身，風浪困掀簸。", "曲肱游華胥，夢斷千山過。", "縱横波間石，滿目牛羊卧。", "秋毫儻不支，巨艦忽已破。", "篙師號神逸，却立變衰懦。", "我豈未之思，懸知無可奈。", "此生足驚憂，似爲天所癉。", "那能一生死，且復耐摧挫。", "日暮同濟人，舉酒紛相賀。", "一笑盡餘觴，歌罷無予和。"]'),
('6458df4c-eebc-4d98-abc7-f6e9e8a0a3b1','次韻令德答天啓','陳淵','宋','宋诗','song-poetry','','[]','小栟妙語言，下筆初無難。',96,'全唐诗/poet.song.93000.json','["小栟妙語言，下筆初無難。", "曹郎更精深，一字不苟安。", "我師陶靖節，亦未游其藩。", "但覺萬仞淵，中有蛟龍蟠。", "人言失故步，乃在學邯鄲。", "平淡恐未臻，先作郊島寒。", "古來文墨士，十九姓字漫。", "尚賴相可否，鹽梅助鹹酸。"]'),
('21734e61-f880-4634-b498-55a71af5af80','復次韻答令德見和來詩及維摩黙然之意','陳淵','宋','宋诗','song-poetry','','[]','多言亦焉用，守黙良獨難。',96,'全唐诗/poet.song.93000.json','["多言亦焉用，守黙良獨難。", "維摩得此門，衆生病自安。", "當時許子將，不造寔與蕃。", "終以月旦評，有愧申屠蟠。", "忠良覆漢鼎，魯酒圍邯鄲。", "獨愛千頃陂，滄波炤人寒。", "君豈叔度歟，胸襟江海漫。", "自然已憤厥，不須珍柚酸。"]'),
('6a738e3a-df1c-4217-add7-a0c4a3eccaec','用令德韻題嚴陵祠','陳淵','宋','宋诗','song-poetry','','[]','價微良易酬，器博無近用。',120,'全唐诗/poet.song.93000.json','["價微良易酬，器博無近用。", "騏驥非良樂，萬里誰能控。", "蕭王漢中興，四海倚爲重。", "誰爲淵驅魚，一呼百萬衆。", "妙算環無端，奇功射必中。", "忘機諒未能，豈數漢陰甕。", "故人鈎尚直，倦作儀韶鳳。", "應無萬牛力，負此丘山棟。", "羊裘又獨往，苦語餘嘲弄。", "至今賣菜言，空記當時夢。"]'),
('1ccb8d08-0f6a-4c78-a4bb-e37ee46036f4','跋子靜所藏魯直書樂天八字偈','陳淵','宋','宋诗','song-poetry','','[]','凝師八字源則豐，樂天說偈流無窮。',96,'全唐诗/poet.song.93000.json','["凝師八字源則豐，樂天說偈流無窮。", "山谷眼明如日中，落筆驚電馳蛟龍。", "誰其得之建溪翁，取人所棄豈俗同。", "搜奇抉怪晉餘風，嫉邪憤世髪上衝。", "自我觀之案兩重，巧偷豪奪願不逢。", "好語傳播人所攻，斯言有味當見容。"]'),
('4c3d537b-fe4c-4969-bbbd-e7427f9654a1','題公叙舫齋','陳淵','宋','宋诗','song-poetry','','[]','胥靡来時楫，鴟夷去後舟。',96,'全唐诗/poet.song.93000.json','["胥靡来時楫，鴟夷去後舟。", "濟川曾入夢，浮海竟難留。", "忠信雖堪倚，行藏要自謀。", "應同仙似泰，不數勇如由。", "水闊風濤夕，鱸肥浦嶼秋。", "落帆如得計，整棹欲何求。", "明月時堪載，新醪便可浮。", "江山無盡意，長艤劍溪頭。"]'),
('340b000a-3eee-4504-bce5-5037afecb907','和羅仲素寄子靜長篇','陳淵','宋','宋诗','song-poetry','','[]','龜山絕壑蟠豫章，秀幹往往參天長。',192,'全唐诗/poet.song.93000.json','["龜山絕壑蟠豫章，秀幹往往參天長。", "十年收拾多散亡，只有太白追蟾光。", "知君所得不可詳，宴坐鐔溪名益彰。", "獨嘗爲我露其鋩，盡掃楊墨揮韓莊。", "邇來黄面稍侵疆，劍藏于室矢在房。", "分將肌肉剜爲瘡，猶說道心乃平常。", "我欲從之挹餘芳，竟坐此傳乖所望。", "新詩謾說陋漢唐，直以未畫窮羲皇。", "豈知籓籬不自防，欲舉萬目誰爲綱。", "况彼桀驁非勤王，安用援手登之堂。", "愛君駿足如飛黄，一空冀北無留良。", "四蹄雷雹方騰驤，肯如駑馬徒爭强。"]'),
('dceb4e27-a8b4-41c2-bac3-1dd890413625','和子靜三絕 亭竹二首 其一','陳淵','宋','宋诗','song-poetry','','[]','窗外度聲風宛轉，庭前舒影月分明。',32,'全唐诗/poet.song.93000.json','["窗外度聲風宛轉，庭前舒影月分明。", "參横斗轉情無盡，骨冷魂清夢不成。"]'),
('828db654-cffd-435f-bd38-9b073dae5963','和子靜三絕 亭竹二首 其二','陳淵','宋','宋诗','song-poetry','','[]','霜雪豈能摧勁節，埃塵無復入虚懷。',32,'全唐诗/poet.song.93000.json','["霜雪豈能摧勁節，埃塵無復入虚懷。", "故應淡薄無人管，不是子猷誰復來。"]'),
('e92b6ba0-cb7b-4221-aa0c-ce04ccc0d6e2','和子靜三絕 漁父一首','陳淵','宋','宋诗','song-poetry','','[]','一聲横笛起蘆花，驚斷天邊雁字斜。',32,'全唐诗/poet.song.93000.json','["一聲横笛起蘆花，驚斷天邊雁字斜。", "白首飽諳鱸鱖美，未能連夜網游鰕。"]'),
('10950765-e1bc-4219-a886-b85550e33395','舟中誦子靜江上之作爲和二絕  其一','陳淵','宋','宋诗','song-poetry','','[]','月下長吟露濕衣，謫仙嘗憶謝玄暉。',32,'全唐诗/poet.song.93000.json','["月下長吟露濕衣，謫仙嘗憶謝玄暉。", "澄江一句無今古，何似晴空獨鳥飛。"]'),
('4d944dc4-0a23-46fe-8cb4-d2953c05cc62','舟中誦子靜江上之作爲和二絕  其二','陳淵','宋','宋诗','song-poetry','','[]','扁舟直與石相摩，得到平流幸已多。',32,'全唐诗/poet.song.93000.json','["扁舟直與石相摩，得到平流幸已多。", "夜泊寒潭風不定，更憂雷雨作驚波。"]'),
('7cd77ba4-4623-4cc9-ae44-d21b85ae9522','閩縣令陳夢兆魚樂軒','陳淵','宋','宋诗','song-poetry','','[]','有樂寧爾憂，無憂乃至樂。',252,'全唐诗/poet.song.93000.json','["有樂寧爾憂，無憂乃至樂。", "觀身見物理，魚樂豈子各。", "萬生擾爲病，安靜即艮藥。", "何以適其情，已定要無虐。", "江湖與此池，等是泉未涸。", "周旋苟得所，是處覺寛綽。", "君看瀕海民，茲物困剽掠。", "縱横墮鈎網，瑣細入杯杓。", "誰云滄海廣，游泳渺無託。", "乃知尺澤間，所樂逾縱壑。", "我家一畝宫，隙地不容鑿。", "未能禁數罟，念此每懷怍。", "陳公吏之師，養善息羣惡。", "愛民以及魚，退念此盤礴。", "魚亦喜公來，出没供笑謔。", "當年濠上游，天籟紛酬酢。", "昭琴既不鼓，應問兩俱錯。", "賢哉鄭國僑，一物心無著。", "但信悠然語，未悟已投鑊。", "懸知此魚烹，不羡波間躍。", "誰當較異同，我亦無今昨。"]'),
('326e96ae-282a-488f-90b6-0558fb381ee2','午睡懷安縣風篁亭','陳淵','宋','宋诗','song-poetry','','[]','旌旗蔽野階除寂，環佩鳴空枕簟涼。',32,'全唐诗/poet.song.93000.json','["旌旗蔽野階除寂，環佩鳴空枕簟涼。", "夢斷鈞天知是想，一溝泉落樂聲長。"]'),
('8274b8ad-799c-4321-8c82-1bf77443e7ca','次韻鄧志宏送張思道游福唐','陳淵','宋','宋诗','song-poetry','','[]','紛紛涴耳俱宜洗，坐遣高人厭丘里。',128,'全唐诗/poet.song.93000.json','["紛紛涴耳俱宜洗，坐遣高人厭丘里。", "迅流早自促行舟，更有西風滿江葦。", "當年筆陣掃千軍，今日流輩推能文。", "英辭谹辯洒醉墨，倐忽百變春空雲。", "人間萬事秋毫細，軒冕儻來誰著意。", "身隨去棹落波間，興逐冥鴻渺天際。", "三山便到蓬萊宫，卸帆海嶼窺魚龍。", "夜涼横笛弄明月，萬頃琉璃秋色中。"]'),
('fc9ab9cd-9861-4cf7-9414-a7c4fd5984e4','自京回次韻鄧志宏見贈','陳淵','宋','宋诗','song-poetry','','[]','妙齡才思湧如泉，末技文章不自賢。',64,'全唐诗/poet.song.93000.json','["妙齡才思湧如泉，末技文章不自賢。", "餘子豈知多問寡，老生端許一當千。", "淹留莫止爲山簣，收拾終同至海川。", "雲路筆間天尺五，會令鷄犬亦能仙。"]'),
('d41aa440-529c-42eb-a159-213b10df570a','翁承事挽詞五首  其一','陳淵','宋','宋诗','song-poetry','','[]','徐行直視日如愚，律己齊家盡可書。',32,'全唐诗/poet.song.93000.json','["徐行直視日如愚，律己齊家盡可書。", "九十一年由砥道，肯令荆棘敝衣裾。"]'),
('dc7ee35d-f8cf-47f3-837e-9b8ae3ad0822','翁承事挽詞五首  其二','陳淵','宋','宋诗','song-poetry','','[]','不將堯舜等瞿曇，簡語寧同賣菜添。',32,'全唐诗/poet.song.93000.json','["不將堯舜等瞿曇，簡語寧同賣菜添。", "惆悵老成無復見，一時流俗正清談。"]'),
('7075936a-bf19-430a-9907-1a676999f9b8','翁承事挽詞五首  其三','陳淵','宋','宋诗','song-poetry','','[]','苦語熏心不易忘，它時聞教我爲詳。',32,'全唐诗/poet.song.93000.json','["苦語熏心不易忘，它時聞教我爲詳。", "須知令尹多仁術，寔自嚴君有義方。"]'),
('825cfa4a-f1fb-43d0-81b9-bcffbac3cc48','翁承事挽詞五首  其四','陳淵','宋','宋诗','song-poetry','','[]','霜髯碧眼照華燈，夾道游人避履聲。',32,'全唐诗/poet.song.93000.json','["霜髯碧眼照華燈，夾道游人避履聲。", "曾是元宵隨步月，西風何忍見銘旌。"]'),
('f0eb3bc7-8798-4f0f-86bf-bef7d42bfe4f','翁承事挽詞五首  其五','陳淵','宋','宋诗','song-poetry','','[]','樓閣溪山兩鬬雄，中横千丈未雩龍。',32,'全唐诗/poet.song.93000.json','["樓閣溪山兩鬬雄，中横千丈未雩龍。", "當時令尹兒啼處，依舊東流遶七峰。"]'),
('3644f10f-ac5d-42ed-9c94-95d918f5fb3a','泊舟延平二絕  其一','陳淵','宋','宋诗','song-poetry','','[]','野梅飄盡喜春歸，又見溪桃片片飛。',32,'全唐诗/poet.song.93000.json','["野梅飄盡喜春歸，又見溪桃片片飛。", "醉卧暖風呼不醒，亂紅無數點人衣。"]'),
('12daaece-82ad-40ea-9f9f-338a5cf04239','泊舟延平二絕  其二','陳淵','宋','宋诗','song-poetry','','[]','星河不動水東流，夜影搖空逼釣舟。',32,'全唐诗/poet.song.93000.json','["星河不動水東流，夜影搖空逼釣舟。", "夢破滄浪歌在耳，欲尋溪友向煙洲。"]'),
('9afeffb2-d198-4cf4-9106-3797605b24d7','寓漳南靜衆寺三月晦信步到庵亭曠望久之聊寄所感','陳淵','宋','宋诗','song-poetry','','[]','意行不知遠，倚杖囂塵外。',48,'全唐诗/poet.song.93000.json','["意行不知遠，倚杖囂塵外。", "南州風物繁，此地溪山會。", "俯窺城市喧，蟻垤幾成壞。", "只爾可忘情，未用旋吾斾。"]'),
('b17fd315-e18a-4800-864f-3387966b8b3c','過永春劇頭舖見壁間石刻臨漳王漕詩輒題數句','陳淵','宋','宋诗','song-poetry','','[]','壁間得微詞，語盡意有餘。',72,'全唐诗/poet.song.93000.json','["壁間得微詞，語盡意有餘。", "摸傳豈真知，無乃勢所驅。", "從來碧紗籠，不護寒士書。", "焉知題柱生，終無駟馬車。", "粉板會當洗，援毫聊自娯。", "從人分輕重，削迹今何如。"]'),
('06d1dbb3-42e2-4d26-8387-73604d4f8e86','次韻德純通判賀用中生子','陳淵','宋','宋诗','song-poetry','','[]','暴客年來不過門，羡君三秀各生春。',64,'全唐诗/poet.song.93000.json','["暴客年來不過門，羡君三秀各生春。", "懸弧適在龍溪側，履迹知從劍水濱。", "魯國考祥欣得鯉，杜陵占夢信爲麟。", "問名更取詩翁語，盛事流傳西鬬新。"]'),
('deafef3a-a5e4-4764-9a39-907fe92b77c5','次韻李伯紀舍人招飲','陳淵','宋','宋诗','song-poetry','','[]','胸中造物可與友，筆下騷人真是奴。',64,'全唐诗/poet.song.93000.json','["胸中造物可與友，筆下騷人真是奴。", "共傳排佛似遷愈，獨喜賦梅追隱逋。", "盤空未念鴟腐鼠，在野寧無駒束芻。", "時時造席聞妙語，謬辱知己非夷吾。"]'),
('fe00981c-9065-4dd4-925c-e579b03ca96a','再和李伯紀舍人韻','陳淵','宋','宋诗','song-poetry','','[]','時來將相寧有種，衛青故是民家奴。',64,'全唐诗/poet.song.93000.json','["時來將相寧有種，衛青故是民家奴。", "懸鶉未用歎歲惡，闊網近喜除官逋。", "本無得喪任失馬，但有言說皆陳芻。", "從公一飲百壺盡，醉倒不知誰謂吾。"]'),
('f4760bdc-e5d2-4597-bcb9-74c910f5564f','和李舍人留題泛碧齋','陳淵','宋','宋诗','song-poetry','','[]','山脚回環插遠潯，碧琉璃上玉爲岑。',64,'全唐诗/poet.song.93000.json','["山脚回環插遠潯，碧琉璃上玉爲岑。", "共憐采鷁風前試，正值滄波雨後深。", "應爲蓴鱸輕去國，遂令胡越盡同心。", "濟川此去爲舟楫，也念江湖有陸沉。"]'),
('a74b7db4-31e1-4949-9cdd-f729134c9802','陪知縣夜飲泛碧齋再用前韻','陳淵','宋','宋诗','song-poetry','','[]','暑雨初收水拍潯，溪光南北影千岑。',64,'全唐诗/poet.song.93000.json','["暑雨初收水拍潯，溪光南北影千岑。", "移舟爲愛玻璃闊，放盞那知琥珀深。", "緩带小風來水面，倚欄涼月轉天心。", "酒酣更駐凌波襪，直待銀河夜色沉。"]'),
('fd5dd0b6-adbf-4b03-9000-dc21de271fa8','鉛山道中小休','陳淵','宋','宋诗','song-poetry','','[]','秋陽如獵火，四顧不可避。',96,'全唐诗/poet.song.93000.json','["秋陽如獵火，四顧不可避。", "肩輿得微陰，休此僕夫瘁。", "我生道途間，歲月七之四。", "山林固清遠，及物乃初意。", "黄雲堆壠畝，早稻一尺穗。", "所欣居者樂，未敢嘆勞勩。", "詔書寛逋負，豪吏不少置。", "民窮戒勿擾，天下適無事。"]'),
('7595fa84-eb91-4626-abec-f7694dfe58b0','贈别楊至游三首  其一','陳淵','宋','宋诗','song-poetry','','[]','醉鄉佳處許誰臨，幸有匏尊可共斟。',32,'全唐诗/poet.song.93000.json','["醉鄉佳處許誰臨，幸有匏尊可共斟。", "要試從前寛窄量，但知空盞莫辭深。"]'),
('b40c4b4f-9f28-4cfc-8bf9-2f3c360c472a','贈别楊至游三首  其二','陳淵','宋','宋诗','song-poetry','','[]','和平簡易是吾師，自有家風更問誰。',32,'全唐诗/poet.song.93000.json','["和平簡易是吾師，自有家風更問誰。", "不是妙年狂氣歇，可能從我獨無疑。"]'),
('cc379582-b179-4653-ad02-f39569452a37','贈别楊至游三首  其三','陳淵','宋','宋诗','song-poetry','','[]','貪瞋癡盡即如如，究竟心源一法無。',32,'全唐诗/poet.song.93000.json','["貪瞋癡盡即如如，究竟心源一法無。", "應悟濓溪真古佛，始知伊洛是醇儒。"]'),
('1e1b7efe-aff7-49ff-bfca-dacfe5d7cc45','次韻李伯紀舍人食了齋所寄石芝有感','陳淵','宋','宋诗','song-poetry','','[]','石芝附石元無根，有名不載農黄文。',128,'全唐诗/poet.song.93000.json','["石芝附石元無根，有名不載農黄文。", "絳囊遠致自東海，謫仙爲向詩中論。", "談餘得味仍遭苦，未辨終甘莫輕吐。", "此言要自顯真心，不比繁辭較鍾乳。", "太丘晚交誰獨深，梁溪心如百鍊金。", "只應異代友元禮，許國有盟今更尋。", "雙魚萬里將芹子，妙意難名聊寄耳。", "餘甘橄欖正須渠，它日忠信今悟矣。"]'),
('720d6577-c9f1-4679-88c8-fb3549f96750','書室獨坐','陳淵','宋','宋诗','song-poetry','','[]','春入庭柯寸寸藍，風簷孤坐怯輕衫。',32,'全唐诗/poet.song.93000.json','["春入庭柯寸寸藍，風簷孤坐怯輕衫。", "青天白日從来好，柏樹桃花子細參。"]'),
('ec76c86b-17ea-4e4b-8edd-6b49b543bfab','自浦城放船下建安寄龐幾先  其一','陳淵','宋','宋诗','song-poetry','','[]','扁舟西下趁殘陽，目斷雲邊歸雁行。',32,'全唐诗/poet.song.93000.json','["扁舟西下趁殘陽，目斷雲邊歸雁行。", "短棹莫辭風浪惡，人間平地有羊腸。"]'),
('02906528-db58-40d4-8f7d-0564a261b9d2','自浦城放船下建安寄龐幾先  其二','陳淵','宋','宋诗','song-poetry','','[]','茅柴也解發清狂，仰看雲天盡十觴。',32,'全唐诗/poet.song.93000.json','["茅柴也解發清狂，仰看雲天盡十觴。", "白首歲寒猶道路，自憐無意避風霜。"]'),
('0627724e-91c7-4297-9b40-67775168b23b','奉陪婺州守南樓宴集','陳淵','宋','宋诗','song-poetry','','[]','溪山自昔東陽勝，賓客偏於北海多。',64,'全唐诗/poet.song.93000.json','["溪山自昔東陽勝，賓客偏於北海多。", "四坐英標真倚玉，一時雄辨劇懸河。", "淹留慙應三刀夢，豈弟仍傳五袴歌。", "更避正堂延蓋老，待將清淨繼蕭何。"]'),
('8764f383-b76f-424f-9388-04e68397ee21','奉陪龜山先生觀修城','陳淵','宋','宋诗','song-poetry','','[]','西山淼淼送斜陽，往事回頭一夢長。',64,'全唐诗/poet.song.93000.json','["西山淼淼送斜陽，往事回頭一夢長。", "萬里喜霑新雨露，百年重拓舊金湯。", "杵聲撼野雷初動，鍤柄揮風蟻自行。", "尊俎折衝今可恃，補牢端爲念亡羊。"]'),
('1d0ecb81-1b82-44de-af5f-e89e1bec0c46','次韻鄧志宏和吏部謝公鐵字韻詩二首  其一','陳淵','宋','宋诗','song-poetry','','[]','結交自惜羞餘耳，直要人情淡如水。',96,'全唐诗/poet.song.93000.json','["結交自惜羞餘耳，直要人情淡如水。", "晏嬰鮑叔久已亡，嗟我欲從誰氏子。", "大栟筆陣掃千人，詩成不顧俗士瞋。", "長歌欲奪謫仙氣，短韻更逼宣城真。", "爾来念我知交絕，託以不能資老拙。", "自笑今年錐也無，何須更覓針頭鐵。"]'),
('d8fad96c-32a8-4029-a5a4-726c264ae7b1','次韻鄧志宏和吏部謝公鐵字韻詩二首  其二','陳淵','宋','宋诗','song-poetry','','[]','愁霖十日槎生耳，寒氣薄人如著水。',96,'全唐诗/poet.song.93000.json','["愁霖十日槎生耳，寒氣薄人如著水。", "坐對毗耶數卷書，未厭銅爐燒柏子。", "區區我亦可憐人，只有無求人不瞋。", "雖無名字振京國，不屈未應慙子真。", "凍琴壁間絃自絕，袖手深藏鳩更拙。", "本無流水遣誰知，此去從人譏嚼鐵。"]');
